-- Poems batch 192
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6ccbb5c2-fffb-4be3-87e2-256f2a246730','除夜','趙萬年','宋','宋诗','song-poetry','','[]','除夜春牛吼，開正虜騎多。',24,'全唐诗/poet.song.184000.json','["除夜春牛吼，開正虜騎多。", "有謀思却敵，休問命如何。"]'),
('01765a03-1031-4370-b2f3-e769e9de509d','圍中墮馬傷足方愈牙痛累日','趙萬年','宋','宋诗','song-poetry','','[]','虜騎塞東津，迍邅困此身。',48,'全唐诗/poet.song.184000.json','["虜騎塞東津，迍邅困此身。", "足傷方復步，牙痛又摇齦。", "忍見胡塵暗，俄驚歲事新。", "龍鍾三十九，碌碌度青春。"]'),
('153ba1f0-fcdf-41d0-be4d-f00f23d9bc5c','正月初三至初五再攻焚其攻具虜騎大却','趙萬年','宋','宋诗','song-poetry','','[]','鵞車虎砲與雲梯，堪笑胡兒巧用機。',32,'全唐诗/poet.song.184000.json','["鵞車虎砲與雲梯，堪笑胡兒巧用機。", "大帥胸中攄妙算，一時談笑盡灰飛。"]'),
('fd72fcf4-6650-4925-ba69-c63c55e0109f','二月三日登城郊外春色可人而虜騎未退','趙萬年','宋','宋诗','song-poetry','','[]','平生春日不傷春，今日逢春愁殺人。',64,'全唐诗/poet.song.184000.json','["平生春日不傷春，今日逢春愁殺人。", "觸目旌旗非族類，無言桃李少精神。", "可憐野興牽羈興，不分紅塵雜虜塵。", "直待元戎攘却後，峴山無惜領嘉賓。"]'),
('c53094df-9922-4d56-846b-b75cefd855c6','毀土山','趙萬年','宋','宋诗','song-poetry','','[]','築土爲山號距堙，胡兒癡計要攻城。',32,'全唐诗/poet.song.184000.json','["築土爲山號距堙，胡兒癡計要攻城。", "誰知壯士中宵出，三月工夫一夜平。"]'),
('7a032308-b948-47e2-8de2-7cc2a4a59e1c','十三日納合道僧携印來降','趙萬年','宋','宋诗','song-poetry','','[]','屹若金湯不可攻，犬羊誰肯自投降。',32,'全唐诗/poet.song.184000.json','["屹若金湯不可攻，犬羊誰肯自投降。", "勢窮方獻將軍印，何似當初莫渡江。"]'),
('6d395608-e8cd-41b0-8fa2-8230c878edc1','徐招幹請喫鱖魚桐皮','趙萬年','宋','宋诗','song-poetry','','[]','簷外桃花片片飛，垂涎漢水鱖魚肥。',32,'全唐诗/poet.song.184000.json','["簷外桃花片片飛，垂涎漢水鱖魚肥。", "桐皮一作饑腸飽，似得精兵解虜圍。"]'),
('4797a7c1-32f8-4155-857c-bebbe7bca93e','程機宜宅喫豆粥','趙萬年','宋','宋诗','song-poetry','','[]','豆紅米白間青蔬，彷彿來從香積厨。',32,'全唐诗/poet.song.184000.json','["豆紅米白間青蔬，彷彿來從香積厨。", "異日大官還飽飫，不應忘却在蕪蔞。"]'),
('44de296f-1b3a-44ef-889d-406b2e1e21a7','偶成','趙萬年','宋','宋诗','song-poetry','','[]','一心憂國不憂家，掠面黄塵带晚沙。',32,'全唐诗/poet.song.184000.json','["一心憂國不憂家，掠面黄塵带晚沙。", "郵傳不通音問隔，家人夜夜卜燈花。"]'),
('9d50a64b-b799-4c9c-95a3-666c67e0a266','却敵凱歌','趙萬年','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','吁嗟黠虜何猖狂，引弓百萬侵吾疆。',384,'全唐诗/poet.song.184000.json','["吁嗟黠虜何猖狂，引弓百萬侵吾疆。", "首屠棗陽擣神馬，窺伺長江欲葦航。", "隆冬久晴江水涸，直揭小樊厲源漳。", "馬沈人溺相枕藉，霜刃逼脅狼驅羊。", "連營立柵三十里，旌旗蔽野塵埃黄。", "元戎忠赤過張許，隔江獨對虜酋語。", "剖析大義面折之，自比關西偉男子。", "虜酋聞風雖縮頸，業謂渡江無我禦。", "四山列騎意洋洋，擬欲一鼓下襄陽。", "城頭四隅密分布，整飭器具嚴隄防。", "火油金汁羅砲座，託叉擂木森旗槍。", "睥睨樓櫓排萬弩，鏵車尅敵皆蹶張。", "一朝步馳如雲集，前摧草牛負土囊。", "雲梯飛橋對樓聳，虎炮鵝車數里長。", "裹以犀革如帆幔，木楯皮屋翼兩旁。", "鐵騎後擁千百隊，矢如蝟集攢鋒鋩。", "楊柳陰中浮梁就，三千敢勇忽推牆。", "層幾列弩下如雨，霹靂巨砲落穹蒼。", "盡將攻械付烈焰，如焮蛇豕燎豺狼。", "騎者顛仆步者走，傷者號叫立者僵。", "虜酋蒲察與葛札，或貫其腦斧其吭。", "生擒首領數百人，斃馬橫屍盈戰場。", "未幾採木空林藪，旬月運土成高岡。", "噪聲裂地屋爲震，火焰燭天星無光。"]'),
('dfb3e865-46b3-47f6-ab4a-1f32b0c37f31','題資福院平綠軒  其一','莫柯','宋','宋诗','song-poetry','','[]','深林閟嘉趣，門徑愜幽居。',48,'全唐诗/poet.song.184000.json','["深林閟嘉趣，門徑愜幽居。", "野色通荒阜，津梁動碧虛。", "日邊山隠隠，煙外竹疏疏。", "徙倚怡雙目，白雲知故廬。"]'),
('bb5c9fbf-a900-41e5-9e46-1f28e79c0c57','題資福院平綠軒  其二','莫柯','宋','宋诗','song-poetry','','[]','世累苦縈束，官閒得自便。',48,'全唐诗/poet.song.184000.json','["世累苦縈束，官閒得自便。", "未賡三隠句，聊叩二乘禪。", "壯志羞朋舊，長歌且聖賢。", "每因休沐地，思辦買山錢。"]'),
('edb0c811-5754-425c-9f1f-edf07aa011d7','同唐太傅重過西湖','史定之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','紅塵憧擾不知年，一望西湖思豁然。',64,'全唐诗/poet.song.184000.json','["紅塵憧擾不知年，一望西湖思豁然。", "上下層樓涵倒影，聯翩飛鳥沒寒烟。", "未須梅萼催詩興，好藉嵐光作畫箋。", "安得扁舟去招隠，蓬窗相對聽鳴泉。"]'),
('c7895001-269f-4286-a08b-eef4771b5c34','句','史定之','宋','宋诗','song-poetry','','[]','一堤楊柳月，十里芰荷風。',12,'全唐诗/poet.song.184000.json','["一堤楊柳月，十里芰荷風。"]'),
('5c5ec2ea-2fd4-43f0-a50c-6be2ccbaa614','吏隠堂爲鄭參議題','張祈','宋','宋诗','song-poetry','','[]','平時谷口馳聲名，只今朝市心如水。',128,'全唐诗/poet.song.184000.json','["平時谷口馳聲名，只今朝市心如水。", "司馬政成方外趣，官事莫能相料理。", "公堂卜築在人境，鍾阜孱顔是吾里。", "瑶林瓊樹風塵外，白雪陽春談笑裏。", "花間有酒可逃禪，客至忘吾還隠几。", "便應詔登金馬門，樂此徜徉聊復爾。", "君王神聖相伊周，虎豹空山不可留。", "招我白雲二三子，彈冠徑出從公遊。"]'),
('67b8963e-1abf-4f4b-8638-112a96db51ff','秀聚亭','張祈','宋','宋诗','song-poetry','','[]','老矣丹心在，愁來酒興濃。',48,'全唐诗/poet.song.184000.json','["老矣丹心在，愁來酒興濃。", "江山遺古意，雲水淡秋容。", "落日孤村笛，微風遠寺鍾。", "平生善知識，却憶妙高峰。"]'),
('2b88b565-e59b-4556-8fd5-12b90e87ae8e','贈劉升之蟄龍巖','胡槻','宋','宋诗','song-poetry','','[]','東望堯山西舜宮，山人名姓不求通。',32,'全唐诗/poet.song.184000.json','["東望堯山西舜宮，山人名姓不求通。", "蟄巖側畔蘧廬子，即是巢由住箇中。"]'),
('ff6566dc-f699-4636-ac5b-bff6dbf38495','崇壽院霜鐘雙閣','韓松','宋','宋诗','song-poetry','','[]','吾聞海上多雲氣，萬狀千形各殊異。',176,'全唐诗/poet.song.184000.json','["吾聞海上多雲氣，萬狀千形各殊異。", "人間亦有亦等奇，二鐘之山蓋其類。", "高崖凌空上摩雲，下有巖隙頗幽邃。", "料應自古水瀧濯，彈空蜂房懸師鼻。", "玲瓏斷續瘦入骨，奇怪嶙峋復蒼翠。", "身如抵掌在靈谷，又若謦咳發深隧。", "笙竽金石不一音，風浪翻騰隨所寄。", "我來天晴江面平，遂得優游訪天秘。", "低昂壈坎或欹側，藤蔓盤旋青覆被。", "遥知蓬萊隔滄海，毛羽不航人莫至。", "歸來困卧小蓬窗，夢想高天三十二。"]'),
('8d27c301-f939-4dc2-a77d-6b2fa8edee1e','游棲真洞','韓松','宋','宋诗','song-poetry','','[]','黄冠具竹輿，邀我游棲真。',108,'全唐诗/poet.song.184000.json','["黄冠具竹輿，邀我游棲真。", "山家雜水樹，野徑橫荆榛。", "長松卧蒼蛟，亂石錯紫鱗。", "委曲至洞府，積雪開雙門。", "結頂寶蓋高，下可容百人。", "神仙獨何之，棋局今猶存。", "翠子拂不落，衣袖生清芬。", "山間局未終，浮世三千春。", "安得從之游，一笑凌層雲。"]'),
('b2cc105e-57c8-45e6-b449-2262a20ea4d4','遊洞霄','韓松','宋','宋诗','song-poetry','','[]','去城十里蔚山川，慾界仙都自古傳。',64,'全唐诗/poet.song.184000.json','["去城十里蔚山川，慾界仙都自古傳。", "一□孤撐青突兀，群峰九鎖翠盤旋。", "能通玄蓋分精路，未數仇池小有天。", "欲洗積年塵土恨，重來大滌訪流泉。"]'),
('2272dca5-f582-490e-bcf9-dfffa4c0b7da','游洞霄宮  其一','韓松','宋','宋诗','song-poetry','','[]','苔封九鎖碧琅玕，中有仙宮玉佩寒。',32,'全唐诗/poet.song.184000.json','["苔封九鎖碧琅玕，中有仙宮玉佩寒。", "閶闔忽聞呼案吏，來乘灝氣跨青鸞。"]'),
('764b70ab-9045-4781-a01f-1a7535f810fa','游洞霄宮  其二','韓松','宋','宋诗','song-poetry','','[]','萬木森秋晃碧宮，靈霞棲斷憬晨鐘。',32,'全唐诗/poet.song.184000.json','["萬木森秋晃碧宮，靈霞棲斷憬晨鐘。", "道人志矣黄庭界，心眼驚舊天柱峰。"]'),
('a8009178-8399-478e-8e34-7c02b361f626','游洞霄宮  其三','韓松','宋','宋诗','song-poetry','','[]','芒鞋踏明月，入谷聞泉聲。',120,'全唐诗/poet.song.184000.json','["芒鞋踏明月，入谷聞泉聲。", "了知非人間，泠然毛骨輕。", "夜投羽士宮，道話留三更。", "凌晨訪幽洞，巖穴何崢嶸。", "仙凡隔幾塵，無由問霓旌。", "舊聞九鎖峰，忽此眼界明。", "躋攀不可上，勢與龍虎爭。", "憑欄試撫掌，碧甃波紋生。", "塵緣苦未斷，世路猶遐征。", "題詩來賢巖，歲晚當再行。"]'),
('0308251d-730e-4a77-84b3-c5de8babc772','游洞霄宮  其四','韓松','宋','宋诗','song-poetry','','[]','玄冥相我作山行，捲却重陰放曉晴。',64,'全唐诗/poet.song.184000.json','["玄冥相我作山行，捲却重陰放曉晴。", "但見峰巒互扃鎖，不見宮闕隠崢嶸。", "雲根洞穴篝燈入，井底波瀾撫掌生。", "喚客入山還送客，淙琤猶記石泉聲。"]'),
('3e696891-33e4-4a11-a568-49732100885f','游大滌假宿鳴玉館成','韓松','宋','宋诗','song-poetry','','[]','風動歸雲清，日落衆山楚。',48,'全唐诗/poet.song.184000.json','["風動歸雲清，日落衆山楚。", "重來興彌深，託宿此何所。", "浪浪鳴玉泉，恍恍對床雨。", "夢斷身高低，塵勞深夜語。"]'),
('334736df-e3a0-460d-8889-471876a35a93','大滌洞留題  其一','裴良傑','宋','宋诗','song-poetry','','[]','杖屨乘閑歷衆山，俄驚凡跡到仙壇。',64,'全唐诗/poet.song.184000.json','["杖屨乘閑歷衆山，俄驚凡跡到仙壇。", "清潀潄玉一川媚，瑞氣浮空兩洞寒。", "風入喬松琴弄操，煙籠遠岫竈燒丹。", "我今聊此凝雙眼，陡覺壺中世界寬。"]'),
('e7919b0e-b264-49c6-9edb-96ec9e772f56','大滌洞留題  其二','裴良傑','宋','宋诗','song-poetry','','[]','鳩杖先生旨趣深，探直搜隠事幽尋。',64,'全唐诗/poet.song.184000.json','["鳩杖先生旨趣深，探直搜隠事幽尋。", "頂頭有眼誰能識，心鑑無塵物莫侵。", "洞裏煙霞人不老，水邊花木自成陰。", "乞師金鼎丹爐火，爲慰平生覺道心。"]'),
('ba545f3b-175d-4e1f-a6f5-e8cdc27778b6','遊虎丘','裴良傑','宋','宋诗','song-poetry','','[]','顧我江湖舊壯懷，家林終是事塵埃。',64,'全唐诗/poet.song.184000.json','["顧我江湖舊壯懷，家林終是事塵埃。", "登臨直到秋方好，行樂只因山遠來。", "劍石池邊須笑適，花亭月下約徘徊。", "自慚俗駕非名勝，竊恐山靈爲勒回。"]'),
('eed59d6f-f34e-417e-9597-cd53b7839662','定泉井','高頤','宋','宋诗','song-poetry','','[]','方師鑿破天地髓，碧龍吹出冰霜寒。',176,'全唐诗/poet.song.184000.json','["方師鑿破天地髓，碧龍吹出冰霜寒。", "一泓清澄絕泥滓，萬竅號勳無波瀾。", "倒海翻江俱是幻，貯風留月得真觀。", "我來酌飲冷徹骨，飄飄此身在霄漢。", "惠山之泉甘如飴，但隨茗碗爭新奇。", "廉泉讓水名匪欺，祗以賢者爲品題。", "此泉源流本曹溪，名之以定實亦宜。", "嘗試以手測其涯，雨不泛溢旱不虧。", "莫言此乏蜿蜒姿，蟲行蛭動皆可疑。", "咫尺中閒涵世界，寂然心印本無礙。", "不與兒童攪水渾，留照鬚眉長自在。"]'),
('ec089d7d-2473-4305-9280-9b37ba8df9b5','支提禪寺','高頤','宋','宋诗','song-poetry','','[]','石龕金佛一千身，不到支提孰識真。',64,'全唐诗/poet.song.184000.json','["石龕金佛一千身，不到支提孰識真。", "髣髴鐘聲鳴翠阜，晶熒燈焰下蒼旻。", "平生夢想烟霞際，今日來遊鬢髮新。", "踏破禪林秋月皎，水雲閒淡入精神。"]'),
('61e91e70-6345-4131-bf7e-9027fe3c610e','歲旱絕糧饋米三斗','曾黯','宋','宋诗','song-poetry','','[]','晚景窮如許，饑寒只自憐。',48,'全唐诗/poet.song.184000.json','["晚景窮如許，饑寒只自憐。", "有書遮老眼，無策度荒年。", "故交分瓶粟，豪家貸子錢。", "本無從理相，溝壑未應填。"]'),
('25533e41-fc16-46f3-84d7-5026351e3bcb','還家寄邢德允','曾黯','宋','宋诗','song-poetry','','[]','年來已是飽知津，倦客空驚老大身。',64,'全唐诗/poet.song.184000.json','["年來已是飽知津，倦客空驚老大身。", "傍塞兵戈猶曩日，滿園桃李又新春。", "半生飄泊成何事，一味癡頑略勝人。", "欲問洛翁功用處，夢中了了醉中真。"]'),
('64c23419-63d3-481d-8062-b370598b7f96','車中','曾黯','宋','宋诗','song-poetry','','[]','頻歲驅馳行萬里，還家幸矣敢言疲。',64,'全唐诗/poet.song.184000.json','["頻歲驅馳行萬里，還家幸矣敢言疲。", "雨寒倦馬愁長路，日落棲禽揀穩枝。", "兩扇携持高老畫，一編吟詠放翁詩。", "客途佳處人知少，正在車中兀兀時。"]'),
('cfe76baf-5d18-4479-8320-f5cf117ac8ca','枕上聞角聲有感','曾黯','宋','宋诗','song-poetry','','[]','學劍年來又不成，羈窮誰與共功名。',64,'全唐诗/poet.song.184000.json','["學劍年來又不成，羈窮誰與共功名。", "殊鄉歲歲秋風客，孤壘朝朝曉角聲。", "富貴安能同噲伍，文章不願以詩鳴。", "鹿門幸有幽人約，飯豆羹藜過此生。"]'),
('ac7c6644-c93c-4c0d-a790-6035c43dcbca','散策','曾黯','宋','宋诗','song-poetry','','[]','散策孤峰寺，維舟岸石林。',48,'全唐诗/poet.song.184000.json','["散策孤峰寺，維舟岸石林。", "月寒初看暈，雲淡欲收陰。", "水合雙江急，山連百粵深。", "歸心正無奈，高處莫登臨。"]'),
('fd057b87-ee2d-4a11-b26e-3bef15b7682e','自玉泉至青溪三十里無人煙云是四川赴汴都大路隠隠灌木間土堠猶在','曾黯','宋','宋诗','song-poetry','','[]','蜀人在昔朝京路，斥堠摧頹草木深。',64,'全唐诗/poet.song.184000.json','["蜀人在昔朝京路，斥堠摧頹草木深。", "馬驛錦官俱改轍，獸蹄鳥跡動驚心。", "生人採捕祠烏鬼，强客椎埋隠綠林。", "何日五丁開故道，關河北望可沾襟。"]'),
('02e0572d-deaf-4af4-b05f-a8fdb2c69e4a','題撫州驛','曾黯','宋','宋诗','song-poetry','','[]','一出都門五見春，衣冠空染九衢塵。',32,'全唐诗/poet.song.184000.json','["一出都門五見春，衣冠空染九衢塵。", "山林有約誰留汝，猿鶴無言解怨人。"]'),
('4b2900ce-1ead-4d5c-b515-e545083ad4a0','閑居','曾黯','宋','宋诗','song-poetry','','[]','綠髮老梅千百樹，梅邊略彴是吾家。',64,'全唐诗/poet.song.184000.json','["綠髮老梅千百樹，梅邊略彴是吾家。", "一窗西日不知晚，十月南枝無數花。", "誰信閑身惟鶴伴，自憐愁眼得書遮。", "閉門兀兀太癡絕，起喚扁舟載月華。"]'),
('10399a23-ebbd-4d77-8ac5-24308c54a56c','題寺壁','王暨','宋','宋诗','song-poetry','','[]','奔馳塵土何時了，自歎一官如蟻小。',32,'全唐诗/poet.song.184000.json','["奔馳塵土何時了，自歎一官如蟻小。", "半夜覓宿僧家園，夢裏聞鴉霜月曉。"]'),
('9f506be1-a8bb-45a6-a890-4547dcd000a1','資水橋','張方','宋','宋诗','song-poetry','','[]','二里橋頭車馬行，靈龜背後玉龍橫。',64,'全唐诗/poet.song.184000.json','["二里橋頭車馬行，靈龜背後玉龍橫。", "漲瀧往日驚河伯，砥柱千年要石兄。", "資水右旋江會合，天台西直卦文明。", "吾心怵惕便施手，事所當爲無問名。"]'),
('0fb18e73-278e-47a0-a99d-e053b1b3bd65','泊舟別故','張方','宋','宋诗','song-poetry','','[]','瓣香杓杜老先生，文藝林中許乞盟。',32,'全唐诗/poet.song.184000.json','["瓣香杓杜老先生，文藝林中許乞盟。", "埽葉巖幽酌泉竇，可能續賦洞簫聲。"]'),
('eae9d1c1-f5db-4b39-8c7c-635311fa2ea6','烏尤山','張方','宋','宋诗','song-poetry','','[]','竹橋沙水烏尤渡，絕壁孤崖意氣驕。',32,'全唐诗/poet.song.184000.json','["竹橋沙水烏尤渡，絕壁孤崖意氣驕。", "故與凌雲分半坐，僧窗假寐見金焦。"]'),
('d5bd774b-82ba-4c1a-a8b3-47a45f8fdfd1','玉堂有感','盧祖皋','宋','宋诗','song-poetry','','[]','兩山風雨故留寒，九陌香泥苦未乾。',32,'全唐诗/poet.song.184000.json','["兩山風雨故留寒，九陌香泥苦未乾。", "開到海棠春爛漫，擔頭時得數枝看。"]'),
('97c16ebd-ff34-46b5-8f5e-94ca6d7620e4','松江別詩','盧祖皋','宋','宋诗','song-poetry','','[]','明月垂虹幾度秋，短蓬長是繫人愁。',32,'全唐诗/poet.song.184000.json','["明月垂虹幾度秋，短蓬長是繫人愁。", "暮烟疎雨分携地，更上松江百尺樓。"]'),
('61fe48fd-ecdb-4b91-8cce-65b7bb5d0f5c','廟山道中','盧祖皋','宋','宋诗','song-poetry','','[]','粉黄蛺蝶遶疎籬，山崦人家挂酒旗。',32,'全唐诗/poet.song.184000.json','["粉黄蛺蝶遶疎籬，山崦人家挂酒旗。", "細雨嫩寒衫袖薄，客中知是菊花時。"]'),
('79f0a9c9-d01d-4ba9-8886-58b25a54bf2a','酴醾','盧祖皋','宋','宋诗','song-poetry','','[]','雪顆雲條一架春，酒中風度夢中聞。',32,'全唐诗/poet.song.184000.json','["雪顆雲條一架春，酒中風度夢中聞。", "東風不是無顔色，過了梅花便到君。"]'),
('5e44d03d-eb8a-4cd3-8e34-4fab2aa8f09f','采菊','盧祖皋','宋','宋诗','song-poetry','','[]','旋移黄菊不嫌遲，晴日霜庭晚更宜。',32,'全唐诗/poet.song.184000.json','["旋移黄菊不嫌遲，晴日霜庭晚更宜。", "閑倚石闌衫袖薄，偶然愁思入新詩。"]'),
('8db5de4c-0a16-4c14-8afa-56ec391f0d81','讀書','盧祖皋','宋','宋诗','song-poetry','','[]','細字燈前老不便，小齋新冷夜無眠。',32,'全唐诗/poet.song.184000.json','["細字燈前老不便，小齋新冷夜無眠。", "數聲牆竹蕭蕭雨，一縷銅爐淡淡煙。"]'),
('3f33b0a7-0e8f-4fc0-a595-ce9ef7e77def','煎茶','盧祖皋','宋','宋诗','song-poetry','','[]','秋庭木落長莓苔，寂寞東崗菊自開。',32,'全唐诗/poet.song.184000.json','["秋庭木落長莓苔，寂寞東崗菊自開。", "惟有詩翁幽興熟，每携茶具竹間來。"]'),
('6f360350-b1c9-458f-a70c-bfd01a55ce77','種橘','盧祖皋','宋','宋诗','song-poetry','','[]','小擘枝頭滿袖香，纍纍秋實正宜霜。',32,'全唐诗/poet.song.184000.json','["小擘枝頭滿袖香，纍纍秋實正宜霜。", "每來長是移時去，爲爾風流似故鄉。"]'),
('ecaf3608-a687-4ca6-8835-d279fde3c21e','閑行','盧祖皋','宋','宋诗','song-poetry','','[]','春風入小畦，數日綠陰齊。',48,'全唐诗/poet.song.184000.json','["春風入小畦，數日綠陰齊。", "把酒尋花飲，將詩就壁題。", "鵝兒唼嫩草，燕子集新泥。", "望見垂楊好，閑行過水西。"]'),
('c6392395-40f3-487b-a540-e22bde693850','寄潘道士','盧祖皋','宋','宋诗','song-poetry','','[]','松深古觀幽，長日斷人遊。',48,'全唐诗/poet.song.184000.json','["松深古觀幽，長日斷人遊。", "苔綠幾層雨，山分一半秋。", "病因凉後減，句向靜中求。", "見說燒銀汞，頻將異草收。"]'),
('fb14069c-5ecc-4a95-983f-00f2f2e4031b','舟中獨酌','盧祖皋','宋','宋诗','song-poetry','','[]','有酒何人可共斟，扁舟終日載孤吟。',64,'全唐诗/poet.song.184000.json','["有酒何人可共斟，扁舟終日載孤吟。", "山川似舊客懷老，天地何言春事深。", "風入平湖寒衮衮，鳥啼芳樹綠愔愔。", "幅巾不受紅塵觸，每一郊行一賞心。"]'),
('5be83186-e6c1-4bde-8204-fc712dfb5fea','上方寺','盧祖皋','宋','宋诗','song-poetry','','[]','題詩上方寺，眼闊句難收。',48,'全唐诗/poet.song.184000.json','["題詩上方寺，眼闊句難收。", "地控三吳勝，天連七澤浮。", "路危行跡少，塔壞斷碑留。", "倆屐幾行破，今年不負秋。"]'),
('05a08421-219c-422f-80cd-f42604114334','雨後得月小飲懷趙天樂','盧祖皋','宋','宋诗','song-poetry','','[]','梅花此夜稀，嘉月弄光輝。',48,'全唐诗/poet.song.184000.json','["梅花此夜稀，嘉月弄光輝。", "不飲强呼酒，欲眠重啟扉。", "語高驚鶴睡，坐久見烏飛。", "想見湖居友，扁舟不肯歸。"]'),
('83ac8e50-316b-44a9-a1ad-8d1f6e0dd908','赤松觀','趙肅遠','宋','宋诗','song-poetry','','[]','入門蒼翠合，地暖不知冬。',48,'全唐诗/poet.song.184000.json','["入門蒼翠合，地暖不知冬。", "羊化屋頭石，鶴歸山下松。", "溪清雲影動，碑老蘚痕封。", "帝者師何在，清遊未許從。"]'),
('ff7388eb-fd14-48c5-a255-aa1e178fe3da','雙溪寺用張令韵','趙肅遠','宋','宋诗','song-poetry','','[]','重來尋野興，淡月半松林。',48,'全唐诗/poet.song.184000.json','["重來尋野興，淡月半松林。", "一寺儼如昨，雙溪清到今。", "亂餘僧改貌，秋老客驚心。", "自覺身如寄，山林滋味深。"]'),
('d4be777e-c9f0-4c13-8aa8-5830fa4178ab','多景樓','趙肅遠','宋','宋诗','song-poetry','','[]','露滴甘泉事已休，欲窮多景漫登樓。',64,'全唐诗/poet.song.184000.json','["露滴甘泉事已休，欲窮多景漫登樓。", "雲收北固千帆雨，雁带南淮萬里秋。", "夜色和愁迷古渡，天風吹恨到神州。", "青山尚在英雄老，休說興亡憶舊游。"]'),
('a70aea96-8979-4141-88c0-dc50a8951abe','岳王墳','趙肅遠','宋','宋诗','song-poetry','','[]','來弔英雄骨尚香，一抔黄土當封疆。',64,'全唐诗/poet.song.184000.json','["來弔英雄骨尚香，一抔黄土當封疆。", "自從駐蹕來吳會，誰更提兵入洛陽。", "殯閣有燈秋樹暗，隧碑無字雨苔荒。", "寒鴉不識當時事，猶戀棲霞噪曉霜。"]'),
('2cc1fef2-11a9-4e57-abc1-a6b75900882b','中秋西橋飲酒和盧申之韵','趙肅遠','宋','宋诗','song-poetry','','[]','翠蘋風起落殘紅，秋月正圓秋氣中。',64,'全唐诗/poet.song.184000.json','["翠蘋風起落殘紅，秋月正圓秋氣中。", "但怪肩吾輪桂長，未容文舉酒樽空。", "帆歸南浦潮回北，人散西橋斗轉東。", "烏鵲高飛驚遠目，誤疑天際有來鴻。"]'),
('9f3a9ae9-d294-491b-8339-5f12e6cd7bd1','冬夜偕徐敬室自白石歸','趙肅遠','宋','宋诗','song-poetry','','[]','落葉溪邊卸小舠，似游赤壁步臨皋。',64,'全唐诗/poet.song.184000.json','["落葉溪邊卸小舠，似游赤壁步臨皋。", "溪聲忽靜霜將下，山意生寒月正高。", "舉世夢酣莊氏蝶，此時心在屈平騷。", "梅花雅有幽期舊，特地吹香滿客袍。"]'),
('984f184e-7221-44bc-bd1e-485c653878f8','楊妃菊','趙肅遠','宋','宋诗','song-poetry','','[]','元是馬嵬山下魄，脫胎今復對西風。',32,'全唐诗/poet.song.184000.json','["元是馬嵬山下魄，脫胎今復對西風。", "當時若使三郎見，又自東籬召入宮。"]'),
('ed4885ec-cf01-4245-9452-9f8d5c0b56f0','洩潭瀑布','薛寘','宋','宋诗','song-poetry','','[]','秋高水壯雪飛濤，巖木招風怒竅號。',32,'全唐诗/poet.song.184000.json','["秋高水壯雪飛濤，巖木招風怒竅號。", "不是玉虹低澗飲，白龍拖雨下山腰。"]'),
('ef02020d-ff2b-4649-ba31-a7f7aaa09696','早梅','鄭碩','宋','宋诗','song-poetry','','[]','紛紛蜂蝶莫教知，竹外疏花一兩枝。',32,'全唐诗/poet.song.184000.json','["紛紛蜂蝶莫教知，竹外疏花一兩枝。", "待得枝頭春爛熳，便如詩到晚唐時。"]'),
('b6bbaaa9-d93b-40d3-b0e3-9372789e2003','題翠蛟亭','趙汝諿','宋','宋诗','song-poetry','','[]','百丈寒蛟下翠庭，幽人相對覺風生。',32,'全唐诗/poet.song.184000.json','["百丈寒蛟下翠庭，幽人相對覺風生。", "闌干小倚飛觴處，一曲松風亂雨聲。"]'),
('2ed30a0c-52c4-496c-82ed-5b25775f88fb','大滌洞留題  其一','趙汝諿','宋','宋诗','song-poetry','','[]','坡老吟來今幾齡，翠蛟飛舞若天成。',32,'全唐诗/poet.song.184000.json','["坡老吟來今幾齡，翠蛟飛舞若天成。", "欄干小倚揮觴處，最愛泉聲亂雨聲。"]'),
('2b93b7fa-cf63-42bf-ad73-8df9f1488151','大滌洞留題  其二','趙汝諿','宋','宋诗','song-poetry','','[]','家近雲山九鎖深，誅茅已負十年心。',32,'全唐诗/poet.song.184000.json','["家近雲山九鎖深，誅茅已負十年心。", "筍輿扶醉歸來晚，清夢猶聞金玉音。"]'),
('e0baa161-ea3d-4a2b-a6a8-e9e7632514bb','題翠蛟','羅相','宋','宋诗','song-poetry','','[]','坡仙已跨老鯨去，夭矯一蛟留翠岑。',64,'全唐诗/poet.song.184000.json','["坡仙已跨老鯨去，夭矯一蛟留翠岑。", "頭角要歸滄海闊，鬐鱗聊舞小亭陰。", "停杯欲共馮夷語，倚杖不知嵐氣深。", "休用旌陽持劍起，憐渠終夜抱珠吟。"]'),
('1c48190c-eb4b-422b-a732-cf5309ee4595','題洞霄','羅相','宋','宋诗','song-poetry','','[]','峰回路轉九重關，一柱擎天鎖翠煙。',64,'全唐诗/poet.song.184000.json','["峰回路轉九重關，一柱擎天鎖翠煙。", "斧鑿無痕開六洞，珮環如響萃群仙。", "巖前翔湧雲根石，林下縈飛玉色泉。", "爲愛丹霞留物外，經綸事業付他年。"]'),
('c44adf73-0181-428a-bb73-605cccea294f','和翠蛟','羅相','宋','宋诗','song-poetry','','[]','深淵蟠屈久潛幽，化作狂瀾石澗浮。',64,'全唐诗/poet.song.184000.json','["深淵蟠屈久潛幽，化作狂瀾石澗浮。", "亭宇翬飛閑日月，風雲蹭蹬老春秋。", "天機儘放源難測，地軸陰收蹟莫搜。", "多謝坡仙特拈出，當年得得動宸遊。"]'),
('2ba54c6e-bd7d-48e2-a2ef-718a228f4e5f','句','劉鎔','宋','宋诗','song-poetry','','[]','環城五里皆奇石，疑是虛無海上山。',16,'全唐诗/poet.song.184000.json','["環城五里皆奇石，疑是虛無海上山。"]'),
('04a2eb07-7e9e-4ebf-83a4-2aff53cc46ae','玩鷗亭','陳槩','宋','宋诗','song-poetry','','[]','雨後方池碧漲秋，玩鷗亭檻俯清流。',64,'全唐诗/poet.song.184000.json','["雨後方池碧漲秋，玩鷗亭檻俯清流。", "時看雪翅輕披縠，忽見霜毫細滾毬。", "來往徑隨蘋岸戲，浮沉爭逐晚潮游。", "吾心久欲同斯樂，早已忘機共倡酬。"]'),
('0c038d40-9f53-47b7-ae05-961897c4f61e','浮碇岡','傅烈','宋','宋诗','song-poetry','','[]','洪水未必能流山，別島安得居人間。',240,'全唐诗/poet.song.184000.json','["洪水未必能流山，別島安得居人間。", "扶桑夜半光吐焰，銅龍白晝飛塵寰。", "初聞其事驚且異，傳言豈或流千蠻。", "試將圖牒爲考訂，山中記載皆班班。", "扶藜喜作山中行，勝處不復愁天慳。", "樓臺自是人隔絕，峰岫直與天回環。", "憑虛搜冥一眺望，日觀朱明兩山向。", "乃知雲浮山更浮，二山總在三山上。", "從來凡眼不見識，怪怪奇奇千萬狀。", "我疑靈竇皆國寶，不待山人留心匠。", "丹崖佛迹直末耳，天鞏名山世基仗。", "干戈昔爲聞馬嵬，有壇百尺那能開。", "坐中一笑失道士，國勢隨滅如烟埃。", "清廟祀典歲歲舉，慶基福地源源來。", "願將此山比南山，歌詩直紀山之隈。"]'),
('45e6aee2-b6a6-4237-8b60-9567584ca53f','代陳均輔贈馬則賢','黄樞','宋','宋诗','song-poetry','','[]','江南星渚山水奇，馬家桂子昌于醫。',192,'全唐诗/poet.song.184000.json','["江南星渚山水奇，馬家桂子昌于醫。", "此心契天雄傑者，滿軒種杏仁間馳。", "身雖如蟬蛻濁世，活人遠志傳孫枝。", "偶同瓜葛花屏下，梅兄樊弟相追隨。", "嗟予蜂房病溽暑，熱烘腦子逾蒸炊。", "難甘遂委庸醫手，蒼黄連月累卵危。", "有損無益智者哂，因陳治法宜如斯。", "言非草草果起死，功當歸子夫何疑。", "况又時當半夏月，雨餘凉氣浮輕絺。", "懸壺索寞乏瓊報，木瓜愧誦前人詩。", "蘇耽橘紅井泉碧，威靈仙術終相期。", "陰功百世固未艾，芝田蘭畹春熙熙。"]'),
('2951adf0-a720-4a10-a448-38eff4c8567f','月泉','周仲卿','宋','宋诗','song-poetry','','[]','石罅玉爲髓，月梭金作棱。',48,'全唐诗/poet.song.184000.json','["石罅玉爲髓，月梭金作棱。", "蒼苔誰鑿破，白雪自堅凝。", "穿豈太山霤，清於萬壑冰。", "此中無六月，門外氣如蒸。"]'),
('13a2dd67-ee9d-4e73-baf4-fc456d2da8e8','登石臺山聯句','周仲卿','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.184000.json','["無正文。"]'),
('d94de810-eb85-4184-9359-6f4df4201b3f','梅','周師成','宋','宋诗','song-poetry','','[]','采采芳梅枝，瑣碎白雲姿。',60,'全唐诗/poet.song.184000.json','["采采芳梅枝，瑣碎白雲姿。", "在山千花怨，出山百鳥啼。", "操持思所寄，轉趾述所思。", "清披太始風，寒應太虛月。", "一日拂人衣，三歲香不歇。"]'),
('86f90586-1266-45d2-b431-a7ffbac343a5','鷄冠花','周師成','宋','宋诗','song-poetry','','[]','爪距深藏獨露冠，紫茸簇出弄清寒。',32,'全唐诗/poet.song.184000.json','["爪距深藏獨露冠，紫茸簇出弄清寒。", "五更月下朦朧看，只欠一聲驚夜闌。"]'),
('fb3abce0-3596-431f-9a2d-42933bea755f','新亭','周師成','宋','宋诗','song-poetry','','[]','昔日新亭今則舊，百年名義只如新。',64,'全唐诗/poet.song.184000.json','["昔日新亭今則舊，百年名義只如新。", "高談坐上無安石，灑淚尊前有伯仁。", "對面飛來帆影少，傳音吹過羽書頻。", "青天重喚當時月，放下清光照坐人。"]'),
('62889cd1-96de-4ccc-8ce0-2a1979ac86be','鳳凰臺','周師成','宋','宋诗','song-poetry','','[]','元嘉王子宅，李白重登臨。',48,'全唐诗/poet.song.184000.json','["元嘉王子宅，李白重登臨。", "鳴鳳元非昔，蟠龍直到今。", "凄凉微子事，寂寞茂弘心。", "望斷長安日，懸知屬意深。"]'),
('02b21eab-92f9-4ca7-8e19-7fc6f6806a5d','周處臺  其一','周師成','宋','宋诗','song-poetry','','[]','孝侯遠矣使人懷，安得從之上此臺。',32,'全唐诗/poet.song.184000.json','["孝侯遠矣使人懷，安得從之上此臺。", "幾回一舸荆溪上，苦被風帆浪槳催。"]'),
('c804c907-c4aa-454d-b857-5cba8ba6e369','周處臺  其二','周師成','宋','宋诗','song-poetry','','[]','克己功夫鮮矣能，孔堂今繼仲由登。',32,'全唐诗/poet.song.184000.json','["克己功夫鮮矣能，孔堂今繼仲由登。", "試從臺上看臺下，狂聖中間隔幾層。"]'),
('2adf529f-1760-4b99-9930-c68dbb4ea8b4','吳大帝廟','周師成','宋','宋诗','song-poetry','','[]','曾是東南第一王，眼看此地六興亡。',64,'全唐诗/poet.song.184000.json','["曾是東南第一王，眼看此地六興亡。", "東緣有酒登京口，西爲無魚憶武昌。", "非復虎臣陪殿上，空餘猩血泣祠旁。", "何年並建琅玡廟，共對淮山草木長。"]'),
('0007eb0c-3ab0-4eb8-bf4f-d8b1635f04a9','酬張韓伯','周師成','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','楚人逢楚節，仍賦楚情詩。',48,'全唐诗/poet.song.184000.json','["楚人逢楚節，仍賦楚情詩。", "滴酒長江遠，思鄉白日遲。", "遥憐壯士腕，也繫兒女絲。", "若有盈妾艾，榴花勿並持。"]'),
('8bd9dfcc-eb17-4d2a-a511-25982b29b607','金陵','周師成','宋','宋诗','song-poetry','','[]','故國已云久，地餘風流情。',48,'全唐诗/poet.song.184000.json','["故國已云久，地餘風流情。", "山花不斷市，江鷗長入城。", "青溪泓玉水，紅樓調春聲。", "斟酌飛仙過，枉轡一來行。"]'),
('30735b92-57f4-44a1-b904-93b69c986fd1','下水門稅亭','周師成','宋','宋诗','song-poetry','','[]','建業塵中吏，秦淮水上亭。',48,'全唐诗/poet.song.184000.json','["建業塵中吏，秦淮水上亭。", "浴晴鳬弄日，飲曉馬吞星。", "地迥來芳草，潮回出斷汀。", "有僧時到此，相對兩浮萍。"]'),
('55777de0-56b6-4a28-95ee-13756344b372','古詩  其一','周師成','宋','宋诗','song-poetry','','[]','昔懷今未歸，悄悄與誰語。',72,'全唐诗/poet.song.184000.json','["昔懷今未歸，悄悄與誰語。", "超超何所爲，空齋聽春雨。", "鏘然金玉聲，幽窗相爾汝。", "政以平在中，萬物皆媚嫵。", "暗想四城外，花草不可數。", "浮雲日夜征，東皋悵何許。"]'),
('c36c10a2-66e2-46a0-959d-1119550e73ee','古詩  其二','周師成','宋','宋诗','song-poetry','','[]','德人天機深，凡子人心多。',72,'全唐诗/poet.song.184000.json','["德人天機深，凡子人心多。", "懔余思寡過，月計愧盈科。", "勿謂玉無玼，當知石可磨。", "四十尚無聞，素心恐蹉跎。", "汲我檐下井，澆我盤中花。", "清香未似之，懶惰欲如何。"]'),
('dbff74ef-e3a4-4d62-99e7-fbadd7cb17d6','句  其一','周師成','宋','宋诗','song-poetry','','[]','黄蘆花白月無頼，烏桕葉紅秋可憐。',16,'全唐诗/poet.song.184000.json','["黄蘆花白月無頼，烏桕葉紅秋可憐。"]'),
('c3ca6ed1-d951-4e19-ae3b-bb7e51ea671c','句  其二','周師成','宋','宋诗','song-poetry','','[]','花縮添新紫，香消減舊黄。',12,'全唐诗/poet.song.184000.json','["花縮添新紫，香消減舊黄。"]'),
('33d483e8-f6bf-4ba6-96cf-89868ca3c906','騮獅嶺','上官彥宗','宋','宋诗','song-poetry','','[]','遠望輕雲絕頂浮，泉聲山色破牢愁。',32,'全唐诗/poet.song.184000.json','["遠望輕雲絕頂浮，泉聲山色破牢愁。", "當年曾有幽棲客，坐對春風萬壑流。"]'),
('e8788645-c235-4cc1-94c0-c4b45c872c0d','青紫峰亭','陳應辰','宋','宋诗','song-poetry','','[]','鐵壁嶙峋構小亭，瀟然雲棟接風櫺。',64,'全唐诗/poet.song.184000.json','["鐵壁嶙峋構小亭，瀟然雲棟接風櫺。", "煙光橫抹半峰紫，山色不磨千古青。", "老去久無金馬夢，歸遲應媿草堂靈。", "明經拾芥成何事，得似朝來對翠屏。"]'),
('aac3b0e8-04e0-4e6d-a8b9-5c2bd482bbf5','送鄭惟泰丞江山','張柏父','宋','宋诗','song-poetry','','[]','都城十兩車，送子江之滸。',108,'全唐诗/poet.song.184000.json','["都城十兩車，送子江之滸。", "目寄片帆飛，水國沿漁浦。", "憐子經世才，戰筆文中虎。", "小試乘田車，暫爲民父母。", "民社不輕寄，憂戚抱民苦。", "忠孝指心切，求不愧仰俯。", "青天遇有闕，思惟煉石補。", "效職了男兒，一扇醇風古。", "送子獨鍾情，淮河共鄉土。"]'),
('5aadde4f-500f-4d11-8130-0dc894b3068e','大小寒','趙某','宋','宋诗','song-poetry','','[]','蹇衛衝風怯曉寒，也隨舉子到長安。',32,'全唐诗/poet.song.184000.json','["蹇衛衝風怯曉寒，也隨舉子到長安。", "路人莫作皇親看，姓趙如今不似韓。"]'),
('1910a630-c8af-4a39-91d0-71a663fef598','偈頌九十三首  其一','釋梵琮','宋','宋诗','song-poetry','','[]','直進直出，直行直用。',20,'全唐诗/poet.song.184000.json','["直進直出，直行直用。", "瞥轉玄關，百發百中。"]'),
('5db3a781-ba1b-4dcf-9aff-474d1c63fb87','偈頌九十三首  其二','釋梵琮','宋','宋诗','song-poetry','','[]','指地指天，草賊大敗。',20,'全唐诗/poet.song.184000.json','["指地指天，草賊大敗。", "入草求人，聊展三拜。"]'),
('aef7c4fd-1c09-476f-bfb9-50ed7e7e2751','偈頌九十三首  其三','釋梵琮','宋','宋诗','song-poetry','','[]','據此丈室，無可不可。',46,'全唐诗/poet.song.184000.json','["據此丈室，無可不可。", "要行即行，要坐便坐。", "漆桶相挨，一時打破。", "三脚蝦𢋙透九垓，笑倒嵩山破竈墮。"]'),
('c2c1fb16-689d-4e29-a66d-02a692e06b48','偈頌九十三首  其四','釋梵琮','宋','宋诗','song-poetry','','[]','一兩三四五，六七八九十。',24,'全唐诗/poet.song.184000.json','["一兩三四五，六七八九十。", "坐斷頂𩕳頭，千聖望不及。"]'),
('8e93d5fa-7ff5-41a3-b38b-a3f92018c841','偈頌九十三首  其五','釋梵琮','宋','宋诗','song-poetry','','[]','湖上一片雲，明月爲知己。',24,'全唐诗/poet.song.184000.json','["湖上一片雲，明月爲知己。", "却被清風吹，吹入深山裏。"]'),
('5dd7b57e-b960-4246-ab38-1f996db67fb3','偈頌九十三首  其六','釋梵琮','宋','宋诗','song-poetry','','[]','打破虛空無縫，衲僧隨處受用。',28,'全唐诗/poet.song.184000.json','["打破虛空無縫，衲僧隨處受用。", "却因聖制入山，雲北雲南做夢。"]'),
('4cc0dc26-c423-4fe6-a1fb-927b8ca2c0a9','偈頌九十三首  其七','釋梵琮','宋','宋诗','song-poetry','','[]','今朝結制，事事超詣。',50,'全唐诗/poet.song.184000.json','["今朝結制，事事超詣。", "問訊燒香，衲僧巴鼻。", "人事上下，巡堂次第。", "無位真人，驀忽噴嚏。", "布袋頭結，吉無不利。"]'),
('716c4bc9-1387-4e75-9ead-b23e7201c11a','偈頌九十三首  其八','釋梵琮','宋','宋诗','song-poetry','','[]','太白禪師，全無伎倆。',68,'全唐诗/poet.song.184000.json','["太白禪師，全無伎倆。", "一錫飛來，占斷千嶂。", "以中心樹，建立聖像。", "合水和泥，根生土長。", "不用換骨脫胎，不須起模打樣。", "一段真實身心，腦後圓光萬丈。"]'),
('c145c84c-136c-4abc-a16b-d730c3a9cb0d','偈頌九十三首  其九','釋梵琮','宋','宋诗','song-poetry','','[]','老觀當場闡大機，逢人赤手爲提持。',32,'全唐诗/poet.song.184000.json','["老觀當場闡大機，逢人赤手爲提持。", "若能直下知端的，佛海波瀾無盡時。"]'),
('62479c94-71bd-4ed6-ac85-83f1f1efd6e6','偈頌九十三首  其一○','釋梵琮','宋','宋诗','song-poetry','','[]','東山水上行，乾元利貞亨。',24,'全唐诗/poet.song.184000.json','["東山水上行，乾元利貞亨。", "誵訛一箇字，才子競頭爭。"]'),
('f2d2cb13-1e38-43ac-9dc6-d707ae8663df','偈頌九十三首  其一一','釋梵琮','宋','宋诗','song-poetry','','[]','今朝正當端午節，衲僧倒用真妙訣。',86,'全唐诗/poet.song.184000.json','["今朝正當端午節，衲僧倒用真妙訣。", "轉聖作凡，點金成鐵。", "却把山茶，以替竹葉。", "角黍滿盤，菖蒲細切。", "雖然俗氣未除，也要大家暖熱。", "百草頭邊，艾人懽悅。", "千峰影裏笑不休，野猿時把藤蘿拽。"]'),
('5e04c836-7b7e-46d6-ae8c-40c9c638df72','偈頌九十三首  其一二','釋梵琮','宋','宋诗','song-poetry','','[]','禁足不定足，居中不住中。',136,'全唐诗/poet.song.184000.json','["禁足不定足，居中不住中。", "去來無罣礙，踢踏活虛空。", "射殺南山虎，翻身控角弓。", "上無攀仰，下絕己躬。", "孤迥迥一塵不立，清寥寥目斷千峰。", "白雲片片，流水重重。", "驀忽和盤掇轉，却要喚西作東。", "生鐵團上，迸開罅縫。", "枯河道裏，露出魚蹤。", "不是妙用，亦非神通。", "大家無別事，平等主人翁。", "咄，老來雙耳聾。"]'),
('2e25f8be-3d6e-4aa4-b7ca-7e5166ffc621','偈頌九十三首  其一三','釋梵琮','宋','宋诗','song-poetry','','[]','趙州南，石橋北，觀音院裏有彌勒。',61,'全唐诗/poet.song.184000.json','["趙州南，石橋北，觀音院裏有彌勒。", "祖師遺下一隻履，直至而今覓不得。", "趙州老子，信手栽荆棘，當門種蒺蔾。", "四方人不到，徒自暗攢眉。"]'),
('eb0fdff2-255b-4dcd-bf8d-e002c084c228','偈頌九十三首  其一四','釋梵琮','宋','宋诗','song-poetry','','[]','世尊拈花，迦葉破顔。',68,'全唐诗/poet.song.184000.json','["世尊拈花，迦葉破顔。", "只因學步，失却邯鄲。", "斫却庭前樹，放出雲外山。", "行人纔眨眼，身在畫圖間。", "鳥飛不到處，今古絕躋攀。", "洞天人去後，誰解倚欄干。"]'),
('17528454-d807-41ba-9c67-0235adda3e48','偈頌九十三首  其一五','釋梵琮','宋','宋诗','song-poetry','','[]','打皷槌鑼競上竿，幾人平地足心酸。',140,'全唐诗/poet.song.184000.json','["打皷槌鑼競上竿，幾人平地足心酸。", "七峰有箇安身法，袖手無言冷處看。", "看即易，上即難。", "搭索上橫身，剎竿上闘走。", "驀忽轉身，打箇筋斗。", "佛祖當場，各出標手。", "微笑因拈華，一時成漏逗。", "洞山麻三斤，雲門乾屎橛。", "德山入門棒，臨濟入門喝，陽焰何曾止得渴。", "衲僧別有條章，今日對衆分雪。", "珠稱夜光，劍號巨闕。"]'),
('dfee812f-a702-414a-80dc-cd85d7e99836','偈頌九十三首  其一六','釋梵琮','宋','宋诗','song-poetry','','[]','仙居多異草，聖地絕凡蹤。',24,'全唐诗/poet.song.184000.json','["仙居多異草，聖地絕凡蹤。", "秋風動鱗甲，生蛇化活龍。"]'),
('29d645a9-d312-49de-864e-0ff9f2ef73c2','偈頌九十三首  其一七','釋梵琮','宋','宋诗','song-poetry','','[]','安居九十日，閒中滋味長。',36,'全唐诗/poet.song.184000.json','["安居九十日，閒中滋味長。", "幸好一盤飯，何用糝椒薑。", "陞堂重舉話，雪上更加霜。"]'),
('eb5b71fe-51fe-4012-b162-aa2030a30a47','偈頌九十三首  其一八','釋梵琮','宋','宋诗','song-poetry','','[]','分冬時節，一物不違。',101,'全唐诗/poet.song.184000.json','["分冬時節，一物不違。", "大家出手，各各提持。", "白糍片片打硬，山果大小隨宜。", "衲僧家，牙如劍樹，口似龍池。", "入齒下咬著，吞吐唾霧霏霏。", "驀忽撞著栗棘，直得暗裏攢眉。", "颺在糞掃堆上，千聖從來不知。", "洞山掇轉處，喪却目前機。"]'),
('bfc3e14e-7363-4ca5-babb-ffbf864505f7','偈頌九十三首  其一九','釋梵琮','宋','宋诗','song-poetry','','[]','强言一物揚家醜，引得傍觀入座來。',32,'全唐诗/poet.song.184000.json','["强言一物揚家醜，引得傍觀入座來。", "笑裏和盤輕掇轉，七峰岌嶪舞三臺。"]'),
('45bc0dbb-a363-40b8-a98f-c6a029c1fd34','偈頌九十三首  其二○','釋梵琮','宋','宋诗','song-poetry','','[]','晴明冬至，吉無不利。',104,'全唐诗/poet.song.184000.json','["晴明冬至，吉無不利。", "坐卧經行，焚香掃地。", "祖師眼睛，衲僧巴鼻。", "八節四時，各安本位。", "拂子點頭，懽懽喜喜。", "洞天優游，欣逢節序。", "君子道長，小人回避。", "時添一線長，光陰不虛棄。", "把定乾坤，據何道理。", "磉下藏黄金，豐城埋劍氣。"]'),
('20c68839-d086-4cda-9e19-1999af0e6b1f','偈頌九十三首  其二一','釋梵琮','宋','宋诗','song-poetry','','[]','因覩明星悟道，未免全身入草。',42,'全唐诗/poet.song.184000.json','["因覩明星悟道，未免全身入草。", "带累後代兒孫，却把白衣染貌。", "七峰當日見他，劈面一拳打倒。"]'),
('75552c64-2e95-45c3-873c-8c46407ac65e','偈頌九十三首  其二二','釋梵琮','宋','宋诗','song-poetry','','[]','七峰無可分歲，抖擻多年活計。',58,'全唐诗/poet.song.184000.json','["七峰無可分歲，抖擻多年活計。", "拂子擺尾摇頭，解作獅子遊戲。", "等閑哮吼一聲，直得驚天動地。", "東村老徹夜燒錢，地爐神不敢瞌睡。"]'),
('f7080d0c-5fef-408b-861f-17a3a888ea9f','偈頌九十三首  其二三','釋梵琮','宋','宋诗','song-poetry','','[]','歲除無物可相延，四壁深圍滿屋煙。',32,'全唐诗/poet.song.184000.json','["歲除無物可相延，四壁深圍滿屋煙。", "幾度撥開還自問，柴頭盡處是新年。"]'),
('5a2add1f-b320-48f2-b09e-503d2534fd2d','偈頌九十三首  其二四','釋梵琮','宋','宋诗','song-poetry','','[]','元正啟祚，萬物咸新。',36,'全唐诗/poet.song.184000.json','["元正啟祚，萬物咸新。", "不勞擬議，覿體全真。", "到此更須進步，却來拂子頭上翻身。"]'),
('c3aa6c59-431c-41f6-9d85-d666f1b742e6','偈頌九十三首  其二五','釋梵琮','宋','宋诗','song-poetry','','[]','月不過五，今日親到。',52,'全唐诗/poet.song.184000.json','["月不過五，今日親到。", "知時識節，隨宜愛道。", "不說向上宗乘，不拋東山暗號。", "露柱與燈籠，撞著呵呵笑，韓信放鐵鷂。"]'),
('e0f03a90-f50f-4206-81f4-45c3b5cf0a54','偈頌九十三首  其二六','釋梵琮','宋','宋诗','song-poetry','','[]','百丈野狐，石女無夫。',20,'全唐诗/poet.song.184000.json','["百丈野狐，石女無夫。", "一回淚下，滄海乾枯。"]'),
('32afb3d6-9f07-468c-8c8c-31ff7fee7d3e','偈頌九十三首  其二七','釋梵琮','宋','宋诗','song-poetry','','[]','三通皷罷，長老陞堂。',90,'全唐诗/poet.song.184000.json','["三通皷罷，長老陞堂。", "兩班問信，侍者燒香。", "未曾啟口，各各舉揚。", "道從信入，信能主張。", "以長就短，以短從長。", "有客雲外至，設供飽枯腸。", "恢恢有餘刃，別有好商量。", "暗中信手纔拈得，贏得呵呵笑一場。"]'),
('979c8450-fc70-4671-89f5-781f4bf67c84','偈頌九十三首  其二八','釋梵琮','宋','宋诗','song-poetry','','[]','鐘聲披起鬰多羅，信手拈來不在多。',32,'全唐诗/poet.song.184000.json','["鐘聲披起鬰多羅，信手拈來不在多。", "堪笑當年明上座，狼忙馳逐太奔波。"]'),
('ce4cfd80-357d-4a90-9151-c7b254edfddf','偈頌九十三首  其二九','釋梵琮','宋','宋诗','song-poetry','','[]','袈裟拈得喜輕便，一片閒雲擁半肩。',32,'全唐诗/poet.song.184000.json','["袈裟拈得喜輕便，一片閒雲擁半肩。", "莫怪逢人頻抖擻，借婆裙子拜婆年。"]'),
('5f2f3358-25f2-4115-998f-4a6d13c4e7ce','偈頌九十三首  其三○','釋梵琮','宋','宋诗','song-poetry','','[]','上方一夜開香積，天曉堂中喫雪團。',32,'全唐诗/poet.song.184000.json','["上方一夜開香積，天曉堂中喫雪團。", "信手拈來當面擲，不知誰識爲人寒。"]'),
('e41f8147-cf57-41c9-8367-d731d4b5845d','偈頌九十三首  其三一','釋梵琮','宋','宋诗','song-poetry','','[]','春雪消，春水足。',74,'全唐诗/poet.song.184000.json','["春雪消，春水足。", "春風吹起洞天雲，落梅點破蒼苔綠。", "言發非聲，色前不物。", "百草頭露眼睛，虛空裏揣出骨。", "林間衲子樂無爲，曉來唱箇太平曲。", "新歲相逢，伏惟萬福。"]'),
('d2a67698-19eb-4fd7-b410-aa74ea8cb27f','偈頌九十三首  其三二','釋梵琮','宋','宋诗','song-poetry','','[]','今朝二月二十五，等閑觸發千鈞弩。',116,'全唐诗/poet.song.184000.json','["今朝二月二十五，等閑觸發千鈞弩。", "一箭中紅心，大地無寸土。", "四圍上下絕遮欄，露出太白庵中主。", "去歲因喪本師歸，未免聲聲叫冤苦。", "苦中樂，樂中苦。", "喝退慈明舊日婆，移凶就吉改墳墓。", "南溪流水青如螺，深居落花紅似雨。", "先師面目儼然存，分付老堅堅收取。"]'),
('85b8a136-f403-4594-a78f-06c1ecdead95','偈頌九十三首  其三三','釋梵琮','宋','宋诗','song-poetry','','[]','了知生死本來同，無數深紅間淺紅。',32,'全唐诗/poet.song.184000.json','["了知生死本來同，無數深紅間淺紅。", "堪笑衲僧無用處，盡將衣鉢付春風。"]'),
('83132bbe-d81e-4e76-b271-3715a0553074','偈頌九十三首  其三四','釋梵琮','宋','宋诗','song-poetry','','[]','勞生正昏睡，侵曉已先行。',24,'全唐诗/poet.song.184000.json','["勞生正昏睡，侵曉已先行。", "到家一著子，日出事還生。"]'),
('baead776-c674-43cf-a974-4de1a490c818','偈頌九十三首  其三五','釋梵琮','宋','宋诗','song-poetry','','[]','今朝四月初十，衲僧獨行特立。',72,'全唐诗/poet.song.184000.json','["今朝四月初十，衲僧獨行特立。", "等閑瞥轉玄關，捏碎虛空出汁。", "電光裡𨁝跳，微塵裡出沒。", "嶮峻崖前百步階，一級自然高一級。", "脚頭脚尾不爭多，千里烏騅追不及。"]'),
('bbb5279d-0763-4aea-bb6e-eca2fcc57446','偈頌九十三首  其三六','釋梵琮','宋','宋诗','song-poetry','','[]','夜來無一事，天曉報上堂。',24,'全唐诗/poet.song.184000.json','["夜來無一事，天曉報上堂。", "幸好一盤飯，何用糝椒薑。"]'),
('64cbb707-446f-42c8-976e-cb40e0c7df46','偈頌九十三首  其三七','釋梵琮','宋','宋诗','song-poetry','','[]','三世諸佛不知有，顛狂普化翻筋斗。',72,'全唐诗/poet.song.184000.json','["三世諸佛不知有，顛狂普化翻筋斗。", "狸奴白牯却知有，寒拾相逢開笑口。", "野干鳴，師子吼。", "八兩半斤，十升一斗。", "不從他覓，須還自有。", "犬不擇家貧，子不嫌母醜。"]'),
('d575f8e2-30ea-4901-82f5-85794eaf5b3c','偈頌九十三首  其三八','釋梵琮','宋','宋诗','song-poetry','','[]','趙州庭柏，說向禪客。',20,'全唐诗/poet.song.184000.json','["趙州庭柏，說向禪客。", "物是實價，錢須足陌。"]'),
('458651e8-c84a-47c9-93d5-6cd5bc742507','偈頌九十三首  其三九','釋梵琮','宋','宋诗','song-poetry','','[]','佛如展手，道似握拳。',36,'全唐诗/poet.song.184000.json','["佛如展手，道似握拳。", "全提正令，無黨無偏。", "蟭螟眼裏放夜市，大蟲舌上打秋千。"]'),
('047c8c1a-cce1-40ce-97e4-94822e74cdd0','偈頌九十三首  其四○','釋梵琮','宋','宋诗','song-poetry','','[]','十五日已前是結，十五日已後是解。',93,'全唐诗/poet.song.184000.json','["十五日已前是結，十五日已後是解。", "結也著，解也著，開眼合眼，伸脚縮脚。", "佛祖老婆，應病與藥。", "而今正體全安，藥病一時掃却。", "赤條條，空索索，月下風前嘯一聲，驚起松梢千歲鶴。", "錯錯，風吹殿角摇鈴鐸。"]'),
('e2647a37-fdd3-4afe-a5c6-55f5d7292510','偈頌九十三首  其四一','釋梵琮','宋','宋诗','song-poetry','','[]','一切即一，一即一切。',113,'全唐诗/poet.song.184000.json','["一切即一，一即一切。", "者也之乎，鷄豚狗彘。", "驀忽擘破面皮，喝退德山臨濟。", "黄檗施財，甘贄密契。", "財法二施，等無差別。", "指鹿爲馬，喚龜作鼈。", "說時點，點時說。", "要作破家兒孫，宜把祖燈吹滅。", "上下三指，彼此七馬，如何分雪。", "休分雪，簷□細雨何曾歇。"]'),
('5e5cf384-82a2-4b8b-85c7-fb734f1e9ac5','偈頌九十三首  其四二','釋梵琮','宋','宋诗','song-poetry','','[]','今朝當八月旦，衲僧眼親手辨。',74,'全唐诗/poet.song.184000.json','["今朝當八月旦，衲僧眼親手辨。", "放出金剛箭，射落天邊雁。", "蒸不熟，煮不爛。", "捏不聚，撥不散。", "解空不解深藏，惹得空中贊歎。", "休贊歎，換却天下眼睛，只消一箇木梙。"]'),
('5cfdb0f1-96a8-4595-aa40-6b968976d010','偈頌九十三首  其四三','釋梵琮','宋','宋诗','song-poetry','','[]','求道如求雨，乾枯日夜愁。',156,'全唐诗/poet.song.184000.json','["求道如求雨，乾枯日夜愁。", "忽然風雨至，萬壑盡爭流。", "直得天下萬物沾潤，三井龍王出頭。", "雲南如劈箭，雲北似傾湫。", "激石怒雷吼，翻空雪浪浮。", "忽然風雨息，平地一時休。", "衲僧家，騎箇水牯牛。", "多快活，百無憂。", "健即行，困即歇。", "布袋頭，親解結。", "釘打釘，鐵打鐵。", "寒道寒，熱道熱。", "此是諸佛心宗，亦名單提妙訣。", "七峰峰頂滑如苔，寒山拾得相拖拽。"]'),
('ff4f0748-2c1a-40b4-ae1c-234d694b62b6','偈頌九十三首  其四四','釋梵琮','宋','宋诗','song-poetry','','[]','普天迎瑞氣，徧界慶生辰。',36,'全唐诗/poet.song.184000.json','["普天迎瑞氣，徧界慶生辰。", "水有朝宗意，葵傾向日心。", "衲僧隨日轉，林下仰天庭。"]'),
('9edfab98-8475-4c68-a958-02514a93f909','偈頌九十三首  其四五','釋梵琮','宋','宋诗','song-poetry','','[]','白雲無定，明月有期。',56,'全唐诗/poet.song.184000.json','["白雲無定，明月有期。", "欲出未出，似歸不歸。", "秋山呈錦繡，紅葉滿林飛。", "瞥不瞥，知不知。", "鏡裏無塵閒處照，柴頭有火暗中吹。"]'),
('90452c52-0263-4ccf-9323-b3ade145a8a1','偈頌九十三首  其四六','釋梵琮','宋','宋诗','song-poetry','','[]','九月盡，十月初。',32,'全唐诗/poet.song.184000.json','["九月盡，十月初。", "山下開田，山上開爐。", "開田要博飯喫，開爐暖熱身軀。"]'),
('dd1fe3ac-5f9c-436c-928a-357c290378a6','偈頌九十三首  其四七','釋梵琮','宋','宋诗','song-poetry','','[]','片紙展信旗，舒卷通消息。',24,'全唐诗/poet.song.184000.json','["片紙展信旗，舒卷通消息。", "其中一箇字，今古無人識。"]'),
('ae1ae354-9229-451a-af45-3e80d1df6e48','偈頌九十三首  其四八','釋梵琮','宋','宋诗','song-poetry','','[]','炳然字義，文彩希奇。',46,'全唐诗/poet.song.184000.json','["炳然字義，文彩希奇。", "夫子不識，達磨不知。", "同風千里，笑展雙眉。", "八十翁翁入場屋，真箇不是小兒嬉。"]'),
('18590445-be3f-4477-b6d4-27031d4ab57e','偈頌九十三首  其四九','釋梵琮','宋','宋诗','song-poetry','','[]','滅門刺史，破家縣令。',30,'全唐诗/poet.song.184000.json','["滅門刺史，破家縣令。", "一句全提，頭正尾正。", "塞却耳根，諦聽諦聽。"]'),
('a1be99ab-5c4c-4bc7-bae6-b9ee44eebbfb','偈頌九十三首  其五○','釋梵琮','宋','宋诗','song-poetry','','[]','赤手爲提綱，豁開善法堂。',78,'全唐诗/poet.song.184000.json','["赤手爲提綱，豁開善法堂。", "燈籠開口笑，露柱放毫光。", "去即印住，住即印破。", "不去不住，玄關金鎖。", "放開一線，無可不可。", "五老暗點頭，東湖輕抹過。", "唱箇月彎彎，調古無人和。"]'),
('e3c1d054-0d9e-4a9b-b9c7-9121a3523605','偈頌九十三首  其五一','釋梵琮','宋','宋诗','song-poetry','','[]','當門有路，衝開碧落。',36,'全唐诗/poet.song.184000.json','["當門有路，衝開碧落。", "轉少移身，將錯就錯。", "一槌打碎趙州關，空裏磨盤生八角。"]'),
('6c006c76-c16a-4d25-b123-432248a7c1e2','偈頌九十三首  其五二','釋梵琮','宋','宋诗','song-poetry','','[]','方丈門中，了無罅縫。',40,'全唐诗/poet.song.184000.json','["方丈門中，了無罅縫。", "維摩文殊，相逢皷籠。", "昨夜三更，打失鼻孔。", "普請諸人，各摸索著。"]'),
('5aae1026-dbb1-42f6-8cc2-e41f4e189038','偈頌九十三首  其五三','釋梵琮','宋','宋诗','song-poetry','','[]','據此座者，說無味話。',20,'全唐诗/poet.song.184000.json','["據此座者，說無味話。", "上下三指，彼此七馬。"]'),
('f18e95b4-fdf2-4603-ac01-8c8da7c9a154','偈頌九十三首  其五四','釋梵琮','宋','宋诗','song-poetry','','[]','根從江西來，還向江西爇。',28,'全唐诗/poet.song.184000.json','["根從江西來，還向江西爇。", "一笑掀天只自知，天上拈來成漏泄。"]'),
('b9fb9a4e-6a91-44c9-a4b6-356c203d07de','偈頌九十三首  其五五','釋梵琮','宋','宋诗','song-poetry','','[]','舊店重開，全無買賣。',20,'全唐诗/poet.song.184000.json','["舊店重開，全無買賣。", "擬欲近前，知君納敗。"]'),
('4433d059-6125-47e9-a65d-9ebdbfc5fbf6','偈頌九十三首  其五六','釋梵琮','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','不離家舍，常在途中。',84,'全唐诗/poet.song.184000.json','["不離家舍，常在途中。", "途中家舍，觸處相逢。", "人從明州來，却入廬山去。", "雲間逢五老，因問途中事。", "難難，狂風吹入拆船灣。", "易易，揚瀾左蠡平如砥。", "也不難，也不易，仰面看天，低頭取氣。"]'),
('0d917cf7-794e-4572-916b-93f4065f4729','偈頌九十三首  其五七','釋梵琮','宋','宋诗','song-poetry','','[]','豁開萬仞崖，劈面通消息。',24,'全唐诗/poet.song.184000.json','["豁開萬仞崖，劈面通消息。", "一條白練飛，界破青山色。"]'),
('95c6b2ed-1d40-4ab5-b202-e84464dca39c','偈頌九十三首  其五八','釋梵琮','宋','宋诗','song-poetry','','[]','不搽紅粉色，不挂綠羅衣。',24,'全唐诗/poet.song.184000.json','["不搽紅粉色，不挂綠羅衣。", "一般閑態度，淡墨畫蛾眉。"]'),
('652e76a2-f19f-4089-8fb2-bbcb806017d3','偈頌九十三首  其五九','釋梵琮','宋','宋诗','song-poetry','','[]','忻逢四老，頭白如新。',54,'全唐诗/poet.song.184000.json','["忻逢四老，頭白如新。", "喙長百尺，鼻重千斤。", "眼隨青嶂合，眉带野花顰。", "迎來送去，以表慇懃。", "爲何如此，遠親不如近隣。"]'),
('d091805d-16d0-44cc-92c6-9d7f9535c32b','偈頌九十三首  其六○','釋梵琮','宋','宋诗','song-poetry','','[]','學道先須有指歸，聞聲見色不思議。',126,'全唐诗/poet.song.184000.json','["學道先須有指歸，聞聲見色不思議。", "九旬黑白分明處，如似盤中一片碁。", "縱橫十字，一著當機。", "有眼則活，無眼則輸。", "爛柯山上，空自躊躇。", "正好和盤翻却，直教脫盡規模。", "解不可得，結亦無拘。", "髑髏識盡，江海乾枯。", "憍梵波提吐舌，西天胡子無鬚。", "色裡膠青只些子，王維妙手亦難圖。"]'),
('71c3e07c-78ba-4f01-be0c-a1aa9e316239','偈頌九十三首  其六一','釋梵琮','宋','宋诗','song-poetry','','[]','出叢林與入叢林，一句當機絕古今。',31,'全唐诗/poet.song.184000.json','["出叢林與入叢林，一句當機絕古今。", "不涉流清到底，九江江水未爲深。"]'),
('17e19a13-fa86-4b55-a7b2-ee31d8d6b4f4','偈頌九十三首  其六二','釋梵琮','宋','宋诗','song-poetry','','[]','新羅僧問答新羅，飛騎將軍意氣多。',32,'全唐诗/poet.song.184000.json','["新羅僧問答新羅，飛騎將軍意氣多。", "奪賊鎗來騎賊馬，不勞餘刃罷干戈。"]'),
('b5575e18-72be-4735-830b-014c83855b9a','偈頌九十三首  其六三','釋梵琮','宋','宋诗','song-poetry','','[]','突出山前古寺基，趙州聞得便攢眉。',32,'全唐诗/poet.song.184000.json','["突出山前古寺基，趙州聞得便攢眉。", "寥寥今古無人共，一片斷雲天外飛。"]'),
('2b0f4e59-d776-4058-b74b-55525be8172e','偈頌九十三首  其六四','釋梵琮','宋','宋诗','song-poetry','','[]','今朝九月九，物物盡知有。',40,'全唐诗/poet.song.184000.json','["今朝九月九，物物盡知有。", "黄花散金錢，茱萸開口笑。", "五老絮帽落風前，陶公醉石翻筋斗。"]'),
('dc41862a-a073-4c29-b809-6c5653b3f144','偈頌九十三首  其六五','釋梵琮','宋','宋诗','song-poetry','','[]','雲居九月半，月向掌中圓。',24,'全唐诗/poet.song.184000.json','["雲居九月半，月向掌中圓。", "覓之亡影象，用之亡正偏。"]'),
('0d276a6b-2ee3-44ff-865a-4994cff9c2e7','偈頌九十三首  其六六','釋梵琮','宋','宋诗','song-poetry','','[]','日日途中行，夜夜家裏坐。',34,'全唐诗/poet.song.184000.json','["日日途中行，夜夜家裏坐。", "日日與夜夜，自然成日課。", "咄，一串數珠數不過。"]'),
('bf2fb2e1-5d84-4b04-ba90-64f5f8cc5873','偈頌九十三首  其六七','釋梵琮','宋','宋诗','song-poetry','','[]','開爐無可做，大家團團坐。',82,'全唐诗/poet.song.184000.json','["開爐無可做，大家團團坐。", "坐久却成勞，撥動爐中火。", "火星忽迸散，內外俱照破。", "一聲寒雁叫長空，雲中道人正高卧。", "驀忽翻身吐氣來，且喫胡餠十數箇。", "食飽多傷心，切忌向浄地上屙。"]'),
('3537df6c-98f3-46b6-adb6-f6de48a8de55','偈頌九十三首  其六八','釋梵琮','宋','宋诗','song-poetry','','[]','今朝十月半，批判舊公案。',166,'全唐诗/poet.song.184000.json','["今朝十月半，批判舊公案。", "達磨不會單傳，夫子不會一貫。", "老聃不會無爲，洞賓不會煅煉。", "長老不會說禪，衲僧不會穿線。", "萬象光中容易度，一毫頭上最難逢。", "半夜玉兔懷胎，天明金鷄生卵。", "養得鳳凰兒，百鳥不敢看。", "踏折梧桐枝，飛去天崖畔。", "招手喚歸來，雲中得相伴。", "飲啄皆自然，一切總成見。", "鳳凰兒，鳳凰兒，被閻老子索飯錢。", "如何支遣，但對他點頭三下，依實供款。"]'),
('d3cb4fb6-d2f6-490e-84bb-771774e98f85','偈頌九十三首  其六九','釋梵琮','宋','宋诗','song-poetry','','[]','君子道長，出生萬象。',66,'全唐诗/poet.song.184000.json','["君子道長，出生萬象。", "小人道消，近火先焦。", "晷運推移，漏泄天機。", "日南長至，吉無不利。", "添一綫長，別有商量。", "但見皇風成一片，不知何處有封疆。"]'),
('2dd53c6b-13cc-4bde-875e-396e7a93400a','偈頌九十三首  其七○','釋梵琮','宋','宋诗','song-poetry','','[]','合眼是舊歲，開眼是新年。',68,'全唐诗/poet.song.184000.json','["合眼是舊歲，開眼是新年。", "新舊交參處，分明在目前。", "梅花香噴雪，楊柳冷含煙。", "年頭佛法無多子，一句單提妙不傳。", "紅日照開銀世界，春風織出錦山川。"]'),
('10dee6a4-acd6-4026-9d51-cf6b400b4c72','偈頌九十三首  其七一','釋梵琮','宋','宋诗','song-poetry','','[]','千峰頂上披衣坐，百草頭邊是道場。',32,'全唐诗/poet.song.184000.json','["千峰頂上披衣坐，百草頭邊是道場。", "喝散白雲無一點，赤心片片報君王。"]'),
('019ba921-22eb-4b7e-b89d-f912c081a400','偈頌九十三首  其七二','釋梵琮','宋','宋诗','song-poetry','','[]','新年已十日，十日在家鄉。',112,'全唐诗/poet.song.184000.json','["新年已十日，十日在家鄉。", "到家一句子，啞子喫生薑。", "眉毛上𨁝跳，鼻孔裡論量。", "針小眼大，尺短寸長。", "雲霞飛片片，流水自茫茫。", "剪斷五色線，補作春衣裳。", "知有者全身披搭，不知有者且莫輕狂。", "莫莫莫莫，老僧與汝安心方。", "雪消春自至，事過心清涼。"]'),
('2d64b1f1-91ed-4b87-92f4-e60b01c6ba50','偈頌九十三首  其七三','釋梵琮','宋','宋诗','song-poetry','','[]','山中上元節，天上野雲收。',100,'全唐诗/poet.song.184000.json','["山中上元節，天上野雲收。", "豁開廣寒殿，清光射斗牛。", "姮娥與燈正，耿耿相應酬。", "一點難瞞處，燈毬掛樹頭。", "籠中看走馬，林下恣閑遊。", "吹滅舊紙撚，潑翻投子油。", "暗中有路明如日，露柱相逢笑不休。", "既能明似鏡，何用曲如鈎。"]'),
('d880f0b8-523f-45f6-8183-4197d9f0a5f8','偈頌九十三首  其七四','釋梵琮','宋','宋诗','song-poetry','','[]','塵起一毫，漚生全潮。',110,'全唐诗/poet.song.184000.json','["塵起一毫，漚生全潮。", "如海之深，似天之高。", "明明了了，歷歷昭昭。", "風颯颯，雨蕭蕭。", "光路宕，赤條條。", "無生國，路不遥。", "豁開功德藏，提起般若刀。", "百寶光中垂雨露，五須彌頂谿波濤。", "還源無別旨，今日與明朝。", "雲間孫子開爐熬，林下一聲婆餠焦。"]'),
('906cdb25-3bd3-44fc-a85d-8df1b9b45e89','偈頌九十三首  其七五','釋梵琮','宋','宋诗','song-poetry','','[]','即心即佛，狗咬枯骨。',37,'全唐诗/poet.song.184000.json','["即心即佛，狗咬枯骨。", "非心非佛，牛溲馬浡。", "不是心，不是佛，不是物，伏惟萬福。"]'),
('6fd6d0ee-59fa-48db-9571-810cd30d2412','偈頌九十三首  其七六','釋梵琮','宋','宋诗','song-poetry','','[]','千說萬說，只是一說，春寒秋熱。',40,'全唐诗/poet.song.184000.json','["千說萬說，只是一說，春寒秋熱。", "千句萬句，只是一句，小出大遇。", "兩段不同，收歸上科。"]'),
('96e6d0ce-9c06-4a6a-a881-ba940c7a2ee1','偈頌九十三首  其七七','釋梵琮','宋','宋诗','song-poetry','','[]','正月已過二月來，百草頭邊次第開。',32,'全唐诗/poet.song.184000.json','["正月已過二月來，百草頭邊次第開。", "昨夜東君行正令，無言桃李舞三臺。"]'),
('e54bf572-dcb0-4356-994e-525785fd002c','偈頌九十三首  其七八','釋梵琮','宋','宋诗','song-poetry','','[]','詩中有禪，東湖湖上浪滔天，一葉扁舟破曉煙。',65,'全唐诗/poet.song.184000.json','["詩中有禪，東湖湖上浪滔天，一葉扁舟破曉煙。", "禪中有詩，手把烏藤出門去，落花流水不相知。", "禪與詩何所爲斷，送二翁出門去，得閑唱箇哩囉囄。"]'),
('e5f41c12-a518-4538-b713-64ded905ad74','偈頌九十三首  其七九','釋梵琮','宋','宋诗','song-poetry','','[]','也大奇，也大奇，住箇庵兒最好嬉。',44,'全唐诗/poet.song.184000.json','["也大奇，也大奇，住箇庵兒最好嬉。", "兩箇兒童忽相打，中間一攧少人知。", "却愁騎馬滑，故作泛舟歸。"]'),
('4c9e599f-6f12-445f-9808-b05922049391','偈頌九十三首  其八○','釋梵琮','宋','宋诗','song-poetry','','[]','因參佛照師，問我本來面。',48,'全唐诗/poet.song.184000.json','["因參佛照師，問我本來面。", "日日要下語，夜夜思量徧。", "伎倆做得盡，恰好一年半。", "至今三十年，又何曾夢見。"]'),
('839b9e5a-0fce-4864-8431-48ae4ae8a142','偈頌九十三首  其八一','釋梵琮','宋','宋诗','song-poetry','','[]','三十餘年住率庵，庵中無物可相參。',32,'全唐诗/poet.song.184000.json','["三十餘年住率庵，庵中無物可相參。", "有時南北東西去，白話閑嘈恣放憨。"]'),
('3803ae6a-125b-4285-b636-6508fcd0aaf4','偈頌九十三首  其八二','釋梵琮','宋','宋诗','song-poetry','','[]','住箇庵兒最孤絕，爐中火種渾如滅。',72,'全唐诗/poet.song.184000.json','["住箇庵兒最孤絕，爐中火種渾如滅。", "謾遣兒童採燥柴，信手拈來得一橛。", "打一吹，光皎潔。", "通身暖，滿屋熱，炎炎奔馳無門歇。", "夜深狼藉燒人衣，等閑拈出安火訣。"]'),
('ec88b1ab-8116-4967-abc3-cf7d64e912e2','偈頌九十三首  其八三','釋梵琮','宋','宋诗','song-poetry','','[]','入山住庵時，全身在荒草。',48,'全唐诗/poet.song.184000.json','["入山住庵時，全身在荒草。", "狐狸交尾巴，屋頭逐魂叫。", "聞者皆寒心，見者生煩惱。", "我有安心方，韓信放鐵鷂。"]'),
('241bd2f6-ad1a-4f39-bf32-b75caf06ce60','偈頌九十三首  其八四','釋梵琮','宋','宋诗','song-poetry','','[]','我有箇火頭，作事多伶俐。',36,'全唐诗/poet.song.184000.json','["我有箇火頭，作事多伶俐。", "飽飯携鉏頭，庵前去鉏地。", "寸草不留蹤，善惡無忌諱。"]'),
('126551bf-16c1-45f7-b49b-98f646b78e58','偈頌九十三首  其八五','釋梵琮','宋','宋诗','song-poetry','','[]','蹉女自慚多醜拙，看頭上雪成堆。',31,'全唐诗/poet.song.184000.json','["蹉女自慚多醜拙，看頭上雪成堆。", "春來思得一回嫁，却請東君爲作媒。"]'),
('1ede6ba3-f6c0-4a3f-b1c2-60e1f3e5d833','偈頌九十三首  其八六','釋梵琮','宋','宋诗','song-poetry','','[]','屋角巖花爛熳，林間春色溫和。',44,'全唐诗/poet.song.184000.json','["屋角巖花爛熳，林間春色溫和。", "處處兒童採蕨，紛紛幽鳥營窠。", "祖意西來沒消息，樹頭百舌語猶多。"]'),
('e8561b69-3d78-4b04-9ccc-a18e42c851d4','偈頌九十三首  其八七','釋梵琮','宋','宋诗','song-poetry','','[]','煨火芋頭四五塊，傍林茅屋兩三間。',32,'全唐诗/poet.song.184000.json','["煨火芋頭四五塊，傍林茅屋兩三間。", "道人若欲來相訪，定是忙忙趕出山。"]'),
('8c28849c-0ec8-4871-ae12-c663077079ed','偈頌九十三首  其八八','釋梵琮','宋','宋诗','song-poetry','','[]','除夜無可分歲，爐中燒些木榾。',48,'全唐诗/poet.song.184000.json','["除夜無可分歲，爐中燒些木榾。", "臭煙衝著鼻孔，面熱忽然噴嚏。", "殘年鈍悶，到此消除。", "新歲佛法，從此吉利。"]'),
('1f66a7ae-b016-4eed-88de-babfd64c31ff','偈頌九十三首  其八九','釋梵琮','宋','宋诗','song-poetry','','[]','今朝正月一，萬事從頭吉。',36,'全唐诗/poet.song.184000.json','["今朝正月一，萬事從頭吉。", "和氣暖如春，世味甜如蜜。", "日月往復來，光陰不相失。"]'),
('4b86bb6d-6048-4a24-a31e-85b0b0d1a0ab','偈頌九十三首  其九○','釋梵琮','宋','宋诗','song-poetry','','[]','今朝正月半，萬物盡更新。',40,'全唐诗/poet.song.184000.json','["今朝正月半，萬物盡更新。", "衲僧無一物，何物當慇懃。", "銀燭高煇天上月，燈花開遍洞中春。"]'),
('9b6fa622-ed3e-4108-a7bb-22dc185d1e32','偈頌九十三首  其九一','釋梵琮','宋','宋诗','song-poetry','','[]','衲僧家，達己靈。',69,'全唐诗/poet.song.184000.json','["衲僧家，達己靈。", "有通變，解逢迎。", "世人既已濁，不可自言清。", "世人既已醉，不可自言醒。", "和光同塵去，頭頭總見成。", "豈不見昔年党太尉，無分無曉最分明。"]'),
('4dee198b-23a1-4966-8ff6-8f0eaf08a5e0','偈頌九十三首  其九二','釋梵琮','宋','宋诗','song-poetry','','[]','把定風光末上開，紛紛如雪點蒼苔。',32,'全唐诗/poet.song.184000.json','["把定風光末上開，紛紛如雪點蒼苔。", "清香飄處多真實，真實中藏調鼎才。"]'),
('1cedebf7-c420-46b8-badc-86d73d178646','頌古三十一首  其一','釋梵琮','宋','宋诗','song-poetry','','[]','謾將淡墨畫垂楊，嫋嫋腰枝百尺長。',32,'全唐诗/poet.song.184000.json','["謾將淡墨畫垂楊，嫋嫋腰枝百尺長。", "寄語行人不須看，一回看著斷人腸。"]'),
