('cdf0d12b-1f29-4583-b7e7-503f73c2bd28','達磨贊','釋梵琮','宋','宋诗','song-poetry','','[]','因販私鹽，無端過界。',44,'全唐诗/poet.song.184000.json','["因販私鹽，無端過界。", "撞著梁王，不勘自敗。", "狼藉官場，遭人笑怪。", "匾檐脫却兩頭，至今全無買賣。"]'),
('8e49e02e-ff9e-4890-a155-883c260b6477','龐居士贊','釋梵琮','宋','宋诗','song-poetry','','[]','得便宜是落便宜，傾盡家珍賣笊籬。',32,'全唐诗/poet.song.184000.json','["得便宜是落便宜，傾盡家珍賣笊籬。", "男女聚頭無結果，這般翁子大無知。"]'),
('15e87b0b-ae66-4c93-8d61-a122f1c17dd6','祖圖贊','釋梵琮','宋','宋诗','song-poetry','','[]','點汙人間閑紙墨，祇因五葉一花開。',32,'全唐诗/poet.song.184000.json','["點汙人間閑紙墨，祇因五葉一花開。", "看他次第傳芳去，總是邯鄲學步來。"]'),
('b50605a5-2f48-4c62-a072-5ee9f5cdc1a9','寒山拾得贊','釋梵琮','宋','宋诗','song-poetry','','[]','寒拾相逢便拍肩，雙收雙放笑掀天。',32,'全唐诗/poet.song.184000.json','["寒拾相逢便拍肩，雙收雙放笑掀天。", "古今一片閑田地，露出尋常茗菷邊。"]'),
('51ee7b03-e35f-44df-b8d6-e2700ed0eb6b','三教圖贊','釋梵琮','宋','宋诗','song-poetry','','[]','六耳不同謀，相看已漏泄。',56,'全唐诗/poet.song.184000.json','["六耳不同謀，相看已漏泄。", "都來只三人，證龜却成鼈。", "者也之乎，無爲寂滅。", "養家一般，道路各別。", "別不別，掉棒打落天邊月。"]'),
('8aff6a3d-a1d2-4624-b3f2-5dca102a9032','觀流水觀音贊','釋梵琮','宋','宋诗','song-poetry','','[]','一片寒泉劈面來，斷崖嶮處滑如苔。',32,'全唐诗/poet.song.184000.json','["一片寒泉劈面來，斷崖嶮處滑如苔。", "舉頭只麽隨流水，大士何曾眼豁開。"]'),
('bbeb92c6-bc7b-4740-a132-32d89f804662','巖頭禪師甘贄居士贊','釋梵琮','宋','宋诗','song-poetry','','[]','安居俗舍太無稽，黑白分明類不齊。',32,'全唐诗/poet.song.184000.json','["安居俗舍太無稽，黑白分明類不齊。", "謾向人前露針線，賺他女子與夫妻。"]'),
('654671fa-df27-4b5d-929a-34e62016e66d','布袋贊','釋梵琮','宋','宋诗','song-poetry','','[]','眼冷千江月，眉橫萬疊山。',24,'全唐诗/poet.song.184000.json','["眼冷千江月，眉橫萬疊山。", "杖頭挑布袋，信脚到人間。"]'),
('d5081430-69b4-4c50-9d5e-dc2cb8f5e6a1','蝦子贊','釋梵琮','宋','宋诗','song-poetry','','[]','斗裏跳出，手中捏定。',20,'全唐诗/poet.song.184000.json','["斗裏跳出，手中捏定。", "不入水泥，喪却性命。"]'),
('aa3d5fb9-754b-43a1-ba63-aa07e408e40e','率庵歌','釋梵琮','宋','宋诗','song-poetry','','[]','三間茅屋堪投老，草草生涯隨分好。',96,'全唐诗/poet.song.184000.json','["三間茅屋堪投老，草草生涯隨分好。", "月池當戶鏡光寒，竹逕遶簷通大道。", "風吹葉葉自成堆，信手拈來一莖草。", "賤如泥，貴似寶，要用便用不須討。", "遼天鼻孔被渠穿，來往行人俱絆倒。", "阿呵呵，會也麽，問取前村張四哥。"]'),
('681161a5-ecc7-404e-9610-3b5223d62e1c','闡提歌','釋梵琮','宋','宋诗','song-poetry','','[]','無住著，老禪魔。',164,'全唐诗/poet.song.184000.json','["無住著，老禪魔。", "歡喜少，惡性多。", "三毒花中結苦果，蒺蔾園裡養蜂窠。", "說調普賢賣白象，呼喚兒童填黄河。", "戲弄南山老虎，踏翻北海滄波。", "洗盡佛祖冤，法戰罷干戈。", "五千文字拭抹布，一會靈山糞掃籮。", "謾將無義語，唱起闡提歌。", "調古不堪聽，聲極透巖阿。", "能妙轉，絕捫摩。", "六用機中抽線，電光影裏攛梭。", "織成無縫襖，綉出沒底靴。", "三臺舞罷呵呵笑，笑倒多年黑老婆。"]'),
('174dbde6-0a55-4d12-8d62-2249067af9b0','草鞋歌','釋梵琮','宋','宋诗','song-poetry','','[]','村裏人，有意知，就手織成最容易。',115,'全唐诗/poet.song.184000.json','["村裏人，有意知，就手織成最容易。", "長短大小在目前，密用工夫多快利。", "草窠裡面跳出來，結却繩頭有巴鼻。", "牢束跟，緊在耳。", "擲地作金聲，舉步離泥水。", "著入千山與萬山，把定脚頭并脚尾。", "趙州盡力戴不起，玄沙喫絆趯著指。", "拖來拖去底頭穿，輕輕颺在糞裏。"]'),
('29fdd5b6-e697-4f65-981d-8d04b7b3f256','拄杖歌','釋梵琮','宋','宋诗','song-poetry','','[]','拄杖子，最超絕。',116,'全唐诗/poet.song.184000.json','["拄杖子，最超絕。", "到頭到尾黑鱗皴，凜凜風生堅似鐵。", "同我行，共我歇。", "恣縱橫，任拖拽。", "攪動碧潭龍，打落天邊月。", "有時拄到千峰頂，千峰萬峰俱迸裂。", "有時攛入荒草中，潜藏影跡難分別。", "芭蕉有屈無人雪，大隨提起重漏泄。", "而今老大懶扶持，信手拗來成兩橛。"]'),
('5ea1920d-460b-4e81-b246-b6fadb5d168d','明宗','釋梵琮','宋','宋诗','song-poetry','','[]','古徑苔生路已差，無根樹上發空花。',32,'全唐诗/poet.song.184000.json','["古徑苔生路已差，無根樹上發空花。", "一番花落成空果，信手拈來是苦瓜。"]'),
('39a79a5b-2182-46b9-8a5d-306f0791fd2e','羅漢菜','釋梵琮','宋','宋诗','song-poetry','','[]','根塵脫落超諸有，豈與尋常種草同。',32,'全唐诗/poet.song.184000.json','["根塵脫落超諸有，豈與尋常種草同。", "塞斷衲僧三寸舌，橫身鉢裏展神通。"]'),
('76878854-5286-4dc0-b597-9fc0610a46f3','迎善財歸南樓','釋梵琮','宋','宋诗','song-poetry','','[]','古寺閑房共掩扉，相逢彼此罷參歸。',32,'全唐诗/poet.song.184000.json','["古寺閑房共掩扉，相逢彼此罷參歸。", "時難只得同香火，莫信閑人說是非。"]'),
('c67204f9-6c38-4c4d-9211-06501625709f','常禪師荷衣沼','釋梵琮','宋','宋诗','song-poetry','','[]','遇物合人仰祖風，弊衣遺在一池中。',32,'全唐诗/poet.song.184000.json','["遇物合人仰祖風，弊衣遺在一池中。", "秋風吹破春風補，不犯清波一線功。"]'),
('b9795110-6882-489a-a2fb-192a93f94e68','禮佛照禪師塔','釋梵琮','宋','宋诗','song-poetry','','[]','憶得尋流日，重來走一遭。',24,'全唐诗/poet.song.184000.json','["憶得尋流日，重來走一遭。", "跨門相見處，全不犯波濤。"]'),
('3d649dc4-073b-4b15-82e9-00a7003d3185','訪育王東堂空叟和尚夜話  其一','釋梵琮','宋','宋诗','song-poetry','','[]','病餘相對兩枯樁，霜髮毿毿映暖窗。',32,'全唐诗/poet.song.184000.json','["病餘相對兩枯樁，霜髮毿毿映暖窗。", "縱有丹青描不得，到頭六六不成雙。"]'),
('e0b9caca-f11e-4174-8a8b-480dc3aaf2db','訪育王東堂空叟和尚夜話  其二','釋梵琮','宋','宋诗','song-poetry','','[]','因說多年破草鞋，祖翁插脚强安排。',32,'全唐诗/poet.song.184000.json','["因說多年破草鞋，祖翁插脚强安排。", "從茲狼藉渾無底，次第提持轉見乖。"]'),
('671c199f-1af6-4c1c-a5b3-c4aca7acfdfc','禮密庵禪師塔','釋梵琮','宋','宋诗','song-poetry','','[]','綿裏裹刀難近傍，飯中有藥出閩鄉。',32,'全唐诗/poet.song.184000.json','["綿裏裹刀難近傍，飯中有藥出閩鄉。", "至今怕飲山中水，我昔曾遭蠱毒傷。"]'),
('63e3821f-fb3b-4a3a-8299-60dafa142978','送米上佛照禪師','釋梵琮','宋','宋诗','song-poetry','','[]','捻不成團撥不開，一槌直下絕纖埃。',32,'全唐诗/poet.song.184000.json','["捻不成團撥不開，一槌直下絕纖埃。", "從茲幾度經節後，盡向箕前跳出來。"]'),
('1868e314-300e-4ea8-884b-80f07541a5af','訪香山松源和尚','釋梵琮','宋','宋诗','song-poetry','','[]','率菴自笑風流甚，醉後何須苦戀盃。',32,'全唐诗/poet.song.184000.json','["率菴自笑風流甚，醉後何須苦戀盃。", "十字路頭荒草店，引他來往兩三回。"]'),
('303c051f-93af-4e91-a55b-47511ed7b570','謝無用和尚惠鞋','釋梵琮','宋','宋诗','song-poetry','','[]','信手裁成任短長，密通一線透中央。',32,'全唐诗/poet.song.184000.json','["信手裁成任短長，密通一線透中央。", "看來只是舊時底，著了何妨到處行。"]'),
('b0f57fcc-343b-4c61-81c0-b505851843a0','送浙翁禪師住徑山','釋梵琮','宋','宋诗','song-poetry','','[]','古路滑如苔，衲僧忘故步。',48,'全唐诗/poet.song.184000.json','["古路滑如苔，衲僧忘故步。", "人從天台來，却住徑山去。", "家醜向外揚，生鐵被蟲蠹。", "一陳落華風，吹作送行句。"]'),
('2b0d8f91-6c07-43fd-affb-a618ed6e7913','寄滅翁禪師','釋梵琮','宋','宋诗','song-poetry','','[]','老去隠如虎，難瞞在一班。',48,'全唐诗/poet.song.184000.json','["老去隠如虎，難瞞在一班。", "入林最容易，上樹極艱難。", "舌底千谿水，眉間萬疊山。", "年深拽不動，草種轉癡頑。"]'),
('0714a4e4-0416-4b62-a63c-af08604b3a0a','寄台州瑞巖高原禪師住靈隠','釋梵琮','宋','宋诗','song-poetry','','[]','水出在高原，源深到冷泉。',80,'全唐诗/poet.song.184000.json','["水出在高原，源深到冷泉。", "飲者禿却舌，嗅者鼻孔穿。", "口鼻兩俱喪，妙用絕正偏。", "側耳與招手，聽猿同呼猿。", "藤蘿影裡石磊磊，雙澗合流波漣漣。", "南來北來脚下過，欲知冷暖待馿年。"]'),
('d3cace83-a070-478f-8a75-f40ae5042e7a','庵中夏','釋梵琮','宋','宋诗','song-poetry','','[]','草中得路便藏身，不入他家水牯群。',32,'全唐诗/poet.song.184000.json','["草中得路便藏身，不入他家水牯群。", "彈指一聲爲號令，低頭問訊當慇懃。"]'),
('d4375ddd-f56b-472b-9248-bed2c1755c05','耐重','釋梵琮','宋','宋诗','song-poetry','','[]','坐斷孤危未肯休，荷擔傑閣與層樓。',32,'全唐诗/poet.song.184000.json','["坐斷孤危未肯休，荷擔傑閣與層樓。", "柦翁活計丘山重，得力全歸頂𩕳頭。"]'),
('8eb7591b-65f6-47cb-b7c6-85741b876129','山居  其一','釋梵琮','宋','宋诗','song-poetry','','[]','老來歸隠故山深，獨抱無絃絕賞音。',32,'全唐诗/poet.song.184000.json','["老來歸隠故山深，獨抱無絃絕賞音。", "靜對凉風彈一曲，亂蟬聲合奏青林。"]'),
('8ce1bb80-147b-4fb9-96d1-679cff526c54','山居  其二','釋梵琮','宋','宋诗','song-poetry','','[]','居山活計隨時用，觸事都從舊路行。',32,'全唐诗/poet.song.184000.json','["居山活計隨時用，觸事都從舊路行。", "只把手頭些子力，撥開火種自燒鐺。"]'),
('dcbf8bf5-a5a7-45ca-836e-5e636b1a9904','朝陽穿破衲','釋梵琮','宋','宋诗','song-poetry','','[]','笑看體上衣，斷雲欲飛走。',24,'全唐诗/poet.song.184000.json','["笑看體上衣，斷雲欲飛走。", "朝陽忽相逢，針眼已通透。"]'),
('ec0d3255-f266-4f62-8266-ad036560e47a','對月了殘經','釋梵琮','宋','宋诗','song-poetry','','[]','待月了殘經，文義何曾有。',24,'全唐诗/poet.song.184000.json','["待月了殘經，文義何曾有。", "分付與癡兒，黄葉卷在手。"]'),
('62df310b-ef30-44a8-bc3a-a98b0447a0b2','頌古四首  其一','釋梵琮','宋','宋诗','song-poetry','','[]','德山托鉢話，低頭得人怕。',24,'全唐诗/poet.song.184000.json','["德山托鉢話，低頭得人怕。", "三家村裡人，醉後胡廝駡。"]'),
('ee709345-361a-4454-b43d-f81ebfbf89ca','頌古四首  其二','釋梵琮','宋','宋诗','song-poetry','','[]','傍菴來往路相通，步步相隨躡去蹤。',32,'全唐诗/poet.song.184000.json','["傍菴來往路相通，步步相隨躡去蹤。", "山遠年深人不到，一溪流水質長松。"]'),
('bcfcd7e0-d9fa-446c-b1ea-f55431b72d44','頌古四首  其三','釋梵琮','宋','宋诗','song-poetry','','[]','東山水上行，乾元利貞亨。',24,'全唐诗/poet.song.184000.json','["東山水上行，乾元利貞亨。", "譊訛一箇字，才子競頭爭。"]'),
('f50e2d00-8f78-437b-b565-cc9f11f4d28e','頌古四首  其四','釋梵琮','宋','宋诗','song-poetry','','[]','鐘聲披起鬰多羅，信手拈來不在多。',32,'全唐诗/poet.song.184000.json','["鐘聲披起鬰多羅，信手拈來不在多。", "堪笑當年明上座，狼忙馳逐太奔波。"]'),
('3648d59c-7468-4702-a97a-e33edf962ae4','哀山民','趙師秀','宋','宋诗','song-poetry','','[]','憶君初病時，倉皇造君榻。',288,'全唐诗/poet.song.184000.json','["憶君初病時，倉皇造君榻。", "知爲寒所中，脛痹連左胛。", "蔣子丹有神，三日能屈伸。", "五日扶杖立，十日行逡巡。", "於時數相見，談娛靡曾倦。", "啜茶猶滿甌，改詩忽盈卷。", "君亦疑勿藥，春和可爲樂。", "仙家桃最紅，同踐天台約。", "多愁積如山，令君心不閑。", "殘疴故未去，澀嗇腸腑間。", "岳僧有烈劑，倒篋得餘惠。", "服之汗翻漿，事與東流逝。", "啼妻無完裙，弱子猶哀麕。", "詩人例窮苦，窮死更憐君。", "君如三秋草，不見一日好。", "根荄霜霰侵，萎絕嗟何早。", "哭君日無光，思君月照牀。", "猶疑君不死，猛省欲顛狂。", "昨者君未疾，相過不論日。", "晴窗春翦蒲，寒爐夜煨栗。", "石階苔蘚中，猶有舊行蹤。", "憂心不能寐，無夢得相逢。", "君詩如賈島，勁筆斡天巧。", "昔爲人所稱，今爲人所寶。"]'),
('1c7d0d14-f86f-4177-ac6a-983340dcd8ab','後哀','趙師秀','宋','宋诗','song-poetry','','[]','交交谷鳥哀，鬰鬰澗松折。',108,'全唐诗/poet.song.184000.json','["交交谷鳥哀，鬰鬰澗松折。", "山民無還期，春物失怡悅。", "平生感斯人，難以常理說。", "共智己則愚，忽巧衆亦拙。", "芳名信可垂，在世何寂滅。", "含悽爲卜兆，窀穸利茲月。", "行當宿草生，當使我淚歇。", "未知百年後，誰復耕此穴。", "寄言苦吟者，勿棄攝生訣。"]'),
('cef0f07d-7c4d-4b94-8308-f12d13582545','和陳水雲湖莊韵','趙師秀','宋','宋诗','song-poetry','','[]','粼粼水增波，疊疊雲弄影。',96,'全唐诗/poet.song.184000.json','["粼粼水增波，疊疊雲弄影。", "昔誇春徑妍，今愛秋塘靜。", "芳筵集賓彥，清宴除豔靚。", "時當新雨餘，蒼翠獻林嶺。", "既忻沖抱舒，復快遠目騁。", "仰嘉鍾鼎人，而迺眷箕潁。", "深營察高趣，雅詠發沉景。", "獨使和者難，一夕愁欲癭。"]'),
('391213f6-c9cf-4ba0-9832-6d192eb492b1','敬謝章泉趙昌甫二十韵','趙師秀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','耆舊半凋落，在者如晨星。',240,'全唐诗/poet.song.184000.json','["耆舊半凋落，在者如晨星。", "與翁別豫章，十見草木青。", "人生幾堪別，夢寐生羽翎。", "迢迢玉溪波，近昨嘗再經。", "携家事多難，所至那得停。", "山中空望來，日夕不掩扃。", "豈獨負茲約，尺書亦沈冥。", "逢人問消息，但喜言康寧。", "墮來兩卷什，一以慰飄零。", "感此故意弘，不我迹以形。", "文章出晚歲，字畫猶壯齡。", "誦之西湖濱，驚動孤山靈。", "翁卷遊崆峒，一已煩郵鈴。", "幸翁良未衰，吾黨存典刑。", "遥聞曾入郛，諒爲韓與丁。", "郡齋待且久，幾宿澗上亭。", "今春少晴時，澗水應泠泠。", "歸來安穩否，薰風入林坰。", "願言愛玉骨，逍遥卧殊庭。", "會面雖未期，忽聚江湖萍。"]'),
('4d0f8360-b91b-47ca-905a-50cec18f69e3','官田之集翁聘君失期陳伯壽賦詩率爾次韵','趙師秀','宋','宋诗','song-poetry','','[]','好水不厭闊，好風不厭涼。',180,'全唐诗/poet.song.184000.json','["好水不厭闊，好風不厭涼。", "況有十頃荷，荷風媚波光。", "主人昔謂余，此境不可忘。", "舉觴集羣英，期以朝未央。", "清歡遣絲竹，善謔停優倡。", "快若魚脫網，適比鴛在梁。", "搴芳衣履濕，飲淥肌骨香。", "操觚賦相聯，妙續楚九章。", "苦吟墮饑蟬，巧詠發輕簧。", "常勝或倒戈，突出或擅場。", "或峙而遽蹴，或抑而載揚。", "所欠獨巨翁，不使人意强。", "孱衲爾何爲，竭颯立在傍。", "有間衆稍默，談辯忽汪洋。", "夕風亦損荷，萬事付叵量。"]'),
('2632d75b-4a7c-4d61-9036-0e5de4890605','九客一羽衣泛舟分韵得尊字就送朱幾仲','趙師秀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','人生苦形役，不定如車轅。',156,'全唐诗/poet.song.184000.json','["人生苦形役，不定如車轅。", "況各異鄉井，忽此同酒尊。", "此尊豈易同，意乃有數存。", "西湖雪未成，兩山翠相奔。", "山根日照樹，花放林逋村。", "野饌具蘼藿，一飽厭百飧。", "有客何多髯，吐氣鄰芳蓀。", "慷慨念時事，所惜智者昏。", "砭療匪無術，諱疾何由論。", "北望徒太息，歸歟尋故園。", "哆然黄冠師，笑請子勿喧。", "東南守太乙，此宿福所屯。", "吾子且飲酒，酒冷爲子溫。"]'),
('19a64588-7be6-49d6-9386-dfa00f5614a5','哭徐璣五首  其一','趙師秀','宋','宋诗','song-poetry','','[]','君早抱奇質，獲與有道親。',48,'全唐诗/poet.song.184000.json','["君早抱奇質，獲與有道親。", "微官漫不遇，泊然安賤貧。", "心夷語自秀，一洗世士陳。", "使其養以年，鮑謝焉足鄰。"]'),
('b1cd23b4-b08d-44d4-a877-1c5dcff0aba1','哭徐璣五首  其二','趙師秀','宋','宋诗','song-poetry','','[]','昔吾與君遊，嫌疎不嫌數。',48,'全唐诗/poet.song.184000.json','["昔吾與君遊，嫌疎不嫌數。", "自爲貧窶驅，十載九離索。", "前年會京都，朂我返林薄。", "吾貧未得歸，君死不可作。"]'),
('9fc0c150-fc9e-4291-9f1c-92059ef2aec9','哭徐璣五首  其三','趙師秀','宋','宋诗','song-poetry','','[]','思君氣實充，不與短折類。',48,'全唐诗/poet.song.184000.json','["思君氣實充，不與短折類。", "血死匪無由，恐是服椒罪。", "君於藥自深，何獨此乎昧。", "豈不聞仙人，餌菖得千歲。"]'),
('a4b90ac0-d6dc-4a14-8fb0-21830fff0c9d','哭徐璣五首  其四','趙師秀','宋','宋诗','song-poetry','','[]','平生於所學，常若喪其敏。',48,'全唐诗/poet.song.184000.json','["平生於所學，常若喪其敏。", "臨池書未成，池水黑已盡。", "傳來葉嶺帖，遂與蘭亭近。", "凡茲究極功，亦足損肝腎。"]'),
('d0873e59-946b-4d2b-8bd5-0acb1ae58cc9','哭徐璣五首  其五','趙師秀','宋','宋诗','song-poetry','','[]','道暉愛江蘺，吾子思單老。',48,'全唐诗/poet.song.184000.json','["道暉愛江蘺，吾子思單老。", "生念死不滅，應會沅湘道。", "空山獨靈舒，閉戶守枯槁。", "風雪將歲闌，凋零此懷抱。"]'),
('9ac77a18-684e-4062-890d-ee31d763f0a6','桐柏觀','趙師秀','宋','宋诗','song-poetry','','[]','山深地忽平，縹緲見殊庭。',48,'全唐诗/poet.song.184000.json','["山深地忽平，縹緲見殊庭。", "瀑近春風濕，松多曉日青。", "石壇遺鸛羽，粉壁剝龍形。", "道士玉靈寶，輕强滿百齡。"]'),
('392e8464-c0c1-4b66-bfaf-2f7a49f3155d','楊柳塘寄徐照','趙師秀','宋','宋诗','song-poetry','','[]','因貧爲遠別，已是十三程。',48,'全唐诗/poet.song.184000.json','["因貧爲遠別，已是十三程。", "盡日行山色，逢人問地名。", "近書無便寄，新句與誰評。", "想爾寒宵雨，思予亦夢成。"]'),
('05de74cc-4ea8-4828-b0aa-082898d63865','贈孔道士','趙師秀','宋','宋诗','song-poetry','','[]','生來還姓孔，何不戴儒冠。',48,'全唐诗/poet.song.184000.json','["生來還姓孔，何不戴儒冠。", "詩好逢人誦，琴清只自彈。", "訪師行郡遠，愛竹透菴寒。", "見說丹爐內，黄金化不難。"]'),
('1b049fcb-6914-4e58-abda-91c92a93e64d','舟行寄翁十','趙師秀','宋','宋诗','song-poetry','','[]','舟輕風色好，波面去迢迢。',48,'全唐诗/poet.song.184000.json','["舟輕風色好，波面去迢迢。", "取爾詩重讀，令吾病欲銷。", "江禽停晚樹，澗水入秋潮。", "已覺懷人極，分携始一朝。"]'),
('c785b270-e016-4dc7-8372-bce5b88b5682','縉雲縣宿','趙師秀','宋','宋诗','song-poetry','','[]','親知因別久，具酒勞經過。',48,'全唐诗/poet.song.184000.json','["親知因別久，具酒勞經過。", "古邑居人少，春寒入夜多。", "雨香仙地藥，燭動石橋波。", "稍覺離家遠，鄉音一半訛。"]'),
('e6e8b5b1-a0f1-4f87-8f6c-dd7ab51b2af8','進賢道中','趙師秀','宋','宋诗','song-poetry','','[]','半月逢梅雨，初晴客意消。',48,'全唐诗/poet.song.184000.json','["半月逢梅雨，初晴客意消。", "鶑聲臨野水，松影卧新苗。", "少憩休輿卒，閑行過板橋。", "平生無飲分，空愧酒旗招。"]'),
('3865d6c3-9a6e-445b-b3f9-51fc658aa793','冷泉夜坐','趙師秀','宋','宋诗','song-poetry','','[]','衆境碧沈沈，前峰月正臨。',48,'全唐诗/poet.song.184000.json','["衆境碧沈沈，前峰月正臨。", "樓鐘晴聽響，池水夜觀深。", "清浄非人世，虛空是佛心。", "却尋來處宿，風起古松林。"]'),
('f2f5f624-b7bc-427c-b3f6-75a2cee4d5ed','筠州郡庠山亭','趙師秀','宋','宋诗','song-poetry','','[]','一來高處望，遠近盡秋容。',48,'全唐诗/poet.song.184000.json','["一來高處望，遠近盡秋容。", "秀氣歸才子，清風屬釣翁。", "溪晴分別港，山闕見他峰。", "獨憶凉宵月，無因宿此中。"]'),
('992d4dfe-ab3a-4beb-b0d9-a2888afcc93a','延禧觀','趙師秀','宋','宋诗','song-poetry','','[]','寂寞古仙宮，松林常有風。',48,'全唐诗/poet.song.184000.json','["寂寞古仙宮，松林常有風。", "鶴毛兼葉下，井氣與雲同。", "背日苔磚紫，多年粉壁紅。", "相傳陶縣令，曾住此山中。"]'),
('300dbca3-cc92-4cda-a442-0e7fbb191747','撫欄','趙師秀','宋','宋诗','song-poetry','','[]','撫欄驚歲月，久住欲如何。',48,'全唐诗/poet.song.184000.json','["撫欄驚歲月，久住欲如何。", "水國花開早，春城人上多。", "病令詩懶作，閑喜客頻過。", "聽說邊頭事，時賢策在和。"]'),
('ca963cfe-383e-414e-8d79-c4b7bb85ffbe','寄趙昌父','趙師秀','宋','宋诗','song-poetry','','[]','逃名逃未得，幾載住章泉。',48,'全唐诗/poet.song.184000.json','["逃名逃未得，幾載住章泉。", "便使重承詔，多應不議邊。", "高風時所繫，新集世方傳。", "憶就江樓別，雪晴江月圓。"]'),
('e0dc4b1b-7b96-47e4-8413-937d7cd4588a','贈張亦','趙師秀','宋','宋诗','song-poetry','','[]','相逢楚澤中，語罷各西東。',48,'全唐诗/poet.song.184000.json','["相逢楚澤中，語罷各西東。", "天下方無事，男兒未有功。", "邊風吹面黑，市酒到腸空。", "早作歸耕計，吾舟俟爾同。"]'),
('65de1a9d-eaa5-4824-8854-0161d7f09dcc','贈達西堂','趙師秀','宋','宋诗','song-poetry','','[]','秋水數枝蓮，在師房一邊。',48,'全唐诗/poet.song.184000.json','["秋水數枝蓮，在師房一邊。", "固應通浄理，不復念生緣。", "舊願酬初滿，靈方許盡傳。", "閑詢曾住寺，如夢已茫然。"]'),
('89520cd6-6d88-4d2f-9923-8c21d1b1d068','送湯千','趙師秀','宋','宋诗','song-poetry','','[]','能文兼悟性，前是惠休身。',48,'全唐诗/poet.song.184000.json','["能文兼悟性，前是惠休身。", "爲選來京邑，因吟訪野人。", "所居纔隔水，不見忽經旬。", "何事云歸速，儒官拜敕新。"]'),
('0788a898-b6af-4fe9-8b75-a38449505042','石門僧','趙師秀','宋','宋诗','song-poetry','','[]','石門幽絕甚，獨有一禪僧。',48,'全唐诗/poet.song.184000.json','["石門幽絕甚，獨有一禪僧。", "寺廢餘鐘在，房高過客登。", "山蜂成苦蜜，崖溜結空冰。", "如此冬寒月，他人住豈能。"]'),
('446f156f-fda3-4d48-88c1-ee6827a9f3b8','秋色','趙師秀','宋','宋诗','song-poetry','','[]','幽人愛秋色，祇爲屬吟情。',48,'全唐诗/poet.song.184000.json','["幽人愛秋色，祇爲屬吟情。", "一片葉初落，數聯詩已清。", "瘦便藤杖細，涼覺葛衣輕。", "門外蕭蕭徑，今年菊自生。"]'),
('f7a824cf-a644-4780-bf0b-55c8a5b1d089','簡同行翁靈舒','趙師秀','宋','宋诗','song-poetry','','[]','久晴灘磧衆，舟楫後先行。',48,'全唐诗/poet.song.184000.json','["久晴灘磧衆，舟楫後先行。", "終日不相見，與君如各程。", "水禽多雪色，野笛忽秋聲。", "必有新成句，溪流合讓清。"]'),
('0e02d5aa-2e82-4965-8e35-2ba104c75cc6','信州草衣寺','趙師秀','宋','宋诗','song-poetry','','[]','芙蕖四五枝，寂寞在空池。',48,'全唐诗/poet.song.184000.json','["芙蕖四五枝，寂寞在空池。", "難見草衣士，空看宴坐碑。", "香煙思盛日，詩句記游時。", "欲問臺中鶴，長松自不知。"]'),
('a395074f-5375-47af-87fc-0dd8461f8ec9','靈山閣見二徐友舊題句','趙師秀','宋','宋诗','song-poetry','','[]','一面見溪水，三邊皆翠微。',48,'全唐诗/poet.song.184000.json','["一面見溪水，三邊皆翠微。", "晚來虛檻外，秋近白雲飛。", "重至恰身老，同吟感客非。", "靈山自如畫，依舊隔斜暉。"]'),
('69c6e0e8-ea83-408e-aad3-763bd04d0fbd','秋屏作','趙師秀','宋','宋诗','song-poetry','','[]','凡有欄干處，秋來遍往還。',48,'全唐诗/poet.song.184000.json','["凡有欄干處，秋來遍往還。", "就中惟此地，全得見西山。", "鴈落遥沙小，人登廢壘閑。", "因憐一州景，皆在夕陽間。"]'),
('15c3ffc1-a514-4739-8992-17d35df86ed5','送沈莊可','趙師秀','宋','宋诗','song-poetry','','[]','清事貧人占，斯言恐是虛。',48,'全唐诗/poet.song.184000.json','["清事貧人占，斯言恐是虛。", "與花方作譜，爲米又持書。", "時節寒相近，山林拙未除。", "西江波浪急，送子一愁予。"]'),
('21f98c4f-bdfc-4bcd-ba4a-8f545e8af3cf','送周端常之建康','趙師秀','宋','宋诗','song-poetry','','[]','高名聞已久，方策有文雕。',48,'全唐诗/poet.song.184000.json','["高名聞已久，方策有文雕。", "接得詩人信，知從諫議招。", "住遥勞枉刺，去速恨移橈。", "何處逢黄菊，秋風故六朝。"]'),
('38709e35-d853-4bc0-87d9-61615752990a','贈易道士','趙師秀','宋','宋诗','song-poetry','','[]','仙帔畫霞雪，多年侍玉宸。',48,'全唐诗/poet.song.184000.json','["仙帔畫霞雪，多年侍玉宸。", "古於莊子貌，貴似呂公身。", "詩好當開板，丹靈不化銀。", "舊山新築觀，惟夢得歸頻。"]'),
('a207567f-7d31-4fb6-a3c7-7b35701f9f77','送輝上人再住空相','趙師秀','宋','宋诗','song-poetry','','[]','忽然聞受請，鐵錫指秋風。',48,'全唐诗/poet.song.184000.json','["忽然聞受請，鐵錫指秋風。", "寺在寒城裏，州居野水中。", "生緣拋未盡，舊講續應終。", "不用相尋別，浮雲去住同。"]'),
('0151108f-1453-4a70-b686-8378c10d4826','寄薛景石','趙師秀','宋','宋诗','song-poetry','','[]','虛窗風颯然，獨卧聽殘蟬。',48,'全唐诗/poet.song.184000.json','["虛窗風颯然，獨卧聽殘蟬。", "家務貧多闕，詩篇老漸圓。", "清秋添一月，故里別三年。", "最憶君門首，黄花匝野泉。"]'),
('3d6c9626-8ea4-4ae8-8191-bc502cf39b74','送徐璣赴永州掾','趙師秀','宋','宋诗','song-poetry','','[]','二水鴻飛外，君今問去程。',48,'全唐诗/poet.song.184000.json','["二水鴻飛外，君今問去程。", "家貧難擇宦，身遠易成名。", "入署梅花落，過汀蕙草生。", "莫因饒楚思，詞體失和平。"]'),
('6c942b76-e415-484b-97e2-5e4e603dc34e','巖居僧','趙師秀','宋','宋诗','song-poetry','','[]','開扉在石層，盡日少人登。',48,'全唐诗/poet.song.184000.json','["開扉在石層，盡日少人登。", "一鳥過寒木，數花摇翠藤。", "茗煎冰下水，香炷佛前燈。", "吾亦逃名者，何因似此僧。"]'),
('23b6ba83-2c05-4181-91ad-41bf60df53c0','安仁道中','趙師秀','宋','宋诗','song-poetry','','[]','行盡沿溪路，天寒歲又除。',48,'全唐诗/poet.song.184000.json','["行盡沿溪路，天寒歲又除。", "欲消冰似雪，初長麥如蔬。", "於世無成事，何時有定居。", "等緣貧所役，爲仕媿爲漁。"]'),
('0e064ce5-5c3e-4ae6-8156-0fd8e9d3148c','壕上','趙師秀','宋','宋诗','song-poetry','','[]','遠近人家住，過橋路盡通。',48,'全唐诗/poet.song.184000.json','["遠近人家住，過橋路盡通。", "野田行瘦馬，淺渚聚羣鴻。", "地靜微泉響，天寒落日紅。", "若非身作吏，不道是城中。"]'),
('db9a4318-a5e0-4f26-b3fe-90d6e0256531','月夜懷徐照','趙師秀','宋','宋诗','song-poetry','','[]','月色一庭深，迢遥千里心。',48,'全唐诗/poet.song.184000.json','["月色一庭深，迢遥千里心。", "湘江連底見，秋客與誰吟。", "寒入吹城角，光凝宿竹禽。", "亦知同不寢，難得夢相尋。"]'),
('7ae15b6c-95e9-47d5-bc75-35a4068d4162','送倪道士之廬山','趙師秀','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','近方辭地肺，本自住天台。',48,'全唐诗/poet.song.184000.json','["近方辭地肺，本自住天台。", "有鶴相同出，無雲作伴回。", "道房隨處借，詩板逐時開。", "又說廬山去，閑看瀑布來。"]'),
('a4812da2-fe0a-4726-9758-5f8b864b146a','送鄧漢卿','趙師秀','宋','宋诗','song-poetry','','[]','我亦將歸者，先行極羨君。',48,'全唐诗/poet.song.184000.json','["我亦將歸者，先行極羨君。", "惟因交已久，頗覺意難分。", "江滿帆侵樹，山高燒入雲。", "他年有書札，彼此訪耕耘。"]'),
('6bf74a2e-d1e8-4b7c-b500-ea7cf2ae7c3a','徐孺子宅','趙師秀','宋','宋诗','song-poetry','','[]','今識高眠處，滄波是切鄰。',48,'全唐诗/poet.song.184000.json','["今識高眠處，滄波是切鄰。", "已知難即鹿，惟有獨潛鱗。", "草長過荷葉，藤深失樹身。", "閑思昔微子，猶自得稱仁。"]'),
('cac22212-baf3-4847-a3dc-0d62efbc4ff2','德安道中','趙師秀','宋','宋诗','song-poetry','','[]','餐餘行數步，稍覺一身和。',48,'全唐诗/poet.song.184000.json','["餐餘行數步，稍覺一身和。", "蠶月人家閉，春山瀑布多。", "鶑啼聲出樹，花落片隨波。", "前路東林近，慚因捧檄過。"]'),
('11c5f40a-ff0c-4604-9a85-25fdca4973ad','徐靈暉挽詞','趙師秀','宋','宋诗','song-poetry','','[]','在生貧不害，早喪可嗟吁。',48,'全唐诗/poet.song.184000.json','["在生貧不害，早喪可嗟吁。", "天下黄金有，人間好句無。", "魂應湘水去，名與浪仙俱。", "平日惟耽茗，墳前種幾株。"]'),
('8c5147b7-93b6-4270-86c3-0999424aeabd','太平山讀書寄城中諸友','趙師秀','宋','宋诗','song-poetry','','[]','野人無別事，故得坐空林。',48,'全唐诗/poet.song.184000.json','["野人無別事，故得坐空林。", "黄卷還鋪日，青蓮未悟心。", "鐸音山殿靜，螢影石池深。", "不敢邀芳屣，因閑儻一尋。"]'),
('8eff656a-4435-4c04-ac50-318ea9d941d0','大龍湫','趙師秀','宋','宋诗','song-poetry','','[]','一派落虛空，如何畫得同。',48,'全唐诗/poet.song.184000.json','["一派落虛空，如何畫得同。", "高風吹作雨，低日射成虹。", "西域書曾說，先朝路始通。", "或言龍已去，幽處別爲宮。"]'),
('8d32e852-8b97-4a86-8642-ce021260e2e9','宿徐靈暉山舍','趙師秀','宋','宋诗','song-poetry','','[]','分坐橋邊石，同歸原上村。',48,'全唐诗/poet.song.184000.json','["分坐橋邊石，同歸原上村。", "窺燈禽出樹，聞語僕開門。", "雪後挑蔬潔，更深貰酒渾。", "極知高卧久，吾賤不能倫。"]'),
('6080d0a2-dda4-4e1a-a9f8-314dc1c77682','鴈蕩寶冠寺','趙師秀','宋','宋诗','song-poetry','','[]','行向石欄立，清寒不可云。',48,'全唐诗/poet.song.184000.json','["行向石欄立，清寒不可云。", "流來橋下水，半是洞中雲。", "欲住逢年盡，因吟過夜分。", "蕩陰當絕頂，一鴈未曾聞。"]'),
('ad1e8f49-de41-41e3-9702-56a84bab6b1d','贈約老','趙師秀','宋','宋诗','song-poetry','','[]','一徑入深竹，數楹臨古溝。',48,'全唐诗/poet.song.184000.json','["一徑入深竹，數楹臨古溝。", "更無人共住，極喜客來遊。", "白髮長垂領，新茶綠滿甌。", "自言門外寺，皆是老僧修。"]'),
('2f8a2d3c-8694-4364-b447-4dd13b416a76','送薛子舒赴華亭船官','趙師秀','宋','宋诗','song-poetry','','[]','竹籠盛書去，遥知官事閑。',48,'全唐诗/poet.song.184000.json','["竹籠盛書去，遥知官事閑。", "水程春有雨，海岸曉無山。", "奧理漸摩後，清名護養間。", "坐曹觀剡木，意與易相關。"]'),
('8c94f640-0db1-4c55-a708-2cbc5d9fbf37','翠巖寺','趙師秀','宋','宋诗','song-poetry','','[]','石巖看不見，翠色自重重。',48,'全唐诗/poet.song.184000.json','["石巖看不見，翠色自重重。", "春雨生松葉，山風響鐵鐘。", "碑頑工費墨，草嫩綠添茸。", "住院吳僧老，相迎憶舊逢。"]'),
('c7d53e73-6cd6-4f82-8198-bcf7c1d2b14b','送黄叔向謁楊伯子','趙師秀','宋','宋诗','song-poetry','','[]','嘗聞事將壇，何得復儒冠。',48,'全唐诗/poet.song.184000.json','["嘗聞事將壇，何得復儒冠。", "口誦新詩句，身呈舊箭瘢。", "賞因貧未受，愁擬醉相寬。", "當伏湖州牧，應憐志士寒。"]'),
('5fee919b-0f32-4ff2-8f83-54bc604cbe28','答葉司理','趙師秀','宋','宋诗','song-poetry','','[]','寂寞坐高齋，兵來與訊偕。',48,'全唐诗/poet.song.184000.json','["寂寞坐高齋，兵來與訊偕。", "喜看君字畫，癯似我形骸。", "頗欲徵陳作，遥知動遠懷。", "夢魂思一遇，風雨暗長淮。"]'),
('a44faf84-5d84-4bea-bd3b-a935384864bc','薛氏瓜廬','趙師秀','宋','宋诗','song-poetry','','[]','不作封侯念，悠然遠世紛。',48,'全唐诗/poet.song.184000.json','["不作封侯念，悠然遠世紛。", "惟應種瓜事，猶被讀書分。", "野水多於地，春山半是雲。", "吾生嫌已老，學圃未如君。"]'),
('2e4b87a0-fb1d-4a48-8043-e65d03a4650e','送徐道暉遊湘水','趙師秀','宋','宋诗','song-poetry','','[]','春盡雨霏霏，春寒猶在衣。',48,'全唐诗/poet.song.184000.json','["春盡雨霏霏，春寒猶在衣。", "人尋香草去，鴈背遠峰歸。", "瀟水添湘闊，唐碑入宋稀。", "應知名與姓，題寫遍巖扉。"]'),
('84bd3238-afae-4b58-aa40-75a4babf2477','劉隠君山居','趙師秀','宋','宋诗','song-poetry','','[]','嫌在城中住，全家入翠微。',48,'全唐诗/poet.song.184000.json','["嫌在城中住，全家入翠微。", "開松通月過，接竹引泉歸。", "慮淡頭無白，詩清貌不肥。", "必無車馬至，猶掩向巖扉。"]'),
('fa8e1568-9476-4790-828d-d62e19355ed0','官舍初成','趙師秀','宋','宋诗','song-poetry','','[]','爲宅傍城牆，先求夏日涼。',48,'全唐诗/poet.song.184000.json','["爲宅傍城牆，先求夏日涼。", "鑿池容衆水，栽竹斷斜陽。", "官是三年滿，身無一事忙。", "不知何補報，安坐恐難當。"]'),
('2fa3197c-1d97-4c29-ac44-d6f4e1fc06df','會景軒','趙師秀','宋','宋诗','song-poetry','','[]','此中非一景，欲狀固難名。',48,'全唐诗/poet.song.184000.json','["此中非一景，欲狀固難名。", "江近秋陰早，山多曉氣清。", "斷雲分樹泊，饑鶴下田行。", "別擬深更至，虛空看月明。"]'),
('4c974cd4-f910-4c23-8b0a-aed6ed49631f','和朱子發韵兼簡青龍諸友二首  其一','趙師秀','宋','宋诗','song-poetry','','[]','巷南與巷北，相去路無多。',48,'全唐诗/poet.song.184000.json','["巷南與巷北，相去路無多。", "以我常孤坐，勞君數見過。", "望山嫌夕靄，聽雨想春波。", "稍俟晴明日，相携一醉歌。"]'),
('c7e64380-7ae7-4f64-a261-cbc450a4ec4c','和朱子發韵兼簡青龍諸友二首  其二','趙師秀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雖說京華住，西湖豈不清。',48,'全唐诗/poet.song.184000.json','["雖說京華住，西湖豈不清。", "病多妨野興，貧甚損詩情。", "插柳觀春意，粘碑隔市聲。", "松江幾閒客，日夕聽波鳴。"]'),
('7583b0ab-9c45-4b25-bdc1-c064f883ec68','桃花寺','趙師秀','宋','宋诗','song-poetry','','[]','舊有桃花樹，人呼寺故云。',48,'全唐诗/poet.song.184000.json','["舊有桃花樹，人呼寺故云。", "石幽秋鷺上，灘遠夜僧聞。", "汲井連黄葉，登臺散白雲。", "燒丹勾漏令，無處不逢君。"]'),
('0642e8c7-460a-41ca-8c10-221cf4f09b82','送蔣節推赴岳陽','趙師秀','宋','宋诗','song-poetry','','[]','君山那可上，四面是層波。',48,'全唐诗/poet.song.184000.json','["君山那可上，四面是層波。", "此地風煙古，前人賦詠多。", "征帆衝鴈字，官舍近漁歌。", "況爾修真者，回仙必見過。"]'),
('af3ac427-ffd2-40fd-a423-c156ad98db78','大慈道','趙師秀','宋','宋诗','song-poetry','','[]','青苔生滿路，人跡至應稀。',48,'全唐诗/poet.song.184000.json','["青苔生滿路，人跡至應稀。", "小寺鳴鐘晚，深林透日微。", "野花春後發，山鳥澗中飛。", "或有相逢者，多因採藥歸。"]'),
('4a1e2298-baaf-4e0c-97fe-48096cf38654','送湯主簿','趙師秀','宋','宋诗','song-poetry','','[]','扶起階前菊，秋霖苦未休。',48,'全唐诗/poet.song.184000.json','["扶起階前菊，秋霖苦未休。", "更逢千里別，早白一年頭。", "客借程文看，兒分賜服收。", "還家有新興，佳句入書郵。"]'),
('d57103e0-c145-41d4-87cc-647fb9ce681e','送潘景參赴利路帳幹','趙師秀','宋','宋诗','song-poetry','','[]','蜀道如天遠，携家難計程。',48,'全唐诗/poet.song.184000.json','["蜀道如天遠，携家難計程。", "不從三峽過，免聽幾猿聲。", "戍密野花少，棧虛山雨鳴。", "同年同寂寞，此去子成名。"]'),
('05c390ce-5054-4796-98d8-810d7bad2129','水際','趙師秀','宋','宋诗','song-poetry','','[]','水際移居晚，薰風綠滿汀。',48,'全唐诗/poet.song.184000.json','["水際移居晚，薰風綠滿汀。", "密萍妨下釣，高柳礙觀星。", "忙是僧相過，閑惟雨可聽。", "尋思非久計，終憶自柴扃。"]'),
('c6fec575-672a-4a1e-b1eb-6790c34ef6cd','扶欄','趙師秀','宋','宋诗','song-poetry','','[]','强起扶欄立，新寒陡見侵。',48,'全唐诗/poet.song.184000.json','["强起扶欄立，新寒陡見侵。", "鐘聲諸寺曉，柳蔭半池陰。", "病久方憑艾，貧深或夢金。", "湖邊好風日，孤負幾登臨。"]'),
('60a678d7-e695-434c-b91d-ab6309b2d269','葛翁小閣','趙師秀','宋','宋诗','song-poetry','','[]','樹色對疎櫺，橫陳一片清。',48,'全唐诗/poet.song.184000.json','["樹色對疎櫺，橫陳一片清。", "微風楊葉下，斜日竹稍明。", "此老無塵事，雙姝亦道情。", "客來憐素壁，題句不題名。"]'),
('272ebe74-dced-4d7a-8739-57557e7ca53f','柳下書齋','趙師秀','宋','宋诗','song-poetry','','[]','轉曲認幽棲，齋名壁上題。',48,'全唐诗/poet.song.184000.json','["轉曲認幽棲，齋名壁上題。", "柳遮船步水，草出瓦溝泥。", "養靜拋書冊，銷閑倚杖藜。", "誰知鳳城外，宛是武陵溪。"]'),
('c8eec719-d3ff-40df-94c2-a1de0c056e96','贈陳宗之','趙師秀','宋','宋诗','song-poetry','','[]','四圍皆古今，永日坐中心。',48,'全唐诗/poet.song.184000.json','["四圍皆古今，永日坐中心。", "門對官河水，簷依綠樹陰。", "每留名士飲，屢索老夫吟。", "最感書燒盡，時容借檢尋。"]'),
('9ceb2e1f-4e82-4d93-b37b-3f30a539dd40','謝耕道犁春圖','趙師秀','宋','宋诗','song-poetry','','[]','春雨年年有，良田歲歲無。',48,'全唐诗/poet.song.184000.json','["春雨年年有，良田歲歲無。", "何因將此事，須要畫爲圖。", "野水寒初退，平林綠半敷。", "長謠謝沮溺，未必子知吾。"]'),
('a1fb9d90-1177-4364-98a4-8536d9225080','栗禁','趙師秀','宋','宋诗','song-poetry','','[]','宵長非一夢，欲記已迷茫。',48,'全唐诗/poet.song.184000.json','["宵長非一夢，欲記已迷茫。", "照鏡枯於腊，梳頭落似霜。", "病疴如退愈，貧屢又商量。", "所嗜惟崖栗，今年不敢嘗。"]'),
('709a0217-c5d9-457a-95ee-bd96b9dd98d6','盧申之載酒舟中分韵得明字','趙師秀','宋','宋诗','song-poetry','','[]','閑人閑處住，載酒荷高情。',48,'全唐诗/poet.song.184000.json','["閑人閑處住，載酒荷高情。", "小舍寧容客，同舟却向城。", "弄花忘晝暑，憂穀念秋晴。", "歸路雖無月，銀河亦自明。"]'),
('c8433ac3-0482-48e7-b7d6-11f4f060a98a','送真直院出使江東','趙師秀','宋','宋诗','song-poetry','','[]','一節鑄黄金，翩然別禁林。',48,'全唐诗/poet.song.184000.json','["一節鑄黄金，翩然別禁林。", "幾於言事日，已作去朝心。", "有識愁雖結，無慚喜自深。", "江邊瞻使者，誰不敬曾參。"]'),
('35189941-746f-4f48-9082-b99c608bb9d2','千日','趙師秀','宋','宋诗','song-poetry','','[]','千日方過半，何因便得還。',48,'全唐诗/poet.song.184000.json','["千日方過半，何因便得還。", "就令凡事易，不及一身閑。", "種朮憐官地，登城憶自山。", "苦吟無愛者，寫在戶庭間。"]'),
('91fce927-8239-45e9-97ad-676cdb9e0724','贈湯巾','趙師秀','宋','宋诗','song-poetry','','[]','黄金榜內人，枉刺忽相親。',48,'全唐诗/poet.song.184000.json','["黄金榜內人，枉刺忽相親。", "怪得名差異，吟來句極新。", "獨眠秋寺雨，罕踏帝城塵。", "何限高科客，因容不重身。"]'),
('c13fe29f-48e2-48b6-8f1f-27c20b9be91e','贈張亦','趙師秀','宋','宋诗','song-poetry','','[]','一別無書信，相逢各老蒼。',48,'全唐诗/poet.song.184000.json','["一別無書信，相逢各老蒼。", "山川烽外遠，歲月夢中長。", "空橐盛詩草，單衣涴酒香。", "因言瀼溪宴，同憶舊時狂。"]'),
('91d6792e-71ac-4964-b70e-b58dfafba21d','徐先輩挽詞','趙師秀','宋','宋诗','song-poetry','','[]','豈謂聲名早，番成不遇非。',48,'全唐诗/poet.song.184000.json','["豈謂聲名早，番成不遇非。", "賦曾天子見，詩有世人知。", "忽種松三尺，終乖桂一枝。", "幽芳誰與誌，御史念壎箎。"]'),
('a724ed91-179f-4990-a55d-a5331b0813d0','徐侍郎挽詞','趙師秀','宋','宋诗','song-poetry','','[]','少贊經綸業，周家已卜年。',48,'全唐诗/poet.song.184000.json','["少贊經綸業，周家已卜年。", "謗興無白日，心在有青天。", "遷謫還迎母，囏危復用賢。", "未令吾道泰，星殞灌城邊。"]'),
('d7cb0f3d-dd8d-45c9-b7cc-f657ab763623','訪韓仲止不遇題澗上','趙師秀','宋','宋诗','song-poetry','','[]','隔澗竹扉深，蒼童引客尋。',48,'全唐诗/poet.song.184000.json','["隔澗竹扉深，蒼童引客尋。", "雖然乖晤語，猶得見園林。", "野蔓時妨步，山蟬亦好吟。", "石根泉數斗，清冷應人心。"]'),
('78aa7cbf-664d-48cf-af92-e2d902baa432','龜峰寺','趙師秀','宋','宋诗','song-poetry','','[]','石路入青蓮，來遊出偶然。',48,'全唐诗/poet.song.184000.json','["石路入青蓮，來遊出偶然。", "峰高秋月射，巖裂野煙穿。", "螢冷粘椶上，僧閑坐井邊。", "虛堂留一宿，宛似鴈山眠。"]'),
('09ef0a37-1636-4955-a603-a8a693de1ae6','貴溪夜泊寄趙昌甫','趙師秀','宋','宋诗','song-poetry','','[]','蓍草占秋動，逢秋早得歸。',48,'全唐诗/poet.song.184000.json','["蓍草占秋動，逢秋早得歸。", "本非爲事迫，不欲與心違。", "波浄孤螢度，宵涼數葉飛。", "遠懷高卧者，微月閉松扉。"]'),
('f64c11ec-232d-48a8-a0a5-ecacc2aa57ba','送趙判官','趙師秀','宋','宋诗','song-poetry','','[]','三歲蓮華幕，何曾仕者同。',48,'全唐诗/poet.song.184000.json','["三歲蓮華幕，何曾仕者同。", "開牆通野客，分樹借江鴻。", "與世如無味，於民自有功。", "神仙今已近，不畏引帆風。"]'),
('78aa1fa1-63aa-43a3-a882-79c77728d40c','春晚即事','趙師秀','宋','宋诗','song-poetry','','[]','一身來作吏，白日算徒勞。',48,'全唐诗/poet.song.184000.json','["一身來作吏，白日算徒勞。", "塵土侵衣重，年光如鬢牢。", "春深禽語改，溪落岸沙高。", "柳下垂釣者，吾今媿爾曹。"]'),
('41ca07b9-e3a4-4759-829f-4401d3e5ec19','沈洞主','趙師秀','宋','宋诗','song-poetry','','[]','案上陰符卷，應逢驪母傳。',48,'全唐诗/poet.song.184000.json','["案上陰符卷，應逢驪母傳。", "無言過永日，不食度終年。", "雲覆燒丹竈，花浮洗藥泉。", "時聞有玄虎，來禮洞門前。"]'),
('87a497de-e7e8-4f31-a885-d9e7e87f9ab3','和鮑縣尉','趙師秀','宋','宋诗','song-poetry','','[]','留僧秋閣上，身自伴僧閑。',48,'全唐诗/poet.song.184000.json','["留僧秋閣上，身自伴僧閑。", "潄齒臨寒水，焚香對遠山。", "野禽偷果去，童子借經還。", "餘興成詩句，高題屋柱間。"]'),
('3f0e36c0-f050-48db-aad0-43f709d8f026','停帆','趙師秀','宋','宋诗','song-poetry','','[]','舟過梢人屋，停帆去未能。',48,'全唐诗/poet.song.184000.json','["舟過梢人屋，停帆去未能。", "野梅皆是刺，灘水不爲冰。", "里數訛難準，官稱俗可憎。", "欲登巖石坐，有吏復無朋。"]'),
('3e102074-e8fb-476b-9e5d-0f08cae0e07e','嚴州瀟灑亭','趙師秀','宋','宋诗','song-poetry','','[]','高榭出禪關，人家向下看。',48,'全唐诗/poet.song.184000.json','["高榭出禪關，人家向下看。", "千峰春隔霧，數里夜聞灘。", "偶至因成宿，前遊亦值寒。", "州人多有詠，何不見方干。"]'),
('b62220ee-5a38-4b3c-8fe5-3c8193de3b82','喜徐道暉至','趙師秀','宋','宋诗','song-poetry','','[]','嗜茶身益瘦，兼恐欲通仙。',48,'全唐诗/poet.song.184000.json','["嗜茶身益瘦，兼恐欲通仙。", "近作詩全少，閑成畫亦傳。", "瀟江風雪渡，嶽石姓名鎸。", "自接來消息，朝朝問客船。"]'),
('bc63cba7-6cbf-49e8-9249-fce4b52bce28','小舟','趙師秀','宋','宋诗','song-poetry','','[]','小舟隨處去，幽意日相親。',48,'全唐诗/poet.song.184000.json','["小舟隨處去，幽意日相親。", "野草勝荷葉，輕鷗似逸人。", "閑思此湖水，曾洗幾京塵。", "甚欲營漁屋，空虛未有因。"]'),
('564dd450-3460-43e2-89c5-fc244bd26026','林逋墓下','趙師秀','宋','宋诗','song-poetry','','[]','梅花千樹白，不是舊時村。',48,'全唐诗/poet.song.184000.json','["梅花千樹白，不是舊時村。", "傾我酤來酒，酹君仙去魂。", "短碑藤倚蔓，空冢竹行根。", "猶有歸來鶴，清時欲與論。"]'),
('3bfb497a-751e-458b-bd5b-5afaa1864ff9','寄徐縣丞','趙師秀','宋','宋诗','song-poetry','','[]','自爾爲官去，吾扉亦返關。',48,'全唐诗/poet.song.184000.json','["自爾爲官去，吾扉亦返關。", "池成逢夜雨，籬壞出秋山。", "歲事登禾稼，朝綱去草菅。", "題書寄漳水，專俟好詩還。"]'),
('ec4aa392-278e-4dd1-a725-f09472b9e202','示五峰僧','趙師秀','宋','宋诗','song-poetry','','[]','峰形如掌翠相環，頭白山僧引客看。',64,'全唐诗/poet.song.184000.json','["峰形如掌翠相環，頭白山僧引客看。", "積葉壞來泥徑滑，斜陽移去石橋寒。", "近聞瀑布尋還遠，易得菖蒲采極難。", "分我一峰於此住，與師相聚願辭官。"]'),
('93554500-986c-48af-b975-2e893811f33d','答徐靈淵','趙師秀','宋','宋诗','song-poetry','','[]','弊廬補葺雖勞力，且得幽閑住此身。',64,'全唐诗/poet.song.184000.json','["弊廬補葺雖勞力，且得幽閑住此身。", "舊友誤稱吟筆長，諸親爭笑罷官貧。", "近簷竹密妨巢雀，當戶花疎見路人。", "所慮久晴田事廢，今聞高下雨皆勻。"]'),
('49ef84ef-5333-4456-9ef7-571f3af7cf7b','寄徐丞','趙師秀','宋','宋诗','song-poetry','','[]','病不窺園經一月，更無人跡損青苔。',64,'全唐诗/poet.song.184000.json','["病不窺園經一月，更無人跡損青苔。", "池禽引子銜魚去，野蔓開花上竹來。", "亦欲鬢毛休似雪，爭如丹汞只爲灰。", "秋風昨夜吹寒雨，有夢南遊到海迴。"]'),
('25a655d0-502b-4109-9148-4f4a0bb269b5','送奭上人抄化','趙師秀','宋','宋诗','song-poetry','','[]','冒寒獨向何方去，爲建靈山閣未能。',64,'全唐诗/poet.song.184000.json','["冒寒獨向何方去，爲建靈山閣未能。", "詩卷带呈看疏客，藥爐留借共房僧。", "夕陽岸上行枯葉，瀑布巖前聽拆冰。", "事到有緣隨處應，回來金碧入雲層。"]'),
('9c28cb09-df86-4881-858b-7c405c2e2c3a','陳待制湖樓','趙師秀','宋','宋诗','song-poetry','','[]','何處飛來縹緲中，人間惟有畫圖同。',64,'全唐诗/poet.song.184000.json','["何處飛來縹緲中，人間惟有畫圖同。", "兩層簾幕垂無地，一片笙簫起半空。", "巖竹倒添秋水碧，渚蓮平接夕陽紅。", "遊人未達蒙莊旨，虛倚欄干面面風。"]'),
('e2f84337-1f37-44df-84c9-983ad8560139','送翁卷入山','趙師秀','宋','宋诗','song-poetry','','[]','已送山民歸舊廬，子今復去我何如。',64,'全唐诗/poet.song.184000.json','["已送山民歸舊廬，子今復去我何如。", "漸成老大難爲別，早占清閑未是疎。", "小雨半畦春種藥，寒燈一盞夜修書。", "有人來問陶貞白，說與華陽何處居。"]'),
('e1eff720-e7ac-45bc-a060-13197fd2c5b7','呈蔣薛二友','趙師秀','宋','宋诗','song-poetry','','[]','中夜清寒入縕袍，一杯山茗當香醪。',64,'全唐诗/poet.song.184000.json','["中夜清寒入縕袍，一杯山茗當香醪。", "鳥飛竹葉霜初下，人立梅花月正高。", "無欲自然心似水，有營何止事如毛。", "春來擬約蕭閑伴，重上天台看海濤。"]'),
('e344f7f0-02a1-4d03-a5eb-6eed1d8732a3','萬年寺','趙師秀','宋','宋诗','song-poetry','','[]','萬年山木有千年，石路陰深到繚垣。',64,'全唐诗/poet.song.184000.json','["萬年山木有千年，石路陰深到繚垣。", "幾片雲閑誰是主，一條流水不知源。", "土栽芍藥尤勝木，僧說獼猴極畏猿。", "夜半空堂諸境寂，微聞鐘梵亦成喧。"]'),
('4c016b16-a1d4-4869-bbc8-214cf49426c0','暮春書懷寄翁十','趙師秀','宋','宋诗','song-poetry','','[]','帝里逢春雨不乾，纔晴數日又春還。',64,'全唐诗/poet.song.184000.json','["帝里逢春雨不乾，纔晴數日又春還。", "桐華半落官河水，榆葉全遮客舍山。", "未悔闊疎令事去，最憐乏絕壞身閑。", "菖蒲九節今堪采，思爾逍遥澗谷間。"]'),
('a4165b5f-ff32-4da0-81e2-3877d1d1cd1b','移居謝友人見過','趙師秀','宋','宋诗','song-poetry','','[]','賃得民居亦自清，病身於此寄飄零。',64,'全唐诗/poet.song.184000.json','["賃得民居亦自清，病身於此寄飄零。", "筍從壞砌磚中出，山在隣家樹上青。", "有井極甘便試茗，無花可插任空瓶。", "巷南巷北相知少，感爾詩人遠扣扃。"]'),
('c6fb5564-69ff-4011-aa61-57e75d757c8d','和人韵贈北山僧','趙師秀','宋','宋诗','song-poetry','','[]','又得相逢閑寺裏，凡人多笑太無營。',64,'全唐诗/poet.song.184000.json','["又得相逢閑寺裏，凡人多笑太無營。", "誰知見事心先懶，未說尋幽足已輕。", "二月春風添樹色，一山夜雨失泉聲。", "謝師更作重眠約，來往云消兩日晴。"]'),
('20657c78-7d81-4c62-b782-74416e590d4b','再遊北山和韵','趙師秀','宋','宋诗','song-poetry','','[]','或行或坐水邊亭，處處春風戶不扃。',64,'全唐诗/poet.song.184000.json','["或行或坐水邊亭，處處春風戶不扃。", "飛絮伴人衰鬢白，遠山學我道衣青。", "迢遥更入煙霏去，髣髴如曾夢寐經。", "恐是前生林處士，晚年不飲至今醒。"]'),
('a7898ff7-c05c-4411-aa6d-fc4e4b965def','寄趙楚州','趙師秀','宋','宋诗','song-poetry','','[]','承明雖妙古云勞，小借臨邊却自豪。',64,'全唐诗/poet.song.184000.json','["承明雖妙古云勞，小借臨邊却自豪。", "韓信所封兵尚勁，劉伶曾住酒應高。", "牽來寶馬通言語，放去琱弓落羽毛。", "別有異時人憶處，萬株楊柳綠春壕。"]'),
('8fca6d2f-344a-43e3-b0bd-0fcd869b5293','多景樓晚望','趙師秀','宋','宋诗','song-poetry','','[]','落日欄干與鴈平，往來疑有舊英靈。',64,'全唐诗/poet.song.184000.json','["落日欄干與鴈平，往來疑有舊英靈。", "潮生海口微茫白，麥秀淮南迤邐青。", "遠賈泊舟趨地利，老僧指甕說州形。", "殘風忽送吹營角，聲引邊愁不可聽。"]'),
('e65b5253-5301-416e-9a8a-110467af56d2','姑蘇臺作','趙師秀','宋','宋诗','song-poetry','','[]','何人可與話登臨，徙倚危欄日又沈。',64,'全唐诗/poet.song.184000.json','["何人可與話登臨，徙倚危欄日又沈。", "千古蒼茫青史夢，一年迢遞故鄉心。", "天無雨雪梅花早，地有波濤鴈影深。", "爲是夫差舊臺榭，愁來不敢越人吟。"]'),
('5c33b466-86c5-4ca5-8293-87f980552514','病起','趙師秀','宋','宋诗','song-poetry','','[]','身如瘦鶴已伶俜，一卧兼旬更有零。',64,'全唐诗/poet.song.184000.json','["身如瘦鶴已伶俜，一卧兼旬更有零。", "朝客偶知親送藥，野僧相保密持經。", "力微尚覺衣裳重，才退難徼筆硯靈。", "惟有愛花心未已，遍分黄菊插空瓶。"]'),
('d1066a4d-db52-44bc-b066-77e42e8e3741','簡孫正字','趙師秀','宋','宋诗','song-poetry','','[]','空齋兀兀難消日，況入中年睡亦疎。',64,'全唐诗/poet.song.184000.json','["空齋兀兀難消日，況入中年睡亦疎。", "洗釜煮蔬留客飯，卷簾移菊看人鋤。", "秋衣因病全更衲，曉鬢迎寒半脫梳。", "多謝貴交芸閣裏，許令隨意借官書。"]'),
('64a52b36-7c59-4749-a1f4-840f82d6d50e','次韵趙正字蟹','趙師秀','宋','宋诗','song-poetry','','[]','嗔爾橫行爲多足，割爾兩螯如割玉。',64,'全唐诗/poet.song.184000.json','["嗔爾橫行爲多足，割爾兩螯如割玉。", "憐爾有甲不自衛，評爾一身黄勝肉。", "吳江十月天霜寒，吳人微爾不舉餐。", "萑蒲勿訝束爾急，與虎爭强能上山。"]'),
('01742373-9131-477d-b5fd-5680f11a8951','借居湖上','趙師秀','宋','宋诗','song-poetry','','[]','出仕歸來貧似舊，借園偶近畫橋居。',64,'全唐诗/poet.song.184000.json','["出仕歸來貧似舊，借園偶近畫橋居。", "縱觀不用春携酒，清坐何妨夜讀書。", "港小只通閑客棹，樹低多礙故人車。", "向時城裏緣塵土，久欲湖邊住歲餘。"]'),
('e522a0e1-5307-4d56-95c5-5b1083989ce3','送古壺與人','趙師秀','宋','宋诗','song-poetry','','[]','小壺純素無文采，驗是殷商物至今。',64,'全唐诗/poet.song.184000.json','["小壺純素無文采，驗是殷商物至今。", "損處怕教凡手觸，鑄時應有吉星臨。", "久藏厚土金聲盡，微貯清泉翠色深。", "持贈高人安几席，爲勾古意入新吟。"]'),
('643c12fc-6735-481e-ada9-6ddecab3bf34','贈鄧漢卿','趙師秀','宋','宋诗','song-poetry','','[]','單獨一身長不定，亦無書卷得相隨。',64,'全唐诗/poet.song.184000.json','["單獨一身長不定，亦無書卷得相隨。", "忙過人世當閑日，老遇朝廷用少時。", "衝雪自言行路苦，看松長恨買山遲。", "蕭蕭白髮寒燈下，寫就詩篇欲寄誰。"]'),
('e3fb1fcf-88e6-4c2f-aca8-5b12387b1680','孤山寒食','趙師秀','宋','宋诗','song-poetry','','[]','二月芳菲在水邊，旅人消困亦隨緣。',64,'全唐诗/poet.song.184000.json','["二月芳菲在水邊，旅人消困亦隨緣。", "晴舒蝶翅初勻粉，雨壓楊花未放綿。", "有句自題閑處壁，無錢難買貴時船。", "最憐隠者高眠地，日日春風是筦絃。"]'),
('d24add21-b824-4910-9e8b-0f6a60e08dc1','葉侍郎送紅芍藥','趙師秀','宋','宋诗','song-poetry','','[]','雕欄迎夏發奇葩，不擬分來野客家。',64,'全唐诗/poet.song.184000.json','["雕欄迎夏發奇葩，不擬分來野客家。", "自洗銅瓶插欹側，暫令書卷識奢華。", "舊遊尚憶揚州夢，麗句難同謝脁誇。", "應被花嗔少風味，午窗相對一杯茶。"]'),
('b751ad07-e600-43dd-aa42-695be69bff59','寄茅山溫尊師','趙師秀','宋','宋诗','song-poetry','','[]','幾度題詩寄入山，不知何處得書看。',64,'全唐诗/poet.song.184000.json','["幾度題詩寄入山，不知何處得書看。", "莓苔石上秋吟遠，星斗壇中夜拜寒。", "鶴改新名呼未至，碑逢斷刻打應難。", "憶師每欲尋師去，芝朮栽成自可餐。"]'),
('d6220a86-375c-4d53-98de-f45c80f8460e','會宿再送子野','趙師秀','宋','宋诗','song-poetry','','[]','又承出郭到貧家，一度分携鬢易華。',64,'全唐诗/poet.song.184000.json','["又承出郭到貧家，一度分携鬢易華。", "自說印書春可寄，獨慚闕酒夜難賒。", "眠遲古鼎銷殘火，吟苦寒缸落細花。", "羸病不能親送別，夢魂先立渡頭沙。"]'),
('ae90d435-a441-4721-9865-fc50348a7cd7','京華病後','趙師秀','宋','宋诗','song-poetry','','[]','久在京華損道心，故人誰與念升沈。',64,'全唐诗/poet.song.184000.json','["久在京華損道心，故人誰與念升沈。", "春樓卧病燕相伴，湖寺題詩僧爲吟。", "三月不逢家信至，一莖新有鬢絲侵。", "早知諫獵非時節，只在山中自養金。"]'),
('1ed3d12b-b0e4-465c-afb5-2c7be34541fe','過弋陽','趙師秀','宋','宋诗','song-poetry','','[]','三月三番過弋陽，吾生辛苦莫思量。',64,'全唐诗/poet.song.184000.json','["三月三番過弋陽，吾生辛苦莫思量。", "磨圓灘石幾年浪，丹盡江楓昨夜霜。", "已算中途當度臘，更憐抵舍未爲鄉。", "高眠舊有山中約，只欠青騾道士方。"]'),
('14f4d83d-cdf5-4662-b5fa-be3f08e54ab3','題方興化塋舍','趙師秀','宋','宋诗','song-poetry','','[]','晴簷方聽夜淋浪，晚送儒臣別建章。',64,'全唐诗/poet.song.184000.json','["晴簷方聽夜淋浪，晚送儒臣別建章。", "但欲有言扶國是，不嫌無計作身防。", "輕舟過處猿頻斷，舊宅開時菊正黄。", "心事對牀應細語，得歸如此亦何妨。"]'),
('8030a18c-5011-4330-bd93-bd8900f54f9f','數日','趙師秀','宋','宋诗','song-poetry','','[]','數日秋風欺病夫，盡吹黄葉下庭蕪。',32,'全唐诗/poet.song.184000.json','["數日秋風欺病夫，盡吹黄葉下庭蕪。", "林疎放得遥山出，又被雲遮一半無。"]'),
('526f56ea-67b6-425b-bf34-2704b9452b5d','玉清夜歸','趙師秀','宋','宋诗','song-poetry','','[]','巖有未有桂花開，觀裏閑尋道士來。',32,'全唐诗/poet.song.184000.json','["巖有未有桂花開，觀裏閑尋道士來。", "微雨過時松路黑，野螢飛出照青苔。"]'),
('2d58c17f-490a-4ac3-bf90-e05912550df1','池上','趙師秀','宋','宋诗','song-poetry','','[]','朝來行藥向秋池，池上秋深病不知。',32,'全唐诗/poet.song.184000.json','["朝來行藥向秋池，池上秋深病不知。", "一樹木犀供夜雨，清香移在菊花枝。"]'),
('b8a2b9f9-7b02-43c4-9a77-9abead1a1f24','題四聖觀□道士詩卷','趙師秀','宋','宋诗','song-poetry','','[]','一觀桃花紅似錦，兩堤楊柳綠於雲。',32,'全唐诗/poet.song.184000.json','["一觀桃花紅似錦，兩堤楊柳綠於雲。", "遊人只是遊晴晝，煙雨朝昏盡屬君。"]'),
('0002499f-c7ec-47ec-bb3e-5b5c0c1f9f21','白石巖','趙師秀','宋','宋诗','song-poetry','','[]','誰炷清香禮少君，數聲金磬夢中聞。',32,'全唐诗/poet.song.184000.json','["誰炷清香禮少君，數聲金磬夢中聞。", "起來閑把青衣袖，裹得欄干一片雲。"]'),
('6451fbfc-5a1a-4c49-8417-63308b890b46','再過吳松','趙師秀','宋','宋诗','song-poetry','','[]','江邊無處覓天隨，又趁斜陽過渺瀰。',32,'全唐诗/poet.song.184000.json','["江邊無處覓天隨，又趁斜陽過渺瀰。", "遠愛柳林霜後色，一如春至欲黄時。"]'),
('3083dcca-5895-40b2-9292-820155c89087','山路懷翁卷','趙師秀','宋','宋诗','song-poetry','','[]','困嘗苦茗不論杯，天氣纔晴又有雷。',32,'全唐诗/poet.song.184000.json','["困嘗苦茗不論杯，天氣纔晴又有雷。", "寂寞小亭看草坐，晚風時復墮青梅。"]'),
('57d7745f-1780-44ee-bd7d-badb5567e1c3','采藥徑','趙師秀','宋','宋诗','song-poetry','','[]','十載仙家采藥心，春風過了得幽尋。',32,'全唐诗/poet.song.184000.json','["十載仙家采藥心，春風過了得幽尋。", "如今縱有相逢處，不是桃花是綠陰。"]'),
('c9f9be87-97a9-4736-9aee-78a6aefa9c86','午困','趙師秀','宋','宋诗','song-poetry','','[]','午困因書又見尋，自添茶鼎候微吟。',32,'全唐诗/poet.song.184000.json','["午困因書又見尋，自添茶鼎候微吟。", "病身未覺春風暖，柳色無端日日深。"]'),
('05f9cf64-5ac8-4d29-8827-e8aa4789e171','約客','趙師秀','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u751f\u6d3b", "\u5199\u666f", "\u590f\u5929", "\u521d\u4e2d\u53e4\u8bd7", "\u590f"]','黄梅時節家家雨，青草池塘處處蛙。',32,'全唐诗/poet.song.184000.json','["黄梅時節家家雨，青草池塘處處蛙。", "有約不來過夜半，閑敲棋子落燈花。"]'),
('2f2aa475-975a-4a3b-ba61-b8a5053598a9','中子山作','趙師秀','宋','宋诗','song-poetry','','[]','城郭經寒近佛生，偶來高頂作山行。',32,'全唐诗/poet.song.184000.json','["城郭經寒近佛生，偶來高頂作山行。", "竹房冷落無僧在，獨倚闌干聽晚鶑。"]'),
('db65b112-2eef-4bfb-a6b7-9fd7939d3080','宿國清','趙師秀','宋','宋诗','song-poetry','','[]','殘燈吹了閉禪關，風約孤螢落砌間。',32,'全唐诗/poet.song.184000.json','["殘燈吹了閉禪關，風約孤螢落砌間。", "本爲飲茶妨睡早，强尋詩句擬寒山。"]'),
('1a4bfbaa-4e05-4608-b458-35425cdb4cb0','詩二首  其一','趙師秀','宋','宋诗','song-poetry','','[]','邑事多商榷，惟詩未暇論。',24,'全唐诗/poet.song.184000.json','["邑事多商榷，惟詩未暇論。", "母慈催扇枕，父老欲攀轅。"]'),
('a07c8dc4-5bbc-45c0-8d7a-8df9336164e9','詩二首  其二','趙師秀','宋','宋诗','song-poetry','','[]','三年非一事，知盡愛人心。',48,'全唐诗/poet.song.184000.json','["三年非一事，知盡愛人心。", "滿任添新髮，還家带舊琴。", "鵲聲先棹去，柳色到都深。", "即日應冠豸，憑共記得沈。"]'),
('a0dee6a4-e710-4701-b670-4d8564ede822','秋日偶書','趙師秀','宋','宋诗','song-poetry','','[]','官事何曾曉，閒名苦要簽。',48,'全唐诗/poet.song.184000.json','["官事何曾曉，閒名苦要簽。", "大書公吏恐，直語衆人嫌。", "俸少貧如故，醫慵病却添。", "秋風牆下菊，相對憶陶潛。"]'),
('098b33b3-78ee-41d1-a345-c75d440c497e','秋夜偶書','趙師秀','宋','宋诗','song-poetry','','[]','此生謾與蠹魚同，白髮難收紙上功。',64,'全唐诗/poet.song.184000.json','["此生謾與蠹魚同，白髮難收紙上功。", "輔嗣易行無漢學，玄暉詩變有唐風。", "夜長燈燼挑頻落，秋老蟲聲聽不窮。", "多少故人天祿貴，猶將寂寞歎揚雄。"]'),
('e2bfd7b3-a050-4fd7-9b99-314bc2f6c3e8','十里','趙師秀','宋','宋诗','song-poetry','','[]','烏紗巾上是黄塵，落日荒原更恐人。',64,'全唐诗/poet.song.184000.json','["烏紗巾上是黄塵，落日荒原更恐人。", "竹裏怪禽啼似鬼，道傍枯木祭爲神。", "亦知遠役能添老，無柰高眠不救貧。", "此地到城惟十里，明朝難得自由身。"]'),
('ab66bf68-c0f7-41b4-97b8-d00887084d67','潤陂山上作','趙師秀','宋','宋诗','song-poetry','','[]','一山大半皆櫧葉，絕頂閒尋得徑微。',64,'全唐诗/poet.song.184000.json','["一山大半皆櫧葉，絕頂閒尋得徑微。", "無日謾勞携紙扇，有風猶怯去綿衣。", "野花可愛移難活，啼鳥多情望即飛。", "惟與寺僧居漸熟，煮茶深院待人歸。"]'),
('ee6577c8-25d0-437c-8bda-47ada96dc297','寄新吳友人','趙師秀','宋','宋诗','song-poetry','','[]','每於樓上立，遠遠望新吳。',48,'全唐诗/poet.song.184000.json','["每於樓上立，遠遠望新吳。", "春至山疑長，江空雨似無。", "懷才人盡愛，多病體常癯。", "若治東游策，舟行與子俱。"]'),
('8215c36b-1560-4445-a90f-ddea076e197e','贈源長老歸自湘中','趙師秀','宋','宋诗','song-poetry','','[]','白髮半頭寒未剃，形容清瘦異於常。',64,'全唐诗/poet.song.184000.json','["白髮半頭寒未剃，形容清瘦異於常。", "爲人作畫衣添黑，對客圍棋爪甚長。", "不染世間如菡萏，只留胸次著瀟湘。", "住山亦自年來懶，竹閣門前借一房。"]'),
('3ed36296-1e25-4607-b95b-d554dacbe539','一真姑','趙師秀','宋','宋诗','song-poetry','','[]','忽然能不食，飲水度中年。',48,'全唐诗/poet.song.184000.json','["忽然能不食，飲水度中年。", "此事知難僞，令人信有仙。", "形容無血色，衣服有香煙。", "聽說瑶池路，猶如在目前。"]'),
('8e0301b3-e411-44b0-8c19-07bd5993b686','山路懷翁卷','趙師秀','宋','宋诗','song-poetry','','[]','幽溪曉無雨，野竹葉自濕。',36,'全唐诗/poet.song.184000.json','["幽溪曉無雨，野竹葉自濕。", "涓涓北流泉，風吹落花入。", "不見苦吟人，芳思將誰拾。"]'),
('f9ab8fac-a7db-4455-8866-0b5852e21bff','贈陳復道','趙師秀','宋','宋诗','song-poetry','','[]','自惜今年髮，新添一半華。',48,'全唐诗/poet.song.184000.json','["自惜今年髮，新添一半華。", "祇應如意事，不屬苦吟家。", "忽暖天□雪，微香案有花。", "故人勞見念，相過教丹砂。"]'),
('5a395d18-a6e2-4734-8a70-bff124a0f9b6','答曾景建','趙師秀','宋','宋诗','song-poetry','','[]','愛重吟來句，和經一處安。',48,'全唐诗/poet.song.184000.json','["愛重吟來句，和經一處安。", "亦知將作佛，何訝不爲官。", "楚塞烽煙靜，淮波柳絮殘。", "疑根深未指，欲往愧飛翰。"]'),
('b6bf9921-18d7-4c06-8c01-fc63286f6fa7','德安道中','趙師秀','宋','宋诗','song-poetry','','[]','峰頭不住起雲煙，野水縱橫盡入田。',32,'全唐诗/poet.song.184000.json','["峰頭不住起雲煙，野水縱橫盡入田。", "定是人家蠶事末，道傍桑葉小如錢。"]'),
('d65548a6-654a-4d15-aa87-7b3c6b6b3143','靈巖','趙師秀','宋','宋诗','song-poetry','','[]','忽有千巖聚，禪宮得土慳。',48,'全唐诗/poet.song.184000.json','["忽有千巖聚，禪宮得土慳。", "古來雲是海，天下別無山。", "久立增寒思，初看損壯顔。", "曾聞斤石剝，夜落半空間。"]'),
('a7db7a80-7cc1-49c6-9f49-81fb3f2b8313','杜鵑','趙師秀','宋','宋诗','song-poetry','','[]','三月江頭花正開，啼教花片委青苔。',32,'全唐诗/poet.song.184000.json','["三月江頭花正開，啼教花片委青苔。", "若嫌此地非君土，今度歸時莫要來。"]'),
('fd0cb6b7-245a-42ea-9c3d-e5b9e11b65c9','樓上','趙師秀','宋','宋诗','song-poetry','','[]','曉雨微微灑物華，牽牛初發傍牆花。',32,'全唐诗/poet.song.184000.json','["曉雨微微灑物華，牽牛初發傍牆花。", "數聲野鶴無尋處，只在樓西有竹家。"]'),
('3f92a517-f4b6-4779-b617-b558a1912b9f','吹臺曲','趙師秀','宋','宋诗','song-poetry','','[]','天門玉鑰雙龍開，霓旌羽蓋天上來。',104,'全唐诗/poet.song.184000.json','["天門玉鑰雙龍開，霓旌羽蓋天上來。", "管弦嘈雜入霄漢，美人侍讌黄金臺。", "羽觴行歌歡未足，燕姬成行列紅玉。", "梁王半醉起更衣，夜按玉簫親度曲。", "曲終舉袂俱爭妍，拜舞樽前稱萬年，三山玉女朝羣仙。", "當時弄玉飛上天，至今臺下草成煙。"]'),
('8a8de276-c8a1-44ad-b783-0605b8259208','題方興化塋舍','趙師秀','宋','宋诗','song-poetry','','[]','使君如玉不雕鎸，可惜埋藏已十年。',64,'全唐诗/poet.song.184000.json','["使君如玉不雕鎸，可惜埋藏已十年。", "佳兆昔令人入夢，遺經今有子能傳。", "紫藤附暖應生地，蒼柏凌空欲到天。", "要識德源無盡處，一池清甚發淵泉。"]'),
('d954a8ad-ad47-42b2-b85d-e90ef5fc427a','書李氏園亭','趙師秀','宋','宋诗','song-poetry','','[]','坐久思行步，因而上野亭。',48,'全唐诗/poet.song.184000.json','["坐久思行步，因而上野亭。", "日兼梅雨落，山接稻田青。", "何術銷終訟，連朝役瘦形。", "早知還走俗，不用學通經。"]'),
('8a04fb82-1f64-4c14-aea3-cdfd6157b1aa','奉賦朱新父足庵','趙師秀','宋','宋诗','song-poetry','','[]','人欲難窮極，於中覺者稀。',48,'全唐诗/poet.song.184000.json','["人欲難窮極，於中覺者稀。", "但令無過分，何處有危機。", "長日書千冊，清風竹一園。", "東南坤勢闕，子計不爲非。"]'),
('c80297d0-a3b9-4051-a86f-b9be91355f96','北戶','趙師秀','宋','宋诗','song-poetry','','[]','曉開北戶得新晴，木末猶橫一兩星。',32,'全唐诗/poet.song.184000.json','["曉開北戶得新晴，木末猶橫一兩星。", "滿地綠苔看不見，細花如雪落冬青。"]'),
('c043e27c-0e55-4c46-83f3-a734db7d0153','庵西','趙師秀','宋','宋诗','song-poetry','','[]','數里庵西路，東風去更吹。',48,'全唐诗/poet.song.184000.json','["數里庵西路，東風去更吹。", "稻寒生葉細，松老作花遲。", "小憇嫌無侶，曾游憶有詩。", "新螢光尚小，未暗出空池。"]'),
('3aa5de3c-4c45-4fc0-8e49-c28519d70ec8','石門寺','趙師秀','宋','宋诗','song-poetry','','[]','寺外山皆石，門因鑿石開。',48,'全唐诗/poet.song.184000.json','["寺外山皆石，門因鑿石開。", "野花黄類菊，寒笋綠黏苔。", "官爲看田至，僧方乞食回。", "一雙簷際鴿，空覷出生臺。"]'),
('51427808-7663-4132-9aec-1e7a6c32322f','無言師還道院求詩','趙師秀','宋','宋诗','song-poetry','','[]','師已無言矣，今吾何所云。',48,'全唐诗/poet.song.184000.json','["師已無言矣，今吾何所云。", "惟知佛照子，曾管雁山雲。", "天下閒爲寶，人間熱似焚。", "筠州郡齋近，安坐過秋分。"]'),
('b17a4b12-ffdf-4d93-95a0-3d2f22dc0002','送謝耘之無爲','趙師秀','宋','宋诗','song-poetry','','[]','雙旌雖有舊，道路亦勞形。',48,'全唐诗/poet.song.184000.json','["雙旌雖有舊，道路亦勞形。", "不用携書尺，惟當带酒瓶。", "柘空淮繭白，梅近楚秧青。", "爾以親爲請，仁人豈厭聽。"]'),
('ac7e293b-8fc4-4841-8b6b-a1480e71f121','秋日遊棲霞菴','趙師秀','宋','宋诗','song-poetry','','[]','乘興入孤村，神凝秋水間。',48,'全唐诗/poet.song.184000.json','["乘興入孤村，神凝秋水間。", "菊開嫌徑小，荷盡覺池寬。", "林影懸崖屋，鐘聲何處山。", "清遊殊未倦，初月照松關。"]'),
('bfd29d4a-fc02-43de-9b7b-ca845fa8d879','夜宿江浦聞元八改官寄此','趙師秀','宋','宋诗','song-poetry','','[]','君遊丹陛已三遷，我泛滄浪亦二年。',64,'全唐诗/poet.song.184000.json','["君遊丹陛已三遷，我泛滄浪亦二年。", "劍佩曉趨雙鳳闕，煙波夜宿一漁船。", "交親盡在青雲上，鄉曲都拋白日邊。", "若報生涯應笑殺，結茆栽芋種畬田。"]'),
('97deae8c-bc22-4de2-a6c8-63f736c82a03','句  其一','趙師秀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','病與西湖絕半年。',8,'全唐诗/poet.song.184000.json','["病與西湖絕半年。"]'),
('392bacd8-0c72-457c-af18-a7f9c39a1a77','句  其二','趙師秀','宋','宋诗','song-poetry','','[]','况多秋蘚色。',6,'全唐诗/poet.song.184000.json','["况多秋蘚色。"]'),
('6715ab7c-4973-49c2-a896-884026a12784','句  其三','趙師秀','宋','宋诗','song-poetry','','[]','恨不坐通宵。',6,'全唐诗/poet.song.184000.json','["恨不坐通宵。"]'),
('63291f53-1d4c-4c71-9d12-1832c60f8023','句  其四','趙師秀','宋','宋诗','song-poetry','','[]','路曲山隈一徑通。',8,'全唐诗/poet.song.184000.json','["路曲山隈一徑通。"]'),
('6b238eba-1f2c-492b-98db-e441233469ef','句  其五','趙師秀','宋','宋诗','song-poetry','','[]','聞見隨時入品題。',8,'全唐诗/poet.song.184000.json','["聞見隨時入品題。"]'),
('bfa60daf-9ae4-45ea-897b-7b975bd5d92c','句  其六','趙師秀','宋','宋诗','song-poetry','','[]','地僻傳聞新事少，路遥牽率故人多。',16,'全唐诗/poet.song.184000.json','["地僻傳聞新事少，路遥牽率故人多。"]'),
('89312b97-43b9-4dfb-86b4-032d4132a0bb','句  其七','趙師秀','宋','宋诗','song-poetry','','[]','一瓶茶外無祗待，同上西樓看晚山。',16,'全唐诗/poet.song.184000.json','["一瓶茶外無祗待，同上西樓看晚山。"]'),
('afb4a6f5-1d83-432f-88fd-c0a2bfcb650a','句  其八','趙師秀','宋','宋诗','song-poetry','','[]','石畔長來枝易老，竹間瘦得萼全清。',16,'全唐诗/poet.song.184000.json','["石畔長來枝易老，竹間瘦得萼全清。"]'),
('55e03bdd-cbcd-4f9b-9431-e3cfaf00c88a','句  其九','趙師秀','宋','宋诗','song-poetry','','[]','教人知遁甲，笑客問勾庚。',12,'全唐诗/poet.song.184000.json','["教人知遁甲，笑客問勾庚。"]'),
('0690ddbc-97b7-4046-a897-c7dbb7f29a92','夜讀杜詩四十韻','蘇泂','宋','宋诗','song-poetry','','[]','夜讀老杜詩，如對老杜面。',288,'全唐诗/poet.song.184000.json','["夜讀老杜詩，如對老杜面。", "此翁歷艱難，往往詩中見。", "曩吾游川蜀，所恨年數淺。", "草堂聞無人，正在成都縣。", "斷碑蝕苔蘚，捫讀知幾遍。", "尋思隠其下，終日弄書卷。", "庶幾平生心，所得未應偭。", "親庭宦行在，歸計乖初願。", "言瞻浣花里，巵水乃缺獻。", "人間畫圖樣，皮骨怪豐腆。", "京華四十載，褐短更馿蹇。", "至今彼堂上，唇綻齒微現。", "獨餘雙眸子，利若秋江剪。", "因何太瘦生，貧賤恐不免。", "耒陽一臠炙，飲食知味鮮。", "後人美肴膳，出語穢蝦蜆。", "那知獨角龍，妙用天行健。", "至其得意處，力斡造物轉。", "神雷破潛穴，霹靂飛雨片。", "武夫荷戈戰，颯沓旂鼓偃。", "蛟鼉呿波浪，宗廟羅黻冕。", "鞭車甫平陸，梯磴忽絕巘。", "又如虛空內，一氣互游衍。", "有足恣馳驅，不行渠自遠。"]'),
('30506d94-945f-4291-8ead-4da3e901dfe5','寓言二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','精神徧八方，一散或爲風。',48,'全唐诗/poet.song.184000.json','["精神徧八方，一散或爲風。", "堂堂世之人，奈何總虛空。", "我無騰化術，正爾不能從。", "回視恍兮惚，老子其猶龍。"]'),
('d77c51a2-4fba-49bd-83b0-e1f82714d40d','寓言二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','函關度青牛，生在空桑中。',48,'全唐诗/poet.song.184000.json','["函關度青牛，生在空桑中。", "藁砧未刀頭，妾身變山峰。", "三年化爲碧，是血本來紅。", "古來埋直氣，曾見吐長虹。"]'),
('3e1406e9-d8ec-4808-8b72-d22d33f55428','口占','蘇泂','宋','宋诗','song-poetry','','[]','士生弊於文，其實乃無用。',48,'全唐诗/poet.song.184000.json','["士生弊於文，其實乃無用。", "今年州縣間，朋友多不貢。", "桔槔旱而工，已得輕抱甕。", "大舜舉皋陶，乃曰選於衆。"]'),
('d30740fd-e843-4c2b-85c3-36274ff7c1fe','題欒城第三集','蘇泂','宋','宋诗','song-poetry','','[]','百金貿一書，我心胡不喜。',48,'全唐诗/poet.song.184000.json','["百金貿一書，我心胡不喜。", "自朝至日暝，耽玩無窮已。", "復慚文未老，年既三十四。", "更後四十年，未必辦茲事。"]'),
('97d90a0d-bc94-4baa-8a60-5394cc31e646','擬古','蘇泂','宋','宋诗','song-poetry','','[]','曾城上岧嶢，樓觀切星辰。',96,'全唐诗/poet.song.184000.json','["曾城上岧嶢，樓觀切星辰。", "其下視九州，我行屢秋春。", "道逢兮美人，遺我芳蘭蓀。", "蘭蓀不可佩，飲水代朝餐。", "仰看雙飛燕，起勢何翩翩。", "顔淵稱賢者，樂在簞瓢間。", "美人捨我去，此去何時還。", "怞怞思徒抽，惻惻聲孰聞。"]'),
('719b23e0-83d8-4987-a0b3-399c365b72ed','見懷','蘇泂','宋','宋诗','song-poetry','','[]','顔淵樂簞瓢，曾子日三省。',84,'全唐诗/poet.song.184000.json','["顔淵樂簞瓢，曾子日三省。", "閉門謝往還，安此寂寞境。", "閑來愛我地，止渴望梅嶺。", "玄談破月脇，心對日光炯。", "榮枯百年事，如一彈指頃。", "吾儕各老大，妙契形問影。", "回味久乃知，酒固不勝茗。"]'),
('b91b95e0-1e4f-4428-8e3a-d6bc377b9eae','吾廬','蘇泂','宋','宋诗','song-poetry','','[]','陰陰處士廬，寂寂閉門居。',48,'全唐诗/poet.song.184000.json','["陰陰處士廬，寂寂閉門居。", "頗安顔氏子，敬謝陶胡奴。", "可使龍作魚，不使馬爲駒。", "詩成有奇氣，浮雲時卷舒。"]'),
('4d1edcf3-f384-44df-954a-4c9d9420e00c','郊行弔古呈友人','蘇泂','宋','宋诗','song-poetry','','[]','荒齋讀書罷，出門步青春。',72,'全唐诗/poet.song.184000.json','["荒齋讀書罷，出門步青春。", "春風扇微和，冠者五六人。", "登高恣遊目，行邁靡其因。", "平湖半疆畎，王謝亦齊民。", "父老談古先，觴客酒濡脣。", "歸同牛羊夕，戃恍難重陳。"]'),
('2bff668c-9013-433c-aa6e-dd9d65bdac8f','春日獨居感懷','蘇泂','宋','宋诗','song-poetry','','[]','昔我金陵歸，感此芳歲闌。',144,'全唐诗/poet.song.184000.json','["昔我金陵歸，感此芳歲闌。", "入門見兒女，愧色蓋愁顔。", "從人竊餘瀝，俯育良已難。", "居者瓶盎空，行者衣裳單。", "豈無一杯酒，持慰汝荒寒。", "所知不相待，各去爲蒼山。", "我生轉無聊，終日自閉關。", "門前春風來，草樹向斕斑。", "舟車載游冶，類聚極相歡。", "而我懷所知，所得心未安。", "晨興亦扶杖，十步九思還。", "言瞻山頭石，安得如汝頑。"]'),
('1c906a96-9fb6-4633-98e4-52f7003135a1','春歌','蘇泂','宋','宋诗','song-poetry','','[]','山人昨日到，野棠連夜開。',48,'全唐诗/poet.song.184000.json','["山人昨日到，野棠連夜開。", "啼鵑背山去，流鶑度水來。", "草長留款步，花殘勸餘盃。", "於焉早復暮，行坐摘青梅。"]'),
('a0783f2e-3006-4fcd-9d7f-739ba134b073','奉謝唐子耆及兩馮君載酒寵臨借屋','蘇泂','宋','宋诗','song-poetry','','[]','年事半七十，躬耕吾本謀。',96,'全唐诗/poet.song.184000.json','["年事半七十，躬耕吾本謀。", "讀書詎云然，迺與世爲讎。", "維我先人廬，雨風行蝸牛。", "假此以適我，得無歲云周。", "永懷鵲有巢，寧久居夫鳩。", "食飲所不忘，歸焉買林丘。", "進退孰我能，萬間子無由。", "愧子撫我厚，感子非肴羞。"]'),
('143c25f8-fa33-4aef-b13e-bf6db8c619c6','奉寄子高盧兄五十韻','蘇泂','宋','宋诗','song-poetry','','[]','君才如驌驦，道里未可量。',288,'全唐诗/poet.song.184000.json','["君才如驌驦，道里未可量。", "讀書串脈絡，如海東赴洋。", "五年隔異縣，信若參與商。", "昨者戒車馬，故意改未嘗。", "我家小於斗，下榻出倉黄。", "繩樞三椽共，君視猶雕梁。", "貧又少甘脆，而君甘粃糠。", "晨興烏鵲先，夕憩星宿張。", "上言體金玉，時節登虞唐。", "下言復家世，努力事文章。", "瑣細及兒女，骨肉誼莫當。", "君來歷州府，所在諸侯良。", "肝膽皆善子，子去錐脫囊。", "問胡獨善我，風雨度錢唐。", "我時熟君指，又不羅酒漿。", "何况動隣里，磨刀向豬羊。", "青燈兩夫影，陳義勸交相。", "謂言經時留，十日又理裝。", "但携本經冊，沃州山水鄉。", "子寧舍我去，我意未子忘。", "相逢一歲短，相別一日長。", "何緣子吾所，不然我君傍。", "君雖老馬姿，今乃驥服箱。", "刷燕日千里，闊步徐康莊。"]'),
('9f1637a1-c3f5-4209-8a8b-3aa5e13ace00','次韻潁叟弟耕堂即事  其一','蘇泂','宋','宋诗','song-poetry','','[]','聖賢畏虛名，蠻貊有誠服。',48,'全唐诗/poet.song.184000.json','["聖賢畏虛名，蠻貊有誠服。", "仕雖志溫飽，鮮不餒其腹。", "爾來讀書者，妄意天雨粟。", "東皋春一犁，往哉駕黄犢。"]'),
('dae06c6d-5b83-4f68-93e4-4fbd8079176d','次韻潁叟弟耕堂即事  其二','蘇泂','宋','宋诗','song-poetry','','[]','耕田可無田，耕道豈得道。',48,'全唐诗/poet.song.184000.json','["耕田可無田，耕道豈得道。", "物生豈區區，天意非草草。", "林茂鳥知歸，水清魚惡擾。", "勿謂小人哉，請學樊須老。"]'),
('0e184752-01aa-443c-a4c1-6d5127e57705','次韻潁叟弟耕堂即事  其三','蘇泂','宋','宋诗','song-poetry','','[]','儒冠誤終身，其始從上士。',48,'全唐诗/poet.song.184000.json','["儒冠誤終身，其始從上士。", "頭白賦歸來，不腐已其次。", "我今戒兒姪，萬卷易雙耜。", "向使微阿連，幾敗乃公事。"]'),
('3e4465d7-0005-4bfa-9caa-548f5587ff09','江上遣心','蘇泂','宋','宋诗','song-poetry','','[]','風帆等駿馬，突出不受羈。',120,'全唐诗/poet.song.184000.json','["風帆等駿馬，突出不受羈。", "羣山望如豆，轉盼羅窗扉。", "頃居長安城，小駟驅以馳。", "塵埃困煩促，滯留費憂思。", "不知葭葦鄉，閟此天地奇。", "鷗禽亦佳尚，潔身固我師。", "下上萬頃光，夫豈矜其私。", "物生各有適，我適君無之。", "掀髯倚柁樓，一笑了百癡。", "商歌詎成音，逝者方如斯。"]'),
('2e40f373-b5b7-4234-95df-7ec96e42f9a6','題松鶴','蘇泂','宋','宋诗','song-poetry','','[]','鶴鳴松樹顛，人行松樹下。',48,'全唐诗/poet.song.184000.json','["鶴鳴松樹顛，人行松樹下。", "人禽兩無屬，往往俱物化。", "明日還獨來，寂寞青松夜。", "擾擾征途間，誰是知音者。"]'),
('c3cd036d-42c3-43f4-943e-75c4ea524a7c','晨起長哦後山秋懷十詩飲水一杯清寒徹心','蘇泂','宋','宋诗','song-poetry','','[]','長哦十秋懷，清韻繞屋梁。',48,'全唐诗/poet.song.184000.json','["長哦十秋懷，清韻繞屋梁。", "曲逆有餓死，英布刑而王。", "向來爲長公，甘受三徑荒。", "一身詎無餘，百年信難量。"]'),
('3995c376-cab8-4d4d-83ab-a763c8904561','邊頭嘆','蘇泂','宋','宋诗','song-poetry','','[]','邊頭奏凉風，戰士送寒衣。',96,'全唐诗/poet.song.184000.json','["邊頭奏凉風，戰士送寒衣。", "北征夏徂秋，君王虛六師。", "區區彼敵人，授首詎無期。", "冰霜輝戈甲，勇憶臨去時。", "去去思樹功，寧復顧家爲。", "指揮在將軍，坐作看旌旗。", "謂是白沙漠，那知青草陂。", "當時均死力，顧乃用之非。"]'),
('6ce703c5-829d-4f84-b53d-a91166e1a32d','春日起晚','蘇泂','宋','宋诗','song-poetry','','[]','春風散百物，和暖氣難清。',168,'全唐诗/poet.song.184000.json','["春風散百物，和暖氣難清。", "晨衾四肢倦，欲起還不能。", "展轉卧成晏，起聽百鳥鳴。", "幸然無公事，且復寡經營。", "妻兒悄不喧，日午閉柴荆。", "羹魚就鮮買，軟飯熟香粳。", "雖然媿茲食，頼爾王化成。", "出門步原田，最愛莓苔青。", "半生果何爲，悔不學躬耕。", "把鋤如把筆，冀穫尚何曾。", "還復茅簷下，所思良友朋。", "青雲固云樂，倚伏諒難明。", "那無託衰懶，緬想川上情。", "物我均所役，聊復安其生。"]'),
('ef8a5677-4e6b-470c-9d3f-642702f13931','次馬季思十韻','蘇泂','宋','宋诗','song-poetry','','[]','巷內有佳人，其志介如石。',120,'全唐诗/poet.song.184000.json','["巷內有佳人，其志介如石。", "沉酣數千卷，徑草無行迹。", "秋清入肺胃，籬落牽牛碧。", "詩成錦繡段，裁剸非刀尺。", "如聞急徵召，厚甚帛加璧。", "毋庸北窗下，細字朱黄釋。", "嗟余世無用，痛飲時墮幘。", "思君不相見，誰與浮大白。", "中年友朋減，生意天壤迮。", "何時樗隠園，容我分半席。"]'),
('4a882d89-0a9e-49e3-be91-42c7d5629ad9','詠懷','蘇泂','宋','宋诗','song-poetry','','[]','初夏腓草木，園綠勝春深。',96,'全唐诗/poet.song.184000.json','["初夏腓草木，園綠勝春深。", "微雨灑高棟，好風吹我襟。", "徘徊花下徑，獨往翫層陰。", "東西燕雀飛，寂寞鸞鳳音。", "人生積累資，培塿升高岑。", "陳力正不能，前修愧周任。", "何時歌物阜，薰兮入舜琴。", "俯仰終所爲，於以達吾心。"]'),
('8053df6d-2ef5-4842-8550-88216f6e6b78','送陸放翁赴落致仕修史之命','蘇泂','宋','宋诗','song-poetry','','[]','先生天下名，有耳誰不知。',288,'全唐诗/poet.song.184000.json','["先生天下名，有耳誰不知。", "區區以蠡測，于海徒贅辭。", "弟子事先生，丱角以至斯。", "文章起嬰慕，德行隨蕭規。", "昨聞掛衣冠，固共識者疑。", "豈期平生學，終鬰不得施。", "先生健而武，神志元未衰。", "每登漁隠堂，再拜奉履綦。", "留我坐終日，誨我忘其疲。", "送我出重門，行步又若飛。", "或捉筆大書，或脫口賦詩。", "或時幾酌我，自倒金屈巵。", "我出謂客言，先生壽期頤。", "上爲天下賀，下以賀吾師。", "在郊一角麟，藏六五總龜。", "先生固高世，而世肯我違。", "情知渭濱載，謾道淵明歸。", "果然一札下，未覺十年遲。", "堂堂孝廟史，當代誰宜爲。", "二十八年間，凡事公見之。", "英靈果在天，筆削詎敢私。", "矧惟陛下聖，益重黄髮咨。", "湖山晚無用，遭逢乃今茲。", "先生顧謂我，萬物各有時。"]'),
('a4b767be-b325-41c7-8ea6-73f43675372d','歸越中所居','蘇泂','宋','宋诗','song-poetry','','[]','閑居寡人事，棲遲倦所務。',96,'全唐诗/poet.song.184000.json','["閑居寡人事，棲遲倦所務。", "雅志歸去來，青山越中住。", "爻辭翫往聖，門蔭資先祖。", "雖云隠遁情，尚眷諸親故。", "歲時酒一尊，聊樂我東土。", "采蓮樵風徑，看竹蘭亭路。", "心亨體攸適，干祿靡希遇。", "百年儻有程，庶近嚴光墓。"]'),
('68dcb451-b53c-4c88-98ca-a74ba0cd76d1','用陶己酉歲九月九日韻','蘇泂','宋','宋诗','song-poetry','','[]','壺罇湛名酒，四散會朋交。',96,'全唐诗/poet.song.184000.json','["壺罇湛名酒，四散會朋交。", "黄菊雖未開，翠木亦已凋。", "駕言彼墟矣，佳處聊登高。", "山晴歛將夕，宇浄豁層霄。", "迨我色笑同，息爾筋力勞。", "人情旱欲濡，來蘇慰乾焦。", "儻然隨運往，冥契彭澤陶。", "有花即重九，何必須今朝。"]'),
('1250416e-b330-4227-aeab-1efb1a0ca9fa','和陶九日閒居','蘇泂','宋','宋诗','song-poetry','','[]','斯人鮮常在，奄忽便一生。',108,'全唐诗/poet.song.184000.json','["斯人鮮常在，奄忽便一生。", "茲辰俄重九，令節誰所名。", "把菊見南山，吟詩憶淵明。", "素琴不具絃，大雅留遺聲。", "伯始真糞土，飲水空遐齡。", "異時東坡下，尚有酒可傾。", "才難信遇否，物變更枯榮。", "此翁獨醒者，貧賤胡爲情。", "悵焉服九華，覓醉何由成。"]'),
('bdbaa9b8-9a90-47c5-a6dd-1f9267866208','擬古  其一','蘇泂','宋','宋诗','song-poetry','','[]','煌煌庭中菊，秋後各已花。',144,'全唐诗/poet.song.184000.json','["煌煌庭中菊，秋後各已花。", "玄霜下蒼葉，憔悴同凡葩。", "采之或傷生，不采謂我遐。", "貴賤詎不然，無已安其家。", "蕭條陶彭澤，歸去隨風沙。", "自古有如此，我何良歎嗟。", "季倫昔富貴，舉國稱石家。", "千金買綠珠，歌舞笑春華。", "醉歸擊珊瑚，恨不窮驕奢。", "黄塵洛陽起，里第生桑麻。", "仲尼卒旅人，歷聘空摧車。", "古來竟何爲，不見東門瓜。"]'),
('421bdeb8-59bf-47bf-adf1-272483124c9b','擬古  其二','蘇泂','宋','宋诗','song-poetry','','[]','日月遞相見，玄髮驚蹉跎。',72,'全唐诗/poet.song.184000.json','["日月遞相見，玄髮驚蹉跎。", "冥冥北邙路，去者何其多。", "妻孥聚歡樂，志遠身已訛。", "功名無富貴，此路不可過。", "可憐世上人，刺促鳴干戈。", "金尊幸有酒，不飲將如何。"]'),
('58c4f82c-8032-4064-aef1-390c1d9d4622','擬古  其三','蘇泂','宋','宋诗','song-poetry','','[]','漢光昔未遇，頗爲兄嫂欺。',192,'全唐诗/poet.song.184000.json','["漢光昔未遇，頗爲兄嫂欺。", "誰知韓王信，本是屠沽兒。", "他時築將壇，意氣帝者師。", "中興屏新莽，長劍誅赤眉。", "皇天生一物，大小隨其資。", "例令饑與寒，何以生育爲。", "永言觀厥成，圓璧殊方圭。", "天意定不爾，變化應須時。", "少小弄文翰，把筆能哦詩。", "十五學綴文，如繭中抽絲。", "青雲付達官，十九名新知。", "南轅異燕路，鄙笑無挈提。", "甘心窮閻中，疏食黄瓜虀。", "區區蠹魚習，槁死不可醫。", "閒齋秉微尚，高視聖者師。", "謾言苦如荼，誰信甘如飴。"]'),
('09ceb663-ead2-4ae3-9e77-4edc1b0aae9f','擬古  其四','蘇泂','宋','宋诗','song-poetry','','[]','自吾蜀中歸，稍拂衣上塵。',96,'全唐诗/poet.song.184000.json','["自吾蜀中歸，稍拂衣上塵。", "古今名利場，誤殺多許人。", "歸囊課宿有，頗欲謀其身。", "買花郡庠東，結屋清鏡濱。", "山田不滿百，濁酒當濡唇。", "庶幾友生來，談笑夜達晨。", "此志猶未遂，寬作明年春。", "人生幾明年，謹勿浪苦辛。"]'),
('d67e3d21-f071-4d3f-b9c4-0987bd4071e2','擬古  其五','蘇泂','宋','宋诗','song-poetry','','[]','往時尋芳興，屢醉黄金巵。',144,'全唐诗/poet.song.184000.json','["往時尋芳興，屢醉黄金巵。", "日來酒量窄，三盞忘東西。", "雖然不多飲，不飲還復思。", "所以畢吏部，千古遭嘲嗤。", "每年梅花開，如與粲者期。", "有時棹孤舟，間或借馬騎。", "水村及山驛，日炙仍風吹。", "醉歸更有携，研席相娛嬉。", "今年墮塵鞅，頗復疎闊之。", "此君應有言，亦曰好惡移。", "凄凉殘年歷，春到無多時。", "如何江南岸，不見開一枝。"]'),
('4e9876c9-c710-4ad7-9726-6429ab39e427','秋興  其一','蘇泂','宋','宋诗','song-poetry','','[]','秋高朔馬肥，壯士多感激。',192,'全唐诗/poet.song.184000.json','["秋高朔馬肥，壯士多感激。", "起看天宇空，萬物盡陰黑。", "連年稍艱食，所至多盜賊。", "人情有馴致，世或尚姑息。", "坐令鼠子輩，漸欲穴我室。", "苟生各有養，飛走隨所得。", "奪攘乃如此，彼計多變易。", "我生無根蒂，尚守祖父宅。", "邇來時命乖，僕僕州縣客。", "兩親化爲土，弟妹各狼藉。", "箕風度窗牖，蟋蟀催婦織。", "貧家一匹絹，已費幾蠶力。", "夫妻僅補綴，幸寬兒女責。", "復思後來事，對酒不能喫。", "人言有定數，禍福那可擇。", "胡爲自慘戚，三十頭雪白。"]'),
('f16d5926-7bb5-4a10-a2c5-0c5745d0d564','秋興  其二','蘇泂','宋','宋诗','song-poetry','','[]','貧居應閉門，原憲乃非病。',96,'全唐诗/poet.song.184000.json','["貧居應閉門，原憲乃非病。", "讀書到周孔，歲晚吾事竟。", "佳哉亦可樂，妙在得所性。", "於時俗慮少，魚鳥共涵泳。", "蘆花深兩槳，秋色滿湖鏡。", "頗懷梅子真，屢起泛舟興。", "明當文會友，聖處一參訂。", "此生飯不足，敢不聽於命。"]'),
('b85ef2ef-5c45-421d-b708-68be825a91a3','耕堂弟雪中效宛陵仄字平字詩各次韻一首  其一','蘇泂','宋','宋诗','song-poetry','','[]','旱澇數所繫，累歉望一稔。',48,'全唐诗/poet.song.184000.json','["旱澇數所繫，累歉望一稔。", "種秫秫不孕，酌水水可飲。", "甕牖忽碧玉，喜見月入枕。", "閉戶請謝客，是子亦太甚。"]'),
('e1fef657-ece5-4edc-8787-54bb81e74698','耕堂弟雪中效宛陵仄字平字詩各次韻一首  其二','蘇泂','宋','宋诗','song-poetry','','[]','山河無纖塵，遥觀浮漚如。',48,'全唐诗/poet.song.184000.json','["山河無纖塵，遥觀浮漚如。", "穿廬惟青天，油窗誰其糊。", "狂歌忘寒饑，消流驚須臾。", "煩呼瑶英徒，同來泠然居。"]'),
('ee2011a7-6a3e-4417-89fb-3db7da6eefb7','次邢兄韻簡李簡夫','蘇泂','宋','宋诗','song-poetry','','[]','幽花契幽禪，夷下難爲情。',48,'全唐诗/poet.song.184000.json','["幽花契幽禪，夷下難爲情。", "想見獅子床，天女問浄名。", "至味有不釀，大音本希聲。", "相逢寸紙間，公案今見成。"]'),
('27167c5f-0cc5-45e5-8bb9-c8647512e128','王千里得晉獻之保母碑及硯索詩','蘇泂','宋','宋诗','song-poetry','','[]','客從王家來，示我王家物。',168,'全唐诗/poet.song.184000.json','["客從王家來，示我王家物。", "云是彼樵者，墾山之所得。", "升沉有時節，至寶不浪出。", "祖先暨兒息，嗜好俱第一。", "青氈未渠失，近代無此筆。", "觀其逼人處，造次神品入。", "石遺半缺齧，行草百十七。", "昭陵不可及，季孟精爽集。", "天地倏開張，鬼神爲之泣。", "泓也玉璧姿，肯爲泥沙沒。", "嗚呼黄祊殉，人事止枯骨。", "臨池例飲墨，有底鵝領識。", "夫君矧其後，妙契過漂石。", "居然今視昔，年數正八百。"]'),
('185daf85-4fa8-4f64-b6fe-cd553d72242d','待潮通明詒友朋','蘇泂','宋','宋诗','song-poetry','','[]','子大瞻在前，德允瞠若後。',144,'全唐诗/poet.song.184000.json','["子大瞻在前，德允瞠若後。", "自予得二士，光彩生戶牖。", "向來九州內，所在兩脚走。", "相好亦已多，惟子共辰酉。", "老銛最可人，自謂禿非醜。", "南官棄之去，盧氏真傑斗。", "今朝通明埭，獨客對巵酒。", "追懷平昔意，幸不愧高厚。", "春江散烟露，春事紛花柳。", "問胡此淹留，書卷空在手。", "人生忌多情，所不忘朋友。", "南北與東西，同然一回首。"]'),
('8a2db13e-c711-4e59-8334-f30f1d300e90','送邢芻父赴漕試蓋予以牒遜之','蘇泂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江我之愁，倒嶽推不去。',144,'全唐诗/poet.song.184000.json','["長江我之愁，倒嶽推不去。", "琴瑟有凄怨，居室等行路。", "十三出從師，三十茲無成。", "向來爲何事，投老悲秋螢。", "堂堂文翰場，攘臂君甚武。", "丈夫貴高誼，我得寧在汝。", "達官總遺恨，所樂纔妻兒。", "君堂有夫人，祿養當以時。", "吳山青入天，江水流到海。", "才難嘆先聖，戰伐偶今代。", "四序看迭移，南薰已西風。", "天命不可爲，往哉及其鋒。"]'),
('bf8b9770-bc62-4951-b0a4-4f6cc073fce9','次韻芻父試罷有述','蘇泂','宋','宋诗','song-poetry','','[]','筆耕亦農耕，後種有先熟。',144,'全唐诗/poet.song.184000.json','["筆耕亦農耕，後種有先熟。", "穀終貴於稗，種詎不如稑。", "里門富驕兒，昨者車擊轂。", "一朝禍機至，悔不初碌碌。", "因而利生鈍，甚羨平爲福。", "翩翩歸來賦，寫壁仍畫軸。", "有來顧之唾，謂豈好題目。", "予方友鷗鷺，渠自行雁鶩。", "同參聽誰詣，勇往何待卜。", "君才十倍我，書已萬卷讀。", "邊頭尚征戰，時事非曩夙。", "雖遲劉蕡對，肯效包胥哭。"]'),
('9554f2f4-0f8d-43ee-8650-5717c42f5f57','次韻高秘書','蘇泂','宋','宋诗','song-poetry','','[]','高郎水江漢，波浪所從出。',144,'全唐诗/poet.song.184000.json','["高郎水江漢，波浪所從出。", "讀書識大體，於世無棄物。", "誰歟戒盈滿，視彼欹器側。", "如君執謙柄，我不能萬一。", "羣公石渠上，天子正側席。", "翻然侍親歸，袍茜髮黑漆。", "老仙顧之笑，吾與子居越。", "人生屈伸肘，猶動靜語默。", "非無鶴乘軒，亦有驥在櫪。", "忠當盡臣節，孝則共子職。", "煌煌周孔意，千古照簡冊。", "吾儕負君親，但守不黔突。"]'),
('d53b0313-8e6b-4022-8e9c-05f8513fe340','簡高秘書','蘇泂','宋','宋诗','song-poetry','','[]','昨日山中雲，今朝山下雨。',48,'全唐诗/poet.song.184000.json','["昨日山中雲，今朝山下雨。", "天時或定數，人事恐無據。", "蕭條吟梁父，士有遇不遇。", "不見龐德公，移家鹿門去。"]'),
('c0e8f193-a8dc-4d7e-8ef6-43c8f987e03b','坐睡','蘇泂','宋','宋诗','song-poetry','','[]','世事困纏糾，誰能復自然。',48,'全唐诗/poet.song.184000.json','["世事困纏糾，誰能復自然。", "看書得坐睡，此樂出於天。", "一適萬慮遠，重尋已非先。", "相逢問尊宿，會我無心禪。"]'),
('1465df2a-72f6-4810-861c-22cb37378652','梁湖','蘇泂','宋','宋诗','song-poetry','','[]','路長人迹少，日午樹陰正。',48,'全唐诗/poet.song.184000.json','["路長人迹少，日午樹陰正。", "茲行迺無故，解后得所性。", "佳眠離塵境，此事安心竟。", "晚飯過邑門，未害喧中靜。"]'),
('e1d801fc-48b1-4e15-826e-09c2cb34aac7','正月五日謁放翁留飲歡甚','蘇泂','宋','宋诗','song-poetry','','[]','若人大槐中，不作螻蟻夢。',144,'全唐诗/poet.song.184000.json','["若人大槐中，不作螻蟻夢。", "春風鬢鬚綠，文字凌屈宋。", "昨朝我訪之，杯酒頗自奉。", "魚蝦雜淮海，狼藉蔬果衆。", "妍譚到嘲謔，嘉我一笑共。", "末言神仙事，於世本無用。", "但可於世人，矯首飛鴻送。", "故公所言者，大抵靜觀動。", "胡能更八十，異日亦高冢。", "絕憐稽山下，不逐梅笋貢。", "堂前謾名龜，堂下或歌鳳。", "壽公晚唐衣，聊爲吾道重。"]'),
('9cb1d67f-e1d5-4f90-810a-6c92df28e75d','哭小姪梅老','蘇泂','宋','宋诗','song-poetry','','[]','我初養柏兒，年紀三十四。',240,'全唐诗/poet.song.184000.json','["我初養柏兒，年紀三十四。", "穎季得梅老，歲數適我類。", "而梅生不凡，頭骨甚磽異。", "見之懷抱中，宛有成人器。", "漆光眼目動，玉雪皮肉細。", "愛之甚於柏，稍長望其貴。", "每出偏問歸，祝父好看視。", "猶嫌礙關鑰，莫伴柏嬉戲。", "固嘗約而父，築室更隣位。", "請師共教授，兒姪精六藝。", "中年不如意，藉此期自慰。", "庶幾和仲老，他日遠虎侍。", "梅胡不佳實，飄謝許危脆。", "更醫再而三，歷齒一十二。", "留之苦不可，去我何乃易。", "而父真斷腸，汝伯重垂涕。", "爾梅竟何往，小槥但遺蛻。", "登槃莫薦子，登隴休折寄。", "云然我所傷，畏是爾名字。", "梅兮早歸來，尚作梅花弟。"]'),
('911667a2-cb7b-4d6d-9f9c-0318a45f7410','舉子','蘇泂','宋','宋诗','song-poetry','','[]','先親去無歸，家有十男子。',144,'全唐诗/poet.song.184000.json','["先親去無歸，家有十男子。", "春秋此堂上，拜起共祭祀。", "一貧乃青氈，書種幸未已。", "人言抱子晚，君已三十四。", "何時見入學，况未保齠稚。", "老年樹松柏，仁者用其意。", "父母養我時，辛勤五兄弟。", "蜂房今俯育，誰則逮菽水。", "昊天真罔極，夢想九原啟。", "恭惟父母心，敢不嗣遺體。", "平生忠與孝，舉動法經史。", "先訓吾所知，功名蓋天爾。"]'),
('4a292302-c587-4260-83a2-319f63b8d56e','魯墟行','蘇泂','宋','宋诗','song-poetry','','[]','今茲水用事，簷雨四十日。',276,'全唐诗/poet.song.184000.json','["今茲水用事，簷雨四十日。", "禱祈遍羣望，魚蟹入家宅。", "小民例煎迫，在在絕粒食。", "聖人制邦國，休養覬生活。", "本根者州縣，父母資牧伯。", "夫何失其理，致使爲盜賊。", "犯之復無赦，恐負天地德。", "昨來諸暨變，本以鹺故得。", "有司屢殺戮，勢欲與之敵。", "民生各良性，豈獨肆凶慝。", "饑寒迫於後，妻子時動色。", "那知刀鋸威，乃甚溝壑厄。", "市人起相戰，爭利初毆擊。", "吾非志剽掠，解后有其迹。", "王官亦人耳，聞此宜隠惻。", "不然罹憲網，無暇謀復出。", "嗚呼不得已，天下蓋非一。", "橫尸類雞狗，斬刈遽狼藉。", "頗聞動官軍，餘黨收捕急。", "儻非勸本務，有死民不易。", "是時天復雨，省宰到層畢。", "夫民使之飽，不飽亦吾匹。", "丁寧善其生，淚下死魂魄。"]'),
('fe15d25d-9edc-473d-aacb-1f69e0de7770','夜坐讀韋蘇州集序','蘇泂','宋','宋诗','song-poetry','','[]','茲辰孟春夕，芳意二分在。',144,'全唐诗/poet.song.184000.json','["茲辰孟春夕，芳意二分在。", "登臨愧成晚，倏忽朝晡改。", "樓欄带棲鳥，野色半蒼黛。", "花圍郡園夜，柳暗陂塘外。", "昏鐘四簷雨，懸燈澹予對。", "瓶梅書帙亂，茶樹窗紗礙。", "披文到韋集，神賞希唐代。", "爐烟起寂寞，至味久不壞。", "妻眠稚無擾，斯境非凡會。", "於時暫得我，真浄青蓮界。", "蚩蚩競物欲，宵寐猶憎愛。", "誰知屢空者，庶遠樊籠害。"]'),
('d7afe274-ea67-467e-b8e5-65e0798a85a3','春晚二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','春風爾狂顛，三月不知春。',48,'全唐诗/poet.song.184000.json','["春風爾狂顛，三月不知春。", "青青池上草，翻憶夢中人。", "幽蘭出磵谷，感此芳氣新。", "采采不盈掬，眼前但荆榛。"]'),
('6ff40358-d959-446f-8379-aea324bf6570','春晚二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','佳花有重秀，幽蘭徒自芳。',48,'全唐诗/poet.song.184000.json','["佳花有重秀，幽蘭徒自芳。", "姝媛被奇服，絲竹羅中堂。", "主人惜殘春，清夜未渠央。", "客子抱貞節，泯然獨升床。"]'),
('c6a6c410-a5c0-4462-9d2d-4e45a5779923','看雨','蘇泂','宋','宋诗','song-poetry','','[]','荒池三月雨，閑看水生文。',48,'全唐诗/poet.song.184000.json','["荒池三月雨，閑看水生文。", "客少苔上階，屋老樹遮門。", "幽心契子綦，隠几若忘言。", "鶑聲何從來，還思借宅聞。"]'),
('e77b2e2d-66b6-422c-8897-3320ee209108','山中雨','蘇泂','宋','宋诗','song-poetry','','[]','盈盈池上花，瑟瑟花下雨。',48,'全唐诗/poet.song.184000.json','["盈盈池上花，瑟瑟花下雨。", "雙雙蛺蝶伴，對對鴛鴦侶。", "池魚金作鱗，魚虎翠爲羽。", "兀坐一山春，山春愁獨語。"]'),
('bbfec78e-00bf-4b36-9197-f889164b2a19','走筆次韻芻父喜雨三首  其一','蘇泂','宋','宋诗','song-poetry','','[]','薰兮有南風，下此沛然雨。',48,'全唐诗/poet.song.184000.json','["薰兮有南風，下此沛然雨。", "皇天初震怒，盍燎緇黄侶。", "端來丹山鳳，况戢螽斯羽。", "君詩如民謠，能共天公語。"]'),
('052ff3aa-42a0-4d6b-87e6-79740ab5e722','走筆次韻芻父喜雨三首  其二','蘇泂','宋','宋诗','song-poetry','','[]','青天一聲雷，雲霧忽難開。',48,'全唐诗/poet.song.184000.json','["青天一聲雷，雲霧忽難開。", "此定時節至，何因禱祈來。", "客方聽簷溜，予亦倒殘杯。", "明朝浮舟楫，尚可看楊梅。"]'),
('81d7bf97-3f84-4793-9d74-7cdd59c89beb','走筆次韻芻父喜雨三首  其三','蘇泂','宋','宋诗','song-poetry','','[]','方池蔭垂柳，想見蘇公隄。',48,'全唐诗/poet.song.184000.json','["方池蔭垂柳，想見蘇公隄。", "一雨水入床，蛙部連東西。", "先生不能寐，書卷夜自迷。", "穉子黎明來，官路深尺泥。"]'),
('748eda64-aa80-4275-bf1f-63840e8d40a9','即席次韻景周梅花','蘇泂','宋','宋诗','song-poetry','','[]','魂來孤山青，夢破耶水碧。',120,'全唐诗/poet.song.184000.json','["魂來孤山青，夢破耶水碧。", "非兄孰知我，非我無此客。", "一枝霜雪後，坐斷春寂寂。", "平生桃李場，雖隣有不覿。", "人中具品藻，醖藉李太白。", "歲寒得佳尚，賢賢以易色。", "經年墮塵鞅，此士久乖隔。", "昌原弗相見，所謂順之逆。", "無詩可報答，大叫脫巾幘。", "疎花正點染，半蘂猶索摘。"]'),
('dc2332d9-e715-4f5c-8156-46d3c64b165a','有感','蘇泂','宋','宋诗','song-poetry','','[]','隆冬都門歸，偃息殊未嘗。',192,'全唐诗/poet.song.184000.json','["隆冬都門歸，偃息殊未嘗。", "搔頭不知痒，心事但荒荒。", "頻年借人居，主者來在堂。", "飄然十五口，露處悲風霜。", "而予行無從，寧如棄不將。", "安巢燕飛來，定穴魚蟄藏。", "天地非不寬，一身信難量。", "擾擾復擾擾，天子誅黠羌。", "區區復區區，早飯炊絕糧。", "庭闈蛻骨久，兄弟糊口忙。", "親戚亦豈無，所過門如湯。", "朋友非不多，熟視第感傷。", "欲生生無涯，欲死死無方。", "弱妻叫欲絕，三子病在床。", "汝哭亂我耳，汝痛割我腸。", "父母亦念我，陶山永相望。"]'),
('782914fb-d147-4ae7-bd58-36d8b3245b2f','次韻知縣兄夏夜古調','蘇泂','宋','宋诗','song-poetry','','[]','非禽胡能飛，羽翰上青霄。',132,'全唐诗/poet.song.184000.json','["非禽胡能飛，羽翰上青霄。", "非木胡能花，開謝隨驚飈。", "始予眷所生，於世免塵囂。", "頗知師甯蘧，貧樂富無驕。", "異哉肯顧我，古音日寥寥。", "介然守其業，彈琴自逍遥。", "採苡以永晨，芻藁以終宵。", "尚思舉斯人，還復淳其澆。", "言瞻彼穹矣，維斗南之杓。", "言瞻彼水矣，維海東之潮。", "慨然契薰兮，邈余逮虞姚。"]'),
('023dd831-a7c7-42da-8216-4caf0f8152d4','再和陶韻  其一','蘇泂','宋','宋诗','song-poetry','','[]','紛紛流俗間，哀此萬衆生。',108,'全唐诗/poet.song.184000.json','["紛紛流俗間，哀此萬衆生。", "陶翁蓋達士，酷愛重九名。", "行行步東皋，見菊眼爲明。", "色香不改舊，想像聞其聲。", "讙言各携袂，耄齒逮弱齡。", "屬予剛制酒，空杯與誰傾。", "凜然北窗下，清癯落驕榮。", "雲團煮風葉，競用招我情。", "醒醉未必爾，昭氏何虧成。"]'),
('82577f06-0588-4096-ac7e-2eac75784e96','再和陶韻  其二','蘇泂','宋','宋诗','song-poetry','','[]','賢達不遺世，後來肯下交。',96,'全唐诗/poet.song.184000.json','["賢達不遺世，後來肯下交。", "玄髮一以變，感此徂年凋。", "所懷寄絕俗，泰華未爲高。", "牛山縱尋斧，何時解干霄。", "仲尼聘列國，未覺歷日勞。", "古今君臣義，比干更茅焦。", "皇皇上天意，一物猶甄陶。", "清泉黄金花，庶矣饑渴朝。"]'),
('a9fa49c8-cef7-4b25-a761-923179a91518','邢兄招納凉大善以醉眠不及往大篇見嘲一筆走和','蘇泂','宋','宋诗','song-poetry','','[]','昨宵予不飲，月下看風生。',168,'全唐诗/poet.song.184000.json','["昨宵予不飲，月下看風生。", "不飲竟大奇，識此風月清。", "今宵予醉狂，醉眼仍看月。", "月落猶未醒，思與枕簟歇。", "從來清凉事，果爲獨士慳。", "良月如佳人，解后亦已難。", "月色政爾好，友生偶然來。", "此樂如此時，百歲能幾回。", "我眠不在枕，我醉不在杯。", "平明視鬢毛，定恐此物催。", "四十餘一年，侵尋行老景。", "人老欲何爲，此話當自領。", "大塊天地寬，酒泉歲月永。", "非醉復非眠，快活心下省。"]'),
('1929f836-037b-44ef-ac73-fd3dbbc1421e','梅翁所作無一絲勉强意亦和一首','蘇泂','宋','宋诗','song-poetry','','[]','達士養四體，受敵聽腹背。',48,'全唐诗/poet.song.184000.json','["達士養四體，受敵聽腹背。", "悉意萬卷讀，往昔若晤對。", "日者鬢髮改，自恨筆力退。", "得句造澹薄，是亦我所愛。"]'),
('3dc7bf62-fe69-45a6-abe4-e126086b927a','邢兄次韻再答之','蘇泂','宋','宋诗','song-poetry','','[]','紅塵欲欺人，甚欲出塵去。',144,'全唐诗/poet.song.184000.json','["紅塵欲欺人，甚欲出塵去。", "人生貴險艱，九折有夷路。", "學劍劍不就，學書書不成。", "春蠶裹於繭，腐草化爲螢。", "高明信天資，踸踔亦步武。", "同床有恩怨，當面分爾汝。", "疲容仰吾父，髫齓憐吾兒。", "傳衣與養菽，上下皆失時。", "杜甫西去秦，仲連東蹈海。", "富貴毋相忘，此意豈三代。", "惟君眼中人，多若古人風。", "贈君寶劍篇，謹勿傷其鋒。"]'),
('a173b795-66d2-4455-a772-6ab822252a6f','中秋','蘇泂','宋','宋诗','song-poetry','','[]','親朋關河闊，一歲幾合并。',144,'全唐诗/poet.song.184000.json','["親朋關河闊，一歲幾合并。", "回思十載我，大半短長亭。", "我髮日已白，我心日以驚。", "尚喜淡泊資，於世少經營。", "五日過三縣，山川知我情。", "吟詩自娛悅，俗子徒我評。", "憶我會心友，與我同死生。", "取我塵化衣，濯我滄浪清。", "我歸已數日，我友各有行。", "百川我友朋，五岳我弟兄。", "我酒難獨飲，我懷誰與傾。", "今夕我中秋，我自看月明。"]'),
('89639c63-809c-47db-9584-f9acba260527','自述一首','蘇泂','宋','宋诗','song-poetry','','[]','舂糧了朝炊，細大供十口。',168,'全唐诗/poet.song.184000.json','["舂糧了朝炊，細大供十口。", "身窮兩脚健，天意非汝厚。", "前年取荆釵，頗不窺戶牖。", "甘心似黔婁，習氣除夙有。", "今年長一女，自省稱父母。", "方其我少時，豈意今老醜。", "時平米穀賤，兄弟仍聚首。", "先人敝廬在，清話辰徂酉。", "盍簪到諸雛，千指諒非久。", "居然小世界，榮悴同一朽。", "去城不三里，經歲絕奔走。", "登門亦無賓，老樹堪尚友。", "青氈古家法，迍賤當自守。", "能甘此中泉，不飲富人酒。"]'),
('d751d635-2605-4357-b2d5-0b9ae1173708','咏草','蘇泂','宋','宋诗','song-poetry','','[]','芳草復芳草，青似青松樹。',36,'全唐诗/poet.song.184000.json','["芳草復芳草，青似青松樹。", "今年見汝黄，明年復如故。", "今來古往人，南北東西路。"]'),
('1a2345a2-a634-4a8c-a49e-4a5f28434ae0','白首','蘇泂','宋','宋诗','song-poetry','','[]','白首百歲期，青春三月暮。',36,'全唐诗/poet.song.184000.json','["白首百歲期，青春三月暮。", "荒凉雞下柵，寂寞鶑啼樹。", "山水越王城，行人雨中去。"]'),
('43baf691-d107-4aec-b4ae-857b02906f00','老杜浣花谿圖引','蘇泂','宋','宋诗','song-poetry','','[]','拾遺流落錦官城，故人作尹眼爲青。',240,'全唐诗/poet.song.184000.json','["拾遺流落錦官城，故人作尹眼爲青。", "碧雞坊西結茅屋，百花潭水濯冠纓。", "故衣未補新衣綻，空蟠胸中書萬卷。", "探奇欲度羲皇前，論詩未覺國風遠。", "干戈崢嶸暗宇縣，杜陵韋曲無難犬。", "老妻稚子具眼前，弟妹飄零不相見。", "此公樂易真可人，園翁溪友肯卜隣。", "隣家有酒邀皆去，得意魚鳥來相親。", "浣花酒船散車騎，野牆無主好桃李。", "宗文守家宗武扶，落日蹇馿馱醉起。", "願聞解鞍脫兜鍪，老儒不用千戶侯。", "中原未得平安報，醉裏眉攢萬國愁。", "生綃鋪牆粉墨落，平生忠義今寂寞。", "兒呼不蘇馿失脚，又恐新來有新作。", "常使詩人拜畫圖，煎膠續絃千古無。"]'),
('4bf03488-1977-4ec1-bc77-6bfedd0c9737','猛虎行','蘇泂','宋','宋诗','song-poetry','','[]','君不見蜀山之高直上登雲梯，草邊路側多少豹狼蹄。',247,'全唐诗/poet.song.184000.json','["君不見蜀山之高直上登雲梯，草邊路側多少豹狼蹄。", "盤龍山下三脚虎，震天一嘯回風低。", "橫拖騾馬捉豬犬，咆哮出入吁無時。", "有時人立作氣勢，團目金努矜毛皮。", "跳林越澗伏榛莽，亦挾一子携其妻。", "妻兒子母誰不愛，難以人肉賙其饑。", "好生之德乃天相，殺人正自人殺之。", "吁嗟此虎獨三足，明白罪狀人皆知。", "如何擊搏更不念，白晝坐使行人迷。", "昨宵風雨振林薄，颯沓萬仞千夫隨。", "一夫爭先探其穴，曳出斫死橋之西。", "寢皮食肉志不厭，亦戕其母烹其兒。", "初圖一虎得三虎，頓令此類無留威。", "何如千山盡勦絕，眼見蜀道都平夷。", "乃知强梁不足貴，人世豈得無危機。"]'),
('18233a6b-4813-42e2-9870-ebecaf61bd9f','予既賦金貂亭詩巽伯求益不已偶得名酒連飲輒醉隨意長哦忽數十句錄而成篇真醉漢口中語是可塞嚴命矣惜不令子大德允見之共一醉噱耳','蘇泂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','君不見陳留阮籍字嗣宗，竹林賢者渠稱雄。',387,'全唐诗/poet.song.184000.json','["君不見陳留阮籍字嗣宗，竹林賢者渠稱雄。", "登山臨水輒經日，竟用酣飲全其躬。", "謂渾汝不得復爾，獨善猶子曰仲容。", "以其任達似叔父，氣壓道北空多銅。", "宗人共集作圜坐，酌以大斗飛金鍾。", "著言君子處域內，何異羣蝨居褌中。", "形骸忽忘置不問，豈復上欲圖三公。", "古來賢達類若此，劉伶畢卓非凡庸。", "陶潜數酌宦情遠，李白一斗詩情通。", "彼胡不醒匪不智，智在意表言難窮。", "共惟遥集乃咸嗣，是飲三代傳家風。", "五馬渡江一馬龍，事未幾見嗟江東。", "就家拜爵下車去，摇手溫嶠吾誰從。", "京尹非才固所願，青山聽入明招終。", "所親相顧數在念，謂方醉耳何其聰。", "孫爲知幾翁遠識，信使日月垂虛空。", "山林鐘鼎不兩立，珥貂著屐將無同。", "解之換酒亦不惡，蠟以盛足誠爲工。", "古來醉人醉亦醒，後之醒者醒而聾。", "作亭縹緲山水勝，曳杖扶疎煙雨濛。", "長江爲杯斗爲杓，一飲天地生春紅。", "持杯却酹我遥集，籍咸墳土俱蒿蓬。", "步兵常侍本何物，目送千古歸飛鴻。", "我今與子生並世，得不痛沃崔嵬胸。"]'),
('d4998585-129f-4db8-af0d-b9012018388a','棲閑堂','蘇泂','宋','宋诗','song-poetry','','[]','紛紛世界多金寶，試覓一閑何處討。',322,'全唐诗/poet.song.184000.json','["紛紛世界多金寶，試覓一閑何處討。", "天公忌閑亦惜閑，似欲人人忙裏老。", "長安道上人如烟，信有陰陽錯昏曉。", "食升衣尺我類渠，玉带金魚爲誰好。", "上而公相下百官，鞅掌其身髮華皓。", "出臨民庶或愧色，歸對妻兒仍熱惱。", "農商工賈各有役，何况倡優及輿皂。", "豈如老龔縛屋看青山，賃地於鄰甘種稻。", "有男肯穫女習紡，布褐藜羹事翁媼。", "天憐老龔忙爲貧，報以一閑非草草。", "乃知富貴天不惜，閑處閑人古來少。", "問龔胡爲閑處棲，告以中恬外無擾。", "家傳古書數萬卷，充棟牙籤四圍繞。", "興來拈讀拂蠹魚，興盡留殘聽啼鳥。", "花陰坐久看日轉，葉徑行稀任風掃。", "問閑何味作何說，口不能言心自了。", "初從太白得微遇，晚向淵明飽問道。", "區區擬議已不閑，非作非休此其稍。", "我聞如是三嘆息，苦恨當年歸不早。", "閑中之味肯見分，亦欲誅茅鏡湖小。"]'),
('173a8170-d577-4058-90e5-d695b02bac66','餘姚江上作先寄城中親友','蘇泂','宋','宋诗','song-poetry','','[]','開禧改歲復崢嶸，老我奔馳不少寧。',128,'全唐诗/poet.song.184000.json','["開禧改歲復崢嶸，老我奔馳不少寧。", "雪花欺人入衣袂，前日杭州今四明。", "老來老來我何有，綠髮黄鬚行白首。", "魚鱗年紀今歲是，挽之不住去如走。", "挽君不住知奈何，叩篷擊楫聊高歌。", "天風爲拍雪爲舞，寒水自酌金叵羅。", "脚根萬里不作難，且喜看盡湖中山。", "明朝還舍託朋舊，尚有新詩三百首。"]'),
('18d311fc-341d-4e7c-bd1f-6dbff17ba8b2','春日懷詹梁','蘇泂','宋','宋诗','song-poetry','','[]','陳雷箭去不遺鏃，後世人情手翻覆。',320,'全唐诗/poet.song.184000.json','["陳雷箭去不遺鏃，後世人情手翻覆。", "我生二十少知己，更覺恩怨生骨肉。", "塵沙蹤跡窘吳越，波浪奔馳走巴蜀。", "癡年自長習藝能，如兔之角礙人目。", "相公清德照宇宙，萬物引領望鈞軸。", "平生出言謹許可，愛我重我過推轂。", "前回識得白石生，聞韶盡美一夔足。", "此公所向泯涇渭，於我底裏罄心腹。", "晨星在天萍在水，人生失意多戮辱。", "東歸窮巷口掛壁，豈無他人不如叔。", "邇來詹梁亦好事，頗復顧我青眼獨。", "吟詩造妙五七言，醜媚寒松倚新竹。", "時時敲門小童至，輟書倚火再三讀。", "亦思賡和禮所尚，疲駑鞭扑隨驥騄。", "歲寒相見願始終，且莫嗔怪屢更僕。", "吾儕豈圖偏黨異，俗子空猜往還熟。", "青春飛蓋城西園，畫鷁低飛鏡湖曲。", "杯行到手勿浪憂，世界堅牢等朝燭。", "詹梁長驅行秣駕，賤子終期老茅屋。", "他年官達請掉頭，莫笑渠儂甘碌碌。"]'),
('4884573b-f9d9-4c65-940f-1fd1ae485c80','次韻芻父大篇','蘇泂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我生兩脚半八區，歸來狹視東南隅。',203,'全唐诗/poet.song.184000.json','["我生兩脚半八區，歸來狹視東南隅。", "東南禹跡今綠蕪，百歲幾見人歐蘇。", "聞石藴玉川含珠，山乃秀潤源不枯。", "胸蟠萬卷味道腴，落紙所至雲錦鋪。", "爾來大似天眷吾，貺以佳友令相娛。", "邢子韻勝開冰壺，湘湖與我初索途。", "謂此巨浸其是歟，今夕不飲可得乎。", "吾儕固不如林逋，吟詩寫壁無處無。", "雜蓴便食不用厨，湘湖豈即輸西湖。", "貰錢沽酒勞老夫，酒酣肆筆衫袖烏。", "不覺月墮三更餘，荷香染袂露濕膚，開堂復駕紅塵車。", "君勿笑人生意氣傾堪輿，所得未必如所圖。"]'),
('7943b3e8-fd8e-42fc-8da2-6177a1b47a43','日鑄嶺下狂歌行','蘇泂','宋','宋诗','song-poetry','','[]','我生天地不如意，甚欲飄然去人世。',384,'全唐诗/poet.song.184000.json','["我生天地不如意，甚欲飄然去人世。", "却思一死胡足悲，死而不樂胡死爲。", "又思天地之間固有足樂者，安得莊周之鵬穆王馬。", "有時騎氣或御風，天上天中更天下。", "息駕玄冥圃，駐節蓬萊宮。", "攀星太極南，訪日扶桑東。", "東西南北何局促，自可直造混沌趨洪濛。", "又思去有歸，安得來無從。", "當時六鼇負亦重，豈有身常不轉動。", "會須四六二十四足一欠伸，我居其高視爾衆。", "不知化爲大海水，爲復茫茫而已矣。", "不知鼇在復鼇亡，爲復人生或人死。", "此時逍遥游，不見爭奪場，想見四維上下俱茫茫。", "巨鼇爾靈便如此，公欲欠伸不難耳。", "且如皇宋三百六十州，出門所在多山丘。", "其間平地少，但見蘿蔦藤蔓上下磽确森相樛。", "青鞋有底踏須破，人壽幾何行不休。", "更令生世人，偪仄生戈矛。", "迂迴隔絕千里成萬里，親戚朋舊相見朝夕無緣由。", "爾鼇若未動，爲我背略傾。", "颭翻山與丘，平地與人行。", "也知上天本來廣，也知下地本來平。", "只因山丘多，頓使天地輕。", "我當作章問帝借北斗，酌滄溟。"]'),
('3b98f594-56b8-4add-9a48-0d0515ab0c09','甘露歌上呈留守門下侍郎','蘇泂','宋','宋诗','song-poetry','','[]','太微淵默嚴不動，斗爲其車運中央。',154,'全唐诗/poet.song.184000.json','["太微淵默嚴不動，斗爲其車運中央。", "四序回旋變造化，一杓直指無偏傍。", "柄臣比之號八柱，一柱難闕各有當。", "紹熙元年圖舊德，更公玉麟使過國。", "屹然山立天子重，列作八柱扶天極。", "天極尊嚴物有道，不減不溢常不忒。", "均勞於外天闕柱，至今朝廷虛衮舄。", "皇皇辟君明如日，安用動威偃禾木。", "奉以甘露太和液，飲太液親壽益公，雖老歸致太平萬物好。"]'),
('7e16e8e0-53cd-4b68-b294-480b8a15eab1','書懷','蘇泂','宋','宋诗','song-poetry','','[]','出門莽莽無所適，青草門前少行客。',384,'全唐诗/poet.song.184000.json','["出門莽莽無所適，青草門前少行客。", "讀書妄意學周孔，行年三十頭雪白。", "朝廷伏聞治清靜，賤子何憂官得失。", "平生志氣渺江海，前日詩名漫梁益。", "相公青氈化烏有，大似不蒙稽古力。", "恭惟元祐全盛時，左右明王非列辟。", "爾時吾祖亦遭逢，曾與坡范同入直。", "同朝人士服該貫，後世儒生猶辟易。", "石羊去作高資夢，金榜空餘峴山宅。", "爛然朱紫照一門，綿亙百年隨社稷。", "中興郎從間有人，往往命薄中道塞。", "只今晨星頗相望，豈不稽首荷王澤。", "先人中間亦筮仕，曾未幾見捐祿食。", "坐令諸子各困頓，須與祖世事乖隔。", "忠肝痛膽欲誰付，冷屋風燈但蕭瑟。", "明知長短均一盡，自是炎凉心所惻。", "昨蒙宗公置牙齒，事下丞相當審覈。", "駑才不堪駕十乘，爝火或可繼殘夕。", "縱然得遂豈其志，未免妻嫂有輕色。", "諸兄生兒任門戶，兩弟行當問家室。", "祖宗祭祀足依頼，插架牙籤肯終畢。", "至尊恭己正南面，下採芻蕘及羣策。", "男兒努力要及時，致君堯舜收故物。", "春風吹花滿江城，醉擊珊瑚夜吹笛。"]'),
('69139e8c-bf58-4155-a9a3-c176b45a9f4d','青牛宮','蘇泂','宋','宋诗','song-poetry','','[]','青牛宮中青草生，數間老屋徒欹傾。',64,'全唐诗/poet.song.184000.json','["青牛宮中青草生，數間老屋徒欹傾。", "老人婆娑坐牛背，似怪關尹聞其名。", "東來萬里西遊客，倚遍宮前舊時柏。", "巫咸大招不可期，欲向青牛問消息。"]'),
('8f011290-e170-4171-8375-7cff34e4863a','再和古梅','蘇泂','宋','宋诗','song-poetry','','[]','和羹之說昔有聞，豈得不如魯泮芹。',160,'全唐诗/poet.song.184000.json','["和羹之說昔有聞，豈得不如魯泮芹。", "聞名尚救渴將軍，會稽竹箭胡能羣。", "初花的皪美無度，情事淡泊春空雲。", "樹猶如此人何堪，再三歎息殷仲文。", "江南晚生敬耆舊，汲水封植敢不勤。", "清霜既降河水涸，笑持雙鬢舉似君。", "人間凉燠易更變，有底寒谷回氤氳。", "神奇正爾出臭腐，枯木何怪生奇芬。", "諸生徑登李杜壇，此老行策伊傅勳。", "吾詩稱贊愧不足，舉止羞澀如羊欣。"]'),
('a6959462-554a-4bb2-92ca-1ef956b752f4','湘湖飲平遠亭口占呈邢芻父','蘇泂','宋','宋诗','song-poetry','','[]','我屐欲行山路遠，我舟欲泛湖水深。',64,'全唐诗/poet.song.184000.json','["我屐欲行山路遠，我舟欲泛湖水深。", "湘湖湘湖在何許，不在天上終可尋。", "君才未減邢居實，藥品之中貴參朮。", "君歸芹省我湘湖，夜看月明朝日出。"]'),
('910e9d25-8480-43e7-b709-278c948ccd11','又口占和林奇卿府教春日即事','蘇泂','宋','宋诗','song-poetry','','[]','門前車馬無行迹，堂上真重戴憑席。',128,'全唐诗/poet.song.184000.json','["門前車馬無行迹，堂上真重戴憑席。", "東風吹水綠芹香，課試公勤榜新拆。", "研經未羨陸德明，侯喜况有能詩聲。", "朝廷更化要三傑，聘幣應先魯兩生。", "休言三仕有三已，時節因緣還在是。", "滿園桃李競紛華，未害疎梅粲寒蘂。", "皇天著意生孔顔，一匙蔬飯宜加餐。", "渺然人物望公等，解后試挽唐虞還。"]'),
('a82480e7-26fb-48cd-aa9b-4f9264fb8405','金錯刀行','蘇泂','宋','宋诗','song-poetry','','[]','黄金錯刀白玉環，蘚花古血寒斑斑。',100,'全唐诗/poet.song.184000.json','["黄金錯刀白玉環，蘚花古血寒斑斑。", "皇天生物有深意，入樹伐石無堅頑。", "丈夫意氣豈兒女，事變虧成爭一縷。", "拔天動地風雨來，環響刀鳴夜飛去。", "世間萬事須乘時，古來失意多傷悲。", "嗚呼寶刀在手無能爲，不知去後鬰鬰令人思。"]'),
('1d85d3b4-faef-42df-af53-9c913f29ef07','次陸放翁韻','蘇泂','宋','宋诗','song-poetry','','[]','登高望遠不可無，不可一日不讀書。',64,'全唐诗/poet.song.184000.json','["登高望遠不可無，不可一日不讀書。", "予方自委下濕地，君乃獨占高明居。", "楊雲儻許客載酒，杜陵安得錢買馿。", "徐行過君就書讀，頗幸借屋今連閭。"]'),
('ecb5287f-7c96-4354-9ebe-fe6d4bfe03cf','送孟信州去矣行','蘇泂','宋','宋诗','song-poetry','','[]','青絲絡馬黄金羈，紫衣導從前驅馳。',96,'全唐诗/poet.song.184000.json','["青絲絡馬黄金羈，紫衣導從前驅馳。", "男兒四十作太守，路人指點生光輝。", "我時笑與路人說，太守襟懷世人別。", "平生爲政學魯論，愛民如兒少鞭撻。", "上饒之民吾賀君，君獨不見南安軍。", "是家官職未渠已，太后垂簾功蓋世。"]'),
('390c77f4-8179-446f-b0f1-c70ab89c897a','秋夜登湖橋','蘇泂','宋','宋诗','song-poetry','','[]','平湖秋水滿拍拍，恰好三月桃花春。',64,'全唐诗/poet.song.184000.json','["平湖秋水滿拍拍，恰好三月桃花春。", "所不同者一輪月，下上青鏡奩寒銀。", "我來跨湖橋頂坐，月照水光光照我。", "春暄那得抵秋清，自摘霜華餐露顆。"]'),
('df50f498-2d64-449d-b0cf-570e3f78d21e','聞鶑','蘇泂','宋','宋诗','song-poetry','','[]','東村水車聲未已，西村阿童喚牛起。',64,'全唐诗/poet.song.184000.json','["東村水車聲未已，西村阿童喚牛起。", "麥晴欲穩天更寒，霧雨蕭蕭熟梅子。", "讀書窗下少人知，綠陰幽草勝花時。", "一聲婭姹復婭姹，時有黄鸝來去飛。"]'),
('9673c9f0-aaaf-4fe9-b07e-14151a4d66e2','病中排悶','蘇泂','宋','宋诗','song-poetry','','[]','中年一病一回覺，老大康寧知更難。',64,'全唐诗/poet.song.184000.json','["中年一病一回覺，老大康寧知更難。", "只今四十已華髮，未到七旬應碧山。", "故疆風土望莫及，前輩典刑追不還。", "但願生生遇堯舜，耕田鑿井泰嵩間。"]'),
('1bba6db8-298d-4912-b000-c8683f713378','春日閑望','蘇泂','宋','宋诗','song-poetry','','[]','到處林園靜，能來是主人。',48,'全唐诗/poet.song.184000.json','["到處林園靜，能來是主人。", "鶑喉低囀玉，魚腹暖翻銀。", "翫雨沾芳履，吟風岸角巾。", "功名吾老矣，甘作太平民。"]'),
('201b0cd7-a095-4527-af52-fb68a0328696','次韻七首  其一','蘇泂','宋','宋诗','song-poetry','','[]','隠几看魚樂，洋洋圉圉然。',48,'全唐诗/poet.song.184000.json','["隠几看魚樂，洋洋圉圉然。", "一身隨見定，萬事任從前。", "賣劍更農服，操觚耨紙田。", "豈能無儉歲，固自有豐年。"]'),
('86c8850b-b785-4566-9bb6-943e7dbcd0bf','次韻七首  其二','蘇泂','宋','宋诗','song-poetry','','[]','步蹇堪扶杖，頭童欲罷簪。',48,'全唐诗/poet.song.184000.json','["步蹇堪扶杖，頭童欲罷簪。", "渚雲秋澹泊，庭樹晚蕭森。", "秀穎垂千畝，遥青出寸岑。", "本來關箇事，而獨可人心。"]'),
('51ed960f-ad35-4079-a252-0de3a69e2131','次韻七首  其三','蘇泂','宋','宋诗','song-poetry','','[]','昵愛經過數，尊榮記憶疎。',48,'全唐诗/poet.song.184000.json','["昵愛經過數，尊榮記憶疎。", "頼收顔氏帖，誰奉子公書。", "西夏方徵甲，東州且定居。", "雖無南過雁，幸有北來魚。"]'),
('9009413b-e7a7-46f0-a573-5149cd437ea4','次韻七首  其四','蘇泂','宋','宋诗','song-poetry','','[]','山色對疎櫺，之人一似清。',48,'全唐诗/poet.song.184000.json','["山色對疎櫺，之人一似清。", "水邊同婦飲，花下趁兒行。", "養鴨期充膳，騎牛學治生。", "時因把鋤暇，毋廢讀書聲。"]'),
('a8ee9701-31ae-4a8d-8735-c35ad1ec19b9','次韻七首  其五','蘇泂','宋','宋诗','song-poetry','','[]','香醪如蜜甜，村酒漸多添。',48,'全唐诗/poet.song.184000.json','["香醪如蜜甜，村酒漸多添。", "弄水閒移棹，看山自捲簾。", "深心非木石，癡腹慣虀鹽。", "莫作淵明解，逃魚本欲潛。"]'),
('5215d533-96ec-4eb2-9b65-373798a196c0','次韻七首  其六','蘇泂','宋','宋诗','song-poetry','','[]','茅茨依橘柚，鄰舍即烟波。',48,'全唐诗/poet.song.184000.json','["茅茨依橘柚，鄰舍即烟波。", "更與山爲伴，何憂屋不多。", "功名元有命，嗤笑亦從他。", "但願年年熟，杯來爾汝歌。"]'),
('00a3795a-c4bd-4eb9-b55f-318c08ef8fd0','次韻七首  其七','蘇泂','宋','宋诗','song-poetry','','[]','廢田爲屋宇，困士學農桑。',48,'全唐诗/poet.song.184000.json','["廢田爲屋宇，困士學農桑。", "來者或相問，耕焉安得堂。", "爲言吾欲醉，且去客無妨。", "信有癡人夢，寧甘草徑荒。"]'),
('67cfcc4b-439c-4aef-adfc-91204593aac1','一室','蘇泂','宋','宋诗','song-poetry','','[]','一室星辰入，平居社稷憂。',48,'全唐诗/poet.song.184000.json','["一室星辰入，平居社稷憂。", "螢飛原有夜，蟬遠不勝秋。", "短髮千方誤，中年萬事休。", "摩挲門外柳，坎止亦乘流。"]'),
('3a4305c4-6ca0-4c45-aa16-1e551e54752f','遣熱二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','人生萬家室，大暑亦勞勞。',48,'全唐诗/poet.song.184000.json','["人生萬家室，大暑亦勞勞。", "滴露點周易，臨風歌楚騷。", "朱丹誰復羨，斑白懶能薅。", "一笑問兒子，汝何催我曹。"]'),
('6ed5c781-d580-4b42-b4fd-8f27aa520610','遣熱二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','田舍東湖隔，樓居北戶升。',48,'全唐诗/poet.song.184000.json','["田舍東湖隔，樓居北戶升。", "感時秋鬢白，懷友晚山青。", "病不妨書讀，閒應養性靈。", "敝裘蘇季子，四海一飄萍。"]'),
('3f1b1e50-84bd-46d6-a7b7-1bcd632b7535','客夜','蘇泂','宋','宋诗','song-poetry','','[]','風雨夜冥冥，舟行爲小停。',48,'全唐诗/poet.song.184000.json','["風雨夜冥冥，舟行爲小停。", "野田藏水白，燐火出墳青。", "將子雁能急，久鰥魚獨醒。", "人生貴艱阻，稍向道塗經。"]'),
('685d126c-4159-4759-bb47-cf28e0fc67c5','歲杪','蘇泂','宋','宋诗','song-poetry','','[]','客子船都泊，幽人夜獨醒。',48,'全唐诗/poet.song.184000.json','["客子船都泊，幽人夜獨醒。", "五更初水長，四壁盡歌聲。", "已若從吾好，因之念此生。", "行年半七十，歲事復崢嶸。"]'),
('7e21647b-85b8-4fe6-a4c6-b3e76ae07ff9','舊歲','蘇泂','宋','宋诗','song-poetry','','[]','舊歲無多日，三衢有幾程。',48,'全唐诗/poet.song.184000.json','["舊歲無多日，三衢有幾程。", "雪簷疎滴滴，泉溜響泠泠。", "奔走經年債，襟懷一味清。", "紀行吟放穩，歸詠遣兒聽。"]'),
('4eb8441f-c69f-4bf7-b250-87959f9de94d','秋夜有感  其一','蘇泂','宋','宋诗','song-poetry','','[]','燈影三更夜，蟲聲四壁秋。',48,'全唐诗/poet.song.184000.json','["燈影三更夜，蟲聲四壁秋。", "雨階疎滴滴，風幔颯悠悠。", "朋友新凋喪，湖山舊釣游。", "平生匡復志，老去未能休。"]'),
('f5589505-f2c7-49e0-8afe-465560ae90ef','秋夜有感  其二','蘇泂','宋','宋诗','song-poetry','','[]','樓上幾當當，殘更引漏長。',48,'全唐诗/poet.song.184000.json','["樓上幾當當，殘更引漏長。", "月明山樹濕，露下藥苗香。", "朝野衣冠異，郊原故物傷。", "平生三徑草，此夕更蒼凉。"]'),
('422f9c18-512e-4c86-8fe2-c75c0e30da37','世事','蘇泂','宋','宋诗','song-poetry','','[]','世事一翻手，詩書三折肱。',48,'全唐诗/poet.song.184000.json','["世事一翻手，詩書三折肱。", "江湖多白雨，魂夢雜青燈。", "同好纔如此，言歸有未能。", "平生飛動意，元不羨鸇鷹。"]'),
('5d48f682-4151-4759-9a9e-16c2433068b5','書憤','蘇泂','宋','宋诗','song-poetry','','[]','黄葉冷颼颼，臨風搔白頭。',48,'全唐诗/poet.song.184000.json','["黄葉冷颼颼，臨風搔白頭。", "江湖無老伴，天地有新愁。", "橐禁行鴛曉，榆關戰馬秋。", "平生忠孝意，到死不能休。"]'),
('7da4d239-03de-4ebf-ab89-e895e272866b','琢句','蘇泂','宋','宋诗','song-poetry','','[]','琢句真無益，論詩新有名。',48,'全唐诗/poet.song.184000.json','["琢句真無益，論詩新有名。", "客懷無遠近，人事只翻騰。", "積水明寒樹，饑鴻咽夜聲。", "半年安坐得，又作雨中行。"]'),
('4486ac1e-6e35-4ffb-83cd-9ccab23a04d7','懷親堂','蘇泂','宋','宋诗','song-poetry','','[]','升堂知孝子，即事每思親。',48,'全唐诗/poet.song.184000.json','["升堂知孝子，即事每思親。", "根本由先世，栽培得後人。", "一林香自好，四序感如新。", "勿作商顔戀，家傳漢幄臣。"]'),
('245a8070-a5df-425d-91f9-a2b29186a16c','凉意','蘇泂','宋','宋诗','song-poetry','','[]','涼意滿中庭，乾坤洗濯清。',48,'全唐诗/poet.song.184000.json','["涼意滿中庭，乾坤洗濯清。", "鵲河通海浪，螢火亂天星。", "便覺黄花近，休看白髮生。", "客床眠不穩，起坐聽秋聲。"]'),
('06274ea7-c59f-43e3-bfdb-8f1d7102c1d6','仰屋','蘇泂','宋','宋诗','song-poetry','','[]','仰屋無窮事，甘心未遇時。',48,'全唐诗/poet.song.184000.json','["仰屋無窮事，甘心未遇時。", "雨花明燕羽，風葉墮蛛絲。", "農務從人說，光陰類箭移。", "早知霜白鬢，那免一生癡。"]'),
('ce29534a-e5f0-4bd2-a839-7643fe8cb4de','得屋後舟中作','蘇泂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','有屋吾堪老，無田子緩求。',48,'全唐诗/poet.song.184000.json','["有屋吾堪老，無田子緩求。", "長江惟可飲，萬事不須謀。", "政爾天從欲，端因鬼瞰憂。", "平生晏平仲，能費幾狐裘。"]'),
('9532dd6b-47d8-42f8-ab44-c61c2fb593f2','幽興','蘇泂','宋','宋诗','song-poetry','','[]','花氣濕書籤，琴風入畫簾。',48,'全唐诗/poet.song.184000.json','["花氣濕書籤，琴風入畫簾。", "綠陰連地黑，朱果落枝甜。", "客去從鸚語，人歸問鵲占。", "村居近城郭，幽興得相兼。"]'),
('06722fca-da22-4063-946c-1f785857ab3d','即事  其一','蘇泂','宋','宋诗','song-poetry','','[]','窗外梧桐樹，霜風特地吹。',48,'全唐诗/poet.song.184000.json','["窗外梧桐樹，霜風特地吹。", "莫輕初下葉，長別所生枝。", "便有青葱見，應無歲月追。", "先人移得汝，吾鬢復如絲。"]'),
('59fa30be-b896-4d2d-b227-5a8f72782f09','即事  其二','蘇泂','宋','宋诗','song-poetry','','[]','平生蘇季子，歲晚意何如。',48,'全唐诗/poet.song.184000.json','["平生蘇季子，歲晚意何如。", "收拾江湖夢，歸來田舍廬。", "耰鋤知力腐，書卷著饑驅。", "稍識瞿曇老，長思結習除。"]'),
('1911b611-391b-4393-b19d-5b27312d1770','即事  其三','蘇泂','宋','宋诗','song-poetry','','[]','羣雞紛啄粟，收斂逼深秋。',48,'全唐诗/poet.song.184000.json','["羣雞紛啄粟，收斂逼深秋。", "巷內黄葉落，門前清水流。", "年饑人菜色，家弊僕蓬頭。", "兼善平生志，凄凉出謬悠。"]'),
('4a8a945c-4e98-45c4-b820-df5a4f2bb533','有感','蘇泂','宋','宋诗','song-poetry','','[]','衆木曉森森，孤松自百尋。',48,'全唐诗/poet.song.184000.json','["衆木曉森森，孤松自百尋。", "絕知根氣大，能受雪霜深。", "草草供時役，悠悠匪力任。", "春風遍紅紫，啼鴂便驚心。"]'),
('27380507-ab93-46c4-82ef-f2de9fbee985','有歎  其一','蘇泂','宋','宋诗','song-poetry','','[]','古屋殘僧住，孤墳亂蟻穿。',48,'全唐诗/poet.song.184000.json','["古屋殘僧住，孤墳亂蟻穿。", "山稜人踏減，灘石浪搓圓。", "毀譽無終日，功名有百年。", "予方辜壯歲，渠得戀華顛。"]'),
('9fdaaa1c-c3bb-4b0c-b6f8-b20d29e2a8b5','有歎  其二','蘇泂','宋','宋诗','song-poetry','','[]','氣使與形驅，從知萬化渠。',48,'全唐诗/poet.song.184000.json','["氣使與形驅，從知萬化渠。", "參禪休佞佛，爲士盍忘書。", "枉鑄千金錯，終還一味愚。", "柴門老翁媼，圍坐却安居。"]'),
('ee492c0b-724d-48c9-a50d-1d9919e9f312','有歎  其三','蘇泂','宋','宋诗','song-poetry','','[]','杵臼梁鴻事，人間欠此人。',48,'全唐诗/poet.song.184000.json','["杵臼梁鴻事，人間欠此人。", "癡兒號飯少，愁婦厭家貧。", "雨障雪來晚，梅催柳迓春。", "平生兼善意，孤獨歎沉淪。"]'),
('6819aa96-ce74-4595-adbe-f92dd1663bfa','陶令','蘇泂','宋','宋诗','song-poetry','','[]','陶令歸來後，何人記若翁。',48,'全唐诗/poet.song.184000.json','["陶令歸來後，何人記若翁。", "難將五斗粟，換此一窗風。", "喜色均童稚，高情更菊松。", "悠然信天命，今昨定無同。"]'),
('5233d589-3923-4cef-8144-eabd2ff3a6c2','偶題','蘇泂','宋','宋诗','song-poetry','','[]','少壯憂藜藿，堆盤齒豁疎。',48,'全唐诗/poet.song.184000.json','["少壯憂藜藿，堆盤齒豁疎。", "平生空布褐，垂老賸金珠。", "世有伯勞燕，人誰熊掌魚。", "癡年將半百，撫事已嗟吁。"]'),
('760b09b8-6474-45a0-861a-511b64f26ece','偶作','蘇泂','宋','宋诗','song-poetry','','[]','盤薄意無窮，藏修一畝宮。',48,'全唐诗/poet.song.184000.json','["盤薄意無窮，藏修一畝宮。", "竹鳴知過雨，花動覺微風。", "閒作詩如畫，長思色是空。", "人言類摩詰，雖病有神通。"]'),
('55858286-4e26-490c-b6b8-911fdad2e594','夜讀老杜星月詩二十首','蘇泂','宋','宋诗','song-poetry','','[]','肺胃清如洗，翛然二十詩。',48,'全唐诗/poet.song.184000.json','["肺胃清如洗，翛然二十詩。", "月星連北斗，冰雪繞南枝。", "煮壑充茶椀，烹龍送酒巵。", "杜陵天上語，舉世幾人知。"]'),
('c5138d57-7907-4949-8bcc-63d92b8d6440','重憶舊句','蘇泂','宋','宋诗','song-poetry','','[]','太飽傷清氣，微寒最好詩。',48,'全唐诗/poet.song.184000.json','["太飽傷清氣，微寒最好詩。", "白鷗沒浩蕩，天馬謝羈維。", "矯矯真無敵，飄飄信所之。", "百年龍變化，萬事燕差池。"]'),
('64ee8f02-3de0-4c93-8cc9-93bcc914c1c4','予頃時有一聯云太飽傷清氣微寒最好詩葛天民極愛之偶再續成','蘇泂','宋','宋诗','song-poetry','','[]','太飽傷清氣，微寒最好詩。',48,'全唐诗/poet.song.184000.json','["太飽傷清氣，微寒最好詩。", "輕鷗憐野性，垂柳讓風姿。", "智巧從天賦，疎狂聽我爲。", "極知貧者病，未許藥能醫。"]'),
('825e5359-937d-4e13-81fe-92cdbe6939aa','無題','蘇泂','宋','宋诗','song-poetry','','[]','愛酒陶彭澤，能詩陳後山。',48,'全唐诗/poet.song.184000.json','["愛酒陶彭澤，能詩陳後山。", "浮沉將底用，長大若爲顔。", "鏡面舟一葉，梅邊屋數間。", "饒君雙鬢白，還我半生閒。"]'),
('6027b6d0-46c9-4b54-ab13-8b780989a8d2','得句  其一','蘇泂','宋','宋诗','song-poetry','','[]','存養龜傳息，扶行鶴類形。',48,'全唐诗/poet.song.184000.json','["存養龜傳息，扶行鶴類形。", "題詩窗紙白，住舍竹林青。", "食淡神偏爽，眠稀夢亦靈。", "從來知守分，真箇勝看經。"]'),
('4b802fe6-cb63-4b4d-991d-d46caf0eaeac','得句  其二','蘇泂','宋','宋诗','song-poetry','','[]','馬步山逾險，舟行水未通。',48,'全唐诗/poet.song.184000.json','["馬步山逾險，舟行水未通。", "馭風爲道號，嚙雪是家風。", "自許清如玉，從教臭似銅。", "人生幾兩屐，老去一飄蓬。"]'),
('4c337e9e-be55-4d67-a882-2fe259e3e09d','再次送芻父韻寄之二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','君到知何日，書來未可疎。',48,'全唐诗/poet.song.184000.json','["君到知何日，書來未可疎。", "旅情難是久，別意重於初。", "時暑方遵涉，齋居少自如。", "梁空明月夢，只有不關渠。"]'),
('6c6c24a4-d108-4029-95fe-6e55816cc112','再次送芻父韻寄之二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','當時馬首東，追送苦匆匆。',48,'全唐诗/poet.song.184000.json','["當時馬首東，追送苦匆匆。", "對我藕花雨，思君榕葉風。", "畏途迷白黑，醉眼眩青紅。", "曷日歸相問，江湖一釣翁。"]'),
('d970c2ee-4c13-40b0-b97e-bde48f9c3261','走筆次韻黄觀復學士二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','未見心先識，相逢意輒同。',48,'全唐诗/poet.song.184000.json','["未見心先識，相逢意輒同。", "半生纔得此，叔世若爲容。", "力學君方壯，緣愁我已翁。", "泥塗斷還往，信矣命之窮。"]'),
('f8cb685d-df31-4121-beee-c89daecb5fbe','走筆次韻黄觀復學士二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','自嘆馮唐老，那堪李廣奇。',48,'全唐诗/poet.song.184000.json','["自嘆馮唐老，那堪李廣奇。", "歲寒斯可矣，吾道竟何爲。", "麗日明桃葉，清風近竹枝。", "天機乃人事，到底孰成虧。"]'),
('4eb6780c-2167-4e25-aa0f-fdd82990c40f','見放翁退','蘇泂','宋','宋诗','song-poetry','','[]','住所真容膝，談間便解頤。',48,'全唐诗/poet.song.184000.json','["住所真容膝，談間便解頤。", "胡能萬事足，直作一生癡。", "密雨驚荷葉，微風吹竹枝。", "回舟吾自慊，應賦此翁詩。"]'),
('6c6eee94-28bd-4374-8553-299354c12174','次知縣兄韻','蘇泂','宋','宋诗','song-poetry','','[]','市少全依郭，人稀却似村。',48,'全唐诗/poet.song.184000.json','["市少全依郭，人稀却似村。", "湖山春氣早，烟雨畫圖昏。", "倚樹花微落，吟詩酒屢溫。", "親朋各南北，步屐款誰門。"]'),
('cb0b9ebf-5e4e-4cd5-b3f0-21be0c47e0dc','次韻葛天民','蘇泂','宋','宋诗','song-poetry','','[]','搗柏爲香炷，煎茶當酒杯。',48,'全唐诗/poet.song.184000.json','["搗柏爲香炷，煎茶當酒杯。", "鬢因兒女雪，心向利名灰。", "茅屋湖邊住，柴扉柳下開。", "殘年未歸去，排日爲公來。"]'),
('e691e3f9-b55a-4efb-adcb-674fc8204d73','簡寄','蘇泂','宋','宋诗','song-poetry','','[]','綠樹千家雜，青山四郭新。',48,'全唐诗/poet.song.184000.json','["綠樹千家雜，青山四郭新。", "須知太守印，合付謫仙人。", "波浪窺東海，樓居近北辰。", "不過行儉德，彼瘠本王臣。"]'),
('a7fdc6a0-f976-4614-af31-fb1f985a14e9','簡朱子大學士二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','亭上經秋宴，同鄉見亦難。',48,'全唐诗/poet.song.184000.json','["亭上經秋宴，同鄉見亦難。", "鬢從前度白，楓是此回丹。", "句法流傳否，交情寤寐間。", "重來興不盡，誰棹小舟還。"]'),
('9b67d586-3a19-4090-a959-a75cf68d1bd2','簡朱子大學士二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','人間三十六，曾未識朱園。',48,'全唐诗/poet.song.184000.json','["人間三十六，曾未識朱園。", "一昨袁絲飲，通宵謝屐痕。", "厨燈猶琢句，山雨未移樽。", "子大真吾敬，心期重款門。"]'),
('71426c7b-5646-4983-a689-6ab40a100ced','憶朱子大學士一首','蘇泂','宋','宋诗','song-poetry','','[]','翠麓晚蕭騷，無風樹亦號。',48,'全唐诗/poet.song.184000.json','["翠麓晚蕭騷，無風樹亦號。", "官榮歸若輩，詩態憶吾曹。", "信有憂能死，應無酒可陶。", "平生相照地，不隔半秋毫。"]'),
('b30695a7-d085-4cef-8cda-be733d754fc6','歸自陶山舟中示暹姪','蘇泂','宋','宋诗','song-poetry','','[]','鐘聲四山晚，一舸鏡中歸。',48,'全唐诗/poet.song.184000.json','["鐘聲四山晚，一舸鏡中歸。", "遠舍火明樹，寒天露濕衣。", "塔高城不禁，林暗鳥疇依。", "有句傳猶子，吾疎合世違。"]'),
('0ed5d1f8-ca66-4578-a912-e2b8b701e89b','憶黄觀復','蘇泂','宋','宋诗','song-poetry','','[]','地遠過從少，天多眼界寬。',48,'全唐诗/poet.song.184000.json','["地遠過從少，天多眼界寬。", "曉書繙卷白，秋桂繞亭丹。", "小雨妨相覓，幽花孰與看。", "平生杜陵老，到此賦詩難。"]'),
('5fbd4ce3-60c4-47fb-a505-71dda2f45704','陳杰荆州之役伯文實約予聞其沒官愴甚不寐遂成詩','蘇泂','宋','宋诗','song-poetry','','[]','細雨歸帆暮，西風遠笛哀。',48,'全唐诗/poet.song.184000.json','["細雨歸帆暮，西風遠笛哀。", "江空人永已，興盡首重回。", "嗣祖焉非福，王生本不來。", "從今長謝客，穩卧北山隈。"]'),
('b6beb7f4-d157-41ab-9655-e137a79bfbd2','紫芝申之有月夜賡唱俾予續之','蘇泂','宋','宋诗','song-poetry','','[]','樓高發興微，山水自清輝。',48,'全唐诗/poet.song.184000.json','["樓高發興微，山水自清輝。", "有月略窺枕，無風時動扉。", "他生嫌火食，投老羨空飛。", "安得余盧趙，相從去不歸。"]'),
('240f0278-166e-491b-897a-52ce48a67ecc','陪制帥寶學侍郎飲別金陵諸勝地','蘇泂','宋','宋诗','song-poetry','','[]','制閫三年名，亭臺一日違。',48,'全唐诗/poet.song.184000.json','["制閫三年名，亭臺一日違。", "江山雲外款，鼓吹月中歸。", "夜氣輕杯力，霜稜迫妓圍。", "明當趁朝謁，回首此依依。"]'),
('263b641c-498c-465d-a64d-1a5fd425e957','重送呂知錄表叔','蘇泂','宋','宋诗','song-poetry','','[]','別味中年畏，離筵近日頻。',48,'全唐诗/poet.song.184000.json','["別味中年畏，離筵近日頻。", "青山千騎遠，綠樹一蟬新。", "典獄須吾表，窮涯亦我民。", "時因過周守，相與話推仁。"]'),
('f49842d7-a7c5-4c34-8452-0e6d83145313','遠懷  其一','蘇泂','宋','宋诗','song-poetry','','[]','縹緲龍泉伯，人間第一流。',48,'全唐诗/poet.song.184000.json','["縹緲龍泉伯，人間第一流。", "胡然天下寶，只頓海東頭。", "斯道誰興廢，浮雲任去留。", "絕知他日少，預作百年憂。"]'),
('1c03b4f6-5a95-41cb-8913-ea7fc6abd52f','遠懷  其二','蘇泂','宋','宋诗','song-poetry','','[]','去國三千里，書來一再行。',48,'全唐诗/poet.song.184000.json','["去國三千里，書來一再行。", "過從應夙數，契闊更殊鄉。", "沙草留徐步，溪鷗傍晚凉。", "人間無限事，獨自有難忘。"]'),
('6f7320e1-d404-4deb-b189-28e7e6ca5cf6','次韻芻父秋懷  其一','蘇泂','宋','宋诗','song-poetry','','[]','髮短日益白，眼昏時見花。',48,'全唐诗/poet.song.184000.json','["髮短日益白，眼昏時見花。", "無人知若士，有句可雄誇。", "籬菊風前蕊，山梅雨後葩。", "平生蘇季子，猶足送年華。"]'),
('c4aa49a3-cbcf-4f56-b898-3ba1c5b82e88','次韻芻父秋懷  其二','蘇泂','宋','宋诗','song-poetry','','[]','幸免名爲累，應無口啟羞。',48,'全唐诗/poet.song.184000.json','["幸免名爲累，應無口啟羞。", "竺書時掛眼，衲被久蒙頭。", "未仕胡三已，論才宜四休。", "商宗如見夢，依舊濟川舟。"]'),
('18c647c3-19e3-4c82-89ba-17dbbe28142c','次韻芻父秋懷  其三','蘇泂','宋','宋诗','song-poetry','','[]','太史龜堂上，重來不忍看。',48,'全唐诗/poet.song.184000.json','["太史龜堂上，重來不忍看。", "更無時往復，徒有竹平安。", "世事翻仍覆，人情燠易寒。", "何時一樽酒，同訪小方干。"]'),
('c2c4aa25-e210-4686-82df-d9ab5b1edd01','次韻芻父秋懷  其四','蘇泂','宋','宋诗','song-poetry','','[]','逢人惟婞直，過事懶依阿。',48,'全唐诗/poet.song.184000.json','["逢人惟婞直，過事懶依阿。", "菊引陶彭澤，鳶驚馬伏波。", "衰年如意少，行路得詩多。", "彼其皆車服，嗟嗟如命何。"]'),
('2d99b245-2016-4fc3-9834-2ceb1a8ee64d','次韻芻父秋懷  其五','蘇泂','宋','宋诗','song-poetry','','[]','士有修身者，娟如女在房。',48,'全唐诗/poet.song.184000.json','["士有修身者，娟如女在房。", "刈蘭供作佩，採菊當爲糧。", "春樹翻疑雨，秋花却耐霜。", "從來輿涉意，晚棹轉微茫。"]'),
('3201584b-619e-4646-8bac-42fbba7809cd','次韻芻父秋懷  其六','蘇泂','宋','宋诗','song-poetry','','[]','四十纔如此，將來事可吁。',48,'全唐诗/poet.song.184000.json','["四十纔如此，將來事可吁。", "長齋甘短褐，舊債壓新租。", "已覺身何有，行當夢亦無。", "茅簷負朝日，黄卷足相娛。"]'),
('e0f7e8a4-cafb-4102-98ee-6fd1d94b7671','陋室詩','蘇泂','宋','宋诗','song-poetry','','[]','陋室行蝸子，良朋斷馬蹤。',48,'全唐诗/poet.song.184000.json','["陋室行蝸子，良朋斷馬蹤。", "一官當面過，萬事轉頭空。", "故有詩驅瘧，那無檄愈風。", "豐年仍儉食，歲晚得途窮。"]'),
('93a6da8b-3d2c-4694-a3c4-c0eccac2b49e','即席呈趙大資','蘇泂','宋','宋诗','song-poetry','','[]','裴公非綠野，白傅喜青山。',48,'全唐诗/poet.song.184000.json','["裴公非綠野，白傅喜青山。", "富貴何如老，功名不似閒。", "半生知己地，每見立談間。", "歲歲須來省，從教載雪還。"]'),
('97bd2511-31f0-48b6-83ac-f133a7596b7d','寄衛太常二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','道義分明重，功名取次休。',48,'全唐诗/poet.song.184000.json','["道義分明重，功名取次休。", "重來踏龍尾，猶記立螭頭。", "行輩雲霄上，家山歲月周。", "孰知爲郡樂，未慊過都留。"]'),
('dea3330a-e20f-4b95-9106-5b186aed0fe4','寄衛太常二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','祖世多生契，門牆半面人。',48,'全唐诗/poet.song.184000.json','["祖世多生契，門牆半面人。", "若爲資巨嶽，不敢望洪鈞。", "千載今如此，諸公迹易陳。", "江河須到海，松柏不勝春。"]'),
('a21f474d-01fa-41f5-b97d-5e863c45dd5b','寄盧子高二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','我別君逾壯，君來我欲翁。',48,'全唐诗/poet.song.184000.json','["我別君逾壯，君來我欲翁。", "艱虞疇昔異，風雨數宵同。", "鶴病祇應瘦，鷹饑怕苦籠。", "平生黄叔度，見可俗塵空。"]'),
('dddeeeea-96e3-4d7b-93ab-8302e7b05006','寄盧子高二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','君行甫郭門，我病已昏昏。',48,'全唐诗/poet.song.184000.json','["君行甫郭門，我病已昏昏。", "嘔泄輒經日，芳薌空屢飱。", "每思今古易，終畏別離煩。", "向匪勤車馬，何因共一尊。"]'),
('fff083ac-81cd-4982-a616-4c7784e39fc7','問訊知府高校書','蘇泂','宋','宋诗','song-poetry','','[]','爲問高夫子，朱黄想校書。',48,'全唐诗/poet.song.184000.json','["爲問高夫子，朱黄想校書。", "有詩連日有，無訊十分無。", "月淡梅行色，窗寒竹寄居。", "惟應牙痛愈，列屋任閒渠。"]'),
('f1b46d26-0754-47e3-847e-822d29b97433','次韻高秘書謁陸待制二首  其一','蘇泂','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','人物推前輩，聲名重泰山。',48,'全唐诗/poet.song.184000.json','["人物推前輩，聲名重泰山。", "斯文無毀譽，吾道有間關。", "袖短方妍舞，弓强愧力彎。", "風舟雖屢引，中路忍追還。"]'),
('74764bb3-2489-41f6-8540-b5d700c933b0','次韻高秘書謁陸待制二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','海上三神宅，人間陸放翁。',48,'全唐诗/poet.song.184000.json','["海上三神宅，人間陸放翁。", "談諧詩雅詠，任己易屯蒙。", "松竹當姬侍，鷗禽是僕童。", "後來那可計，應有不如公。"]'),
('7b9760f6-1ce8-4903-a7ed-48274e3c164d','東墅次高秘書韻','蘇泂','宋','宋诗','song-poetry','','[]','累土就川池，蜋蟬半黠癡。',48,'全唐诗/poet.song.184000.json','["累土就川池，蜋蟬半黠癡。", "神僊愚谷賦，圖畫史君詩。", "石磴春風酒，松窗夜雨棋。", "仲謀真有子，㹠犬定吾兒。"]'),
('dcf738b0-30af-4382-a0ce-bb2edee815b5','與趙監簿','蘇泂','宋','宋诗','song-poetry','','[]','昔我離家日，今皇即位年。',48,'全唐诗/poet.song.184000.json','["昔我離家日，今皇即位年。", "同時辭北極，共載入西川。", "雪裏賡詩句，江邊醉酒船。", "重來一訪舊，風景故依然。"]'),
('f72d6b04-e643-4aec-aa5e-90b256db6389','足姜句','蘇泂','宋','宋诗','song-poetry','','[]','那知身百歲，未辦屋三間。',48,'全唐诗/poet.song.184000.json','["那知身百歲，未辦屋三間。", "見客慵開口，逢僧託買山。", "喜無他志願，幸不碍清閒。", "社燕秋鴻裏，人生各有還。"]'),
('5dc94d5e-3651-4ea1-a360-86b595e64ac3','次知縣兄曹娥渡句','蘇泂','宋','宋诗','song-poetry','','[]','自絕雙魚養，愁登老檜亭。',48,'全唐诗/poet.song.184000.json','["自絕雙魚養，愁登老檜亭。", "斷雲知意緒，流水付年齡。", "撫穉頭空白，逢人眼未青。", "貪生不既晚，無地學威靈。"]'),
('9dfaa59c-054f-432b-90e4-2325b2e6651a','五次韻送蹈中造朝','蘇泂','宋','宋诗','song-poetry','','[]','鏡曲春帆遠，延和曉仗穿。',48,'全唐诗/poet.song.184000.json','["鏡曲春帆遠，延和曉仗穿。", "已更新歷日，休問小行年。", "用我書三篋，從渠食萬錢。", "功名今古意，留眼看蒼天。"]'),
('5faf3694-2c92-4d76-8350-20388a046ab0','問訊耕堂','蘇泂','宋','宋诗','song-poetry','','[]','五更三尺雪，應是沒耕廬。',48,'全唐诗/poet.song.184000.json','["五更三尺雪，應是沒耕廬。", "洞徹八窗景，泓澄一腹書。", "卧看龍夭矯，閒翫玉模糊。", "差勝陳家否，妻兒共擁爐。"]'),
('2fda5b12-7290-4750-a518-f5e480c56579','寄趙紫芝','蘇泂','宋','宋诗','song-poetry','','[]','同年今半百，同病半年賒。',48,'全唐诗/poet.song.184000.json','["同年今半百，同病半年賒。", "瘦骨如枯木，殘身類晚花。", "人言關念慮，書字覺欹斜。", "且願逢靈藥，清吟老鬢華。"]'),
('dfefbd86-e984-4bb0-ba52-e6d41d6169ba','寄周晉仙','蘇泂','宋','宋诗','song-poetry','','[]','四海周風子，推敲孰似渠。',48,'全唐诗/poet.song.184000.json','["四海周風子，推敲孰似渠。", "官應憎骨相，老不上髭鬚。", "醉帽欹花落，吟身信杖扶。", "相思不相見，梅樹雨鳩呼。"]'),
('4fe51807-14fa-4451-bf45-262a8259effb','見子大後寄','蘇泂','宋','宋诗','song-poetry','','[]','相過自一奇，歸去復相思。',48,'全唐诗/poet.song.184000.json','["相過自一奇，歸去復相思。", "柳上已春意，屏間如杜詩。", "山川佳甚處，人物眇然時。", "愛重非金玉，微君不我知。"]'),
('cecf80aa-c0d6-4d73-9d27-be18c3053b22','寄常山晉叟兄','蘇泂','宋','宋诗','song-poetry','','[]','行人有公論，知縣得奇才。',48,'全唐诗/poet.song.184000.json','["行人有公論，知縣得奇才。", "祖世今衰矣，吾兄亦壯哉。", "可能千里到，不破一朝來。", "當日王猷興，真成訪戴回。"]'),
('2c5e9ff2-4050-41ac-8812-6346c98cbf1e','代書寄應之舅','蘇泂','宋','宋诗','song-poetry','','[]','故人天一方，鴻雁已南翔。',48,'全唐诗/poet.song.184000.json','["故人天一方，鴻雁已南翔。", "世亂各生死，年饑無稻粱。", "丁寧機上錦，愛惜橐中裝。", "莫作孤飛想，冥冥忌弋傷。"]'),
('295e7140-76ce-4623-b234-baf1c1e0895d','寄潁季','蘇泂','宋','宋诗','song-poetry','','[]','人來得一書，分袂兩旬餘。',48,'全唐诗/poet.song.184000.json','["人來得一書，分袂兩旬餘。", "未擉劉差鱉，誰羹宋嫂魚。", "時情分向背，同氣底親疎。", "想見迎長節，杯行會憶渠。"]'),
('f0cd6153-8138-4aa7-81dc-1536d81a6dc9','代書寄趙處州公甫','蘇泂','宋','宋诗','song-poetry','','[]','苕霅無來使，如今又幾時。',48,'全唐诗/poet.song.184000.json','["苕霅無來使，如今又幾時。", "案餘分惠筆，室有寄來詩。", "豁達偏憐我，風流更許誰。", "懷哉括蒼小，安用借留爲。"]'),
('112cfea0-281a-4d0e-8815-44446db26dce','因會薛船官寄子高','蘇泂','宋','宋诗','song-poetry','','[]','昔忝盧郎舊，因尋薛子舒。',48,'全唐诗/poet.song.184000.json','["昔忝盧郎舊，因尋薛子舒。", "淺交初未愜，重見極相於。", "嗜好三人共，參商十載餘。", "長安燈月酒，吾與汝憐渠。"]'),
('96d755e9-6054-4682-9b48-72a4b21c13e5','先寄觀復','蘇泂','宋','宋诗','song-poetry','','[]','老去真無幾，爲官又不成。',48,'全唐诗/poet.song.184000.json','["老去真無幾，爲官又不成。", "慇懃驅病體，端的爲交情。", "人以風姿勝，梅將雪意爭。", "知君定懷我，株坐或遐征。"]'),
('f20ed08f-897e-41e7-9039-053cd913dcea','送錢子望','蘇泂','宋','宋诗','song-poetry','','[]','才名富有餘，揮袂別鄉閭。',48,'全唐诗/poet.song.184000.json','["才名富有餘，揮袂別鄉閭。", "小作經年計，輕賫一束書。", "州城蕉葉暗，驛路菊花疎。", "尚想南來使，時因問起居。"]'),
('d4e7c978-f18f-4b69-a7e1-d0e57021f99b','送陳永康昌年','蘇泂','宋','宋诗','song-poetry','','[]','公不登臺省，猶宜立內朝。',48,'全唐诗/poet.song.184000.json','["公不登臺省，猶宜立內朝。", "如何百里縣，更以一身遥。", "俗悍須寬理，年豐在政調。", "清秋送卓茂，目斷馬蕭蕭。"]'),
('f1336f6d-6919-45b0-a2dd-6d6d82d90bb5','送趙蹈中府簽對策大廷','蘇泂','宋','宋诗','song-poetry','','[]','奧學通玄象，須時對廣廷。',48,'全唐诗/poet.song.184000.json','["奧學通玄象，須時對廣廷。", "端爲賈生策，動合聖人經。", "事往誰謀始，時今未敉寧。", "因留非所志，君相眼終青。"]'),
('d3efefc3-c02a-4581-b44d-51ff2f2f9620','壽暹姪','蘇泂','宋','宋诗','song-poetry','','[]','行年過二十，不可恃青春。',48,'全唐诗/poet.song.184000.json','["行年過二十，不可恃青春。", "再此爲中宿，三之即老人。", "詩書先足己，壽祿後榮親。", "當日癡頑叔，從師霅水濱。"]'),
('b464d358-7609-425e-814b-c316a75113a8','贈暹姪','蘇泂','宋','宋诗','song-poetry','','[]','祖世青氈遠，關門鬢欲絲。',48,'全唐诗/poet.song.184000.json','["祖世青氈遠，關門鬢欲絲。", "猶欣諸子姪，愛覓老夫詩。", "貧賤端由此，文章安用爲。", "勉哉勤所業，須有中興時。"]'),
('aa351226-bb98-480c-9727-3dcc1b489f0b','思故人','蘇泂','宋','宋诗','song-poetry','','[]','故人不可見，書札報平安。',48,'全唐诗/poet.song.184000.json','["故人不可見，書札報平安。", "黄菊誰能折，青山獨自看。", "雨生南浦足，秋入五湖寬。", "歲晚無多事，相看把釣竿。"]'),
('deb91605-656d-4618-b0c1-50fcc649cb57','感舊  其一','蘇泂','宋','宋诗','song-poetry','','[]','連年走巴蜀，性命實如絲。',48,'全唐诗/poet.song.184000.json','["連年走巴蜀，性命實如絲。", "去有身將影，歸無父惜兒。", "車馳遭虎豹，水宿伴蛟螭。", "少待波瀾闊，須吟憶昔詩。"]'),
('5a058c99-a2a7-40f2-9c20-9e18f4e298a7','感舊  其二','蘇泂','宋','宋诗','song-poetry','','[]','荆州若箇伴，錦水暮雲深。',48,'全唐诗/poet.song.184000.json','["荆州若箇伴，錦水暮雲深。", "萬里元無事，一生長苦心。", "秋林猿弔影，春殿鳥遺音。", "尚喜身强健，幽期或重尋。"]'),
('84cf7c63-e47b-4525-9f9e-c9fa9ce1c0bf','復簡蹈中','蘇泂','宋','宋诗','song-poetry','','[]','庭樹風吹盡，池荷雨滴穿。',48,'全唐诗/poet.song.184000.json','["庭樹風吹盡，池荷雨滴穿。", "病身能幾日，短褐過殘年。", "摘藁有千首，看囊無一錢。", "雞號喚清曉，惜許夢鈞天。"]'),
('cc07a752-359e-493e-9dc4-37a9ae4b2127','簡德允','蘇泂','宋','宋诗','song-poetry','','[]','言歸四十日，兩度得尋君。',48,'全唐诗/poet.song.184000.json','["言歸四十日，兩度得尋君。", "貧病有諸子，情懷無半分。", "梅花年後雪，雁翅屋東雲。", "早晚扁舟興，能來與細論。"]'),
('1b542386-1924-4e06-9f91-7509e5d4f5a2','簡紫芝','蘇泂','宋','宋诗','song-poetry','','[]','一隻林家鶴，饒君骨更清。',48,'全唐诗/poet.song.184000.json','["一隻林家鶴，饒君骨更清。", "愛山幾廢日，琢句恐傷名。", "稍得湖邊住，常來寺裏行。", "相逢怪相喜，同病又同庚。"]'),
('6375b1ea-db27-484a-8a5b-85dab28b85ea','哭邢芻父六首  其一','蘇泂','宋','宋诗','song-poetry','','[]','頤養花能秀，謙卑玉似溫。',48,'全唐诗/poet.song.184000.json','["頤養花能秀，謙卑玉似溫。", "當家衣鉢受，外氏典型存。", "逸驥方開路，歸雲遽斂昏。", "胸中何事了，地下與誰論。"]'),
('0d101aa4-2fd2-40a1-a212-9ca4d94b490d','哭邢芻父六首  其二','蘇泂','宋','宋诗','song-poetry','','[]','未晬俄孤子，垂髫便俊聲。',48,'全唐诗/poet.song.184000.json','["未晬俄孤子，垂髫便俊聲。", "深知表獨立，敢謂竟無成。", "嗜好惟經史，情親到友生。", "回看真夢幻，未必泯神明。"]'),
('ead3eae6-33d8-4733-8290-1faf3d67df09','哭邢芻父六首  其三','蘇泂','宋','宋诗','song-poetry','','[]','江漢淵流遠，芝蘭雅韻深。',48,'全唐诗/poet.song.184000.json','["江漢淵流遠，芝蘭雅韻深。", "規行真畏友，莊語賸閑心。", "未悉昭昭理，長懷秩秩音。", "且隨賢父窆，應伴放翁吟。"]'),
('8e3463c9-cd76-4418-a120-881fe306b9d4','哭邢芻父六首  其四','蘇泂','宋','宋诗','song-poetry','','[]','在昔呻吟作，於今族姓無。',48,'全唐诗/poet.song.184000.json','["在昔呻吟作，於今族姓無。", "致身胡不可，得壽有相須。", "鬼魅資强黠，乾坤惡好儒。", "黄陳諸老淚，何獨爲惇夫。"]'),
('4e319293-e6ca-4e05-a531-88e166d14945','哭邢芻父六首  其五','蘇泂','宋','宋诗','song-poetry','','[]','慟哭叫蒼天，其如手足然。',48,'全唐诗/poet.song.184000.json','["慟哭叫蒼天，其如手足然。", "幾年能爾熟，一日棄予先。", "委翰愁胠篋，賡詩歎絕絃。", "求兒方畫褓，有母况華顛。"]'),
('11aeb8fb-32d1-45d4-8d83-6d661affd790','哭邢芻父六首  其六','蘇泂','宋','宋诗','song-poetry','','[]','太學三旬食，邢家萬事空。',48,'全唐诗/poet.song.184000.json','["太學三旬食，邢家萬事空。", "初頭纔過我，半後已無公。", "惚恍扶床語，倉皇就木終。", "從今顔巷冷，寧復孔尊同。"]'),
('aeed078c-53e4-47d3-bf35-d2d4303b868c','再省剡姊','蘇泂','宋','宋诗','song-poetry','','[]','短景催長至，冬溫爲小春。',48,'全唐诗/poet.song.184000.json','["短景催長至，冬溫爲小春。", "昔遊今更省，母逝姊爲親。", "風木悲吟楚，晴沙巧籀秦。", "扁舟君莫羨，未必自由身。"]'),
('e8e4735d-c62d-47b7-b574-2898a380202b','足疾數日簡潁弟','蘇泂','宋','宋诗','song-poetry','','[]','病脚冬逾甚，羈懷老自驚。',48,'全唐诗/poet.song.184000.json','["病脚冬逾甚，羈懷老自驚。", "生前終有役，隠去更須名。", "褐短愁紉婦，文疎愧屬兄。", "何時了婚嫁，一意學躬耕。"]'),
('7e7c144a-4b64-42cf-929e-96e2726d4851','簡趙紫芝','蘇泂','宋','宋诗','song-poetry','','[]','別久似相忘，因行遇道傍。',48,'全唐诗/poet.song.184000.json','["別久似相忘，因行遇道傍。", "問知元姓字，傳讀是文章。", "鶴骨秋逾瘦，松身老更長。", "十年猶九品，如我合耕桑。"]'),
('2a2d45cc-2227-4a17-8133-38755d94df27','壽潁季','蘇泂','宋','宋诗','song-poetry','','[]','有屋須生子，爲家要及時。',48,'全唐诗/poet.song.184000.json','["有屋須生子，爲家要及時。", "雲山千態度，弓冶幾書詩。", "壽日能佳事，秋風况捷期。", "長年一杯酒，吾與菊花知。"]'),
('65a7b71d-307d-4387-8d37-efa2f07193f0','除夕呈主人','蘇泂','宋','宋诗','song-poetry','','[]','使節梅花外，椒盤淚眼邊。',48,'全唐诗/poet.song.184000.json','["使節梅花外，椒盤淚眼邊。", "山川非故國，笳皷咽新年。", "機事鷗偏覺，家書雁不傳。", "細箋今夕恨，萬一主人憐。"]'),
('285e85af-0e99-4f1d-ac00-d9230bfa02a3','送觀復機宜榮侍南遊二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','友誼平生少，心期遠近同。',48,'全唐诗/poet.song.184000.json','["友誼平生少，心期遠近同。", "略無時俗氣，信有古人風。", "幾諫知吾子，忠言在若翁。", "南州須趣召，先寄狀元紅。"]'),
('39e14c2e-4e02-4cd5-8c8a-edb0145ccb45','送觀復機宜榮侍南遊二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','命拙仍多故，君來每慰情。',48,'全唐诗/poet.song.184000.json','["命拙仍多故，君來每慰情。", "艱虞還儉歲，文字久寒盟。", "又作家山別，寬爲數月程。", "閑門閉蕭瑟，病眼向誰明。"]'),
('df7963dc-f71e-4288-a083-e929e8375c30','十二月二十八夜至此悵然繼和','蘇泂','宋','宋诗','song-poetry','','[]','病馬猶依櫪，饑鴻更著行。',48,'全唐诗/poet.song.184000.json','["病馬猶依櫪，饑鴻更著行。", "深宵風雨後，萬里道途長。", "骨立難看鏡，愁來怕舉觴。", "少年輕聚散，曾笑客思鄉。"]'),
('5472a023-c12d-4b68-9974-32670fdd3019','重哭周四','蘇泂','宋','宋诗','song-poetry','','[]','甫讀宗周挽，那知遽絕絃。',48,'全唐诗/poet.song.184000.json','["甫讀宗周挽，那知遽絕絃。", "所嗟無我輩，不獨在詩篇。", "行到水窮處，魂傷山寂然。", "灰寒空酹酒，慟哭向蒼天。"]'),
('e03feee6-1037-4a90-8076-ec881b9e5c04','二十三弟喪偶慰之','蘇泂','宋','宋诗','song-poetry','','[]','汝婦真良偶，吾家無間言。',48,'全唐诗/poet.song.184000.json','["汝婦真良偶，吾家無間言。", "生來諸澹泊，奪去幾煩冤。", "室想羸鰥慕，牀餘稚乳存。", "羈遊違一奠，何日送丘原。"]'),
('981ec1cb-2cd9-4f83-8c62-187a670fe886','挽故開府節使觀文趙公二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','杵臼孤無食，詩書卒致身。',48,'全唐诗/poet.song.184000.json','["杵臼孤無食，詩書卒致身。", "佩琴重化蜀，衣錦却歸鄞。", "不廢先君養，難忘舊日貧。", "公卿如匹士，伯父更何人。"]'),
('611d2e7f-1ec6-4487-b5b4-b65000b83152','挽故開府節使觀文趙公二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','綠鬢今如雪，陪行萬里長。',48,'全唐诗/poet.song.184000.json','["綠鬢今如雪，陪行萬里長。", "稍從師北面，重作婿東床。", "道義非常重，精神有不忘。", "一爲天下慟，端復細思量。"]'),
('2c1ed950-b58f-424c-a837-8654d34cd739','湖中','蘇泂','宋','宋诗','song-poetry','','[]','湘湖夢不到，今日到湘湖。',48,'全唐诗/poet.song.184000.json','["湘湖夢不到，今日到湘湖。", "草木儘春色，山川如畫圖。", "雨慳蓴摘後，花發燕飛初。", "張翰平生意，扁舟未可無。"]'),
('3a0a42da-aaac-4236-82f5-e1d40bcfb3a6','百家泊','蘇泂','宋','宋诗','song-poetry','','[]','舟子更相語，泥深不可行。',48,'全唐诗/poet.song.184000.json','["舟子更相語，泥深不可行。", "擁裘聽水響，無寐到天明。", "篷背瀟湘雨，溪南欵乃聲。", "在家那汝覺，數舍許離情。"]'),
('4565391c-94f2-4f66-97de-5dc7a2e4ce98','淹泊','蘇泂','宋','宋诗','song-poetry','','[]','淹泊何如此，歸來亦偶然。',48,'全唐诗/poet.song.184000.json','["淹泊何如此，歸來亦偶然。", "江寒惟罩雨，船晚各炊煙。", "宿雁起無借，饑烏鳴乞憐。", "遥傳潮入浦，孤埭已爭牽。"]'),
('8bbbd2e4-0c75-4886-ab84-2811a4dfd7f7','過天章','蘇泂','宋','宋诗','song-poetry','','[]','菜把充詩腹，籃輿兀病身。',48,'全唐诗/poet.song.184000.json','["菜把充詩腹，籃輿兀病身。", "山煙孤起晚，官柳探生春。", "歲月渠催我，妻孥爾累人。", "誰言行路好，得似在家貧。"]'),
('75c014d6-83ad-4448-b969-85438d54f192','三峽','蘇泂','宋','宋诗','song-poetry','','[]','三峽波濤壯，秋深鼓棹前。',48,'全唐诗/poet.song.184000.json','["三峽波濤壯，秋深鼓棹前。", "飛空多隕石，失木有驚猿。", "灑徧時時雨，晴開處處天。", "篙工罷鑼鼓，此地出神仙。"]'),
('f88c961a-520a-4bf9-a705-d2c5fa22416a','夢峽','蘇泂','宋','宋诗','song-poetry','','[]','未定還家樂，仍思去國情。',48,'全唐诗/poet.song.184000.json','["未定還家樂，仍思去國情。", "猿枝樓閣影，龍府佩環聲。", "水漩欹斜碧，山摇突兀晴。", "分明昨夜夢，百丈峽中行。"]'),
('7fee77d6-7031-4e90-9f69-290756bc348e','峽險','蘇泂','宋','宋诗','song-poetry','','[]','剖鑿誰其始，山川出秘奇。',48,'全唐诗/poet.song.184000.json','["剖鑿誰其始，山川出秘奇。", "祗應天地設，未必鬼神爲。", "崩石驚船過，盤渦逼棹移。", "蓬萊如在眼，淚冷掛猿枝。"]'),
('1202019e-4bcf-439a-90aa-353d27720030','次韻望海亭','蘇泂','宋','宋诗','song-poetry','','[]','城裏偏高處，分明見海潮。',48,'全唐诗/poet.song.184000.json','["城裏偏高處，分明見海潮。", "鸛巢多碧樹，人語半丹霄。", "州宅樓臺近，居民市井遥。", "芳時一來此，因得離紛囂。"]'),
('0c9b6f59-c183-44bf-8ea9-d2f0c35fb4ec','鏡曲','蘇泂','宋','宋诗','song-poetry','','[]','鏡曲非塵世，春風屬酒杯。',48,'全唐诗/poet.song.184000.json','["鏡曲非塵世，春風屬酒杯。", "欲紓憂百結，須索醉千回。", "蓮實兒拳似，紫荆父手栽。", "無人競來往，坐穩興悠哉。"]'),
('546166fc-6580-4a8c-be80-7ec34fd91a2e','題蠟屐金貂二亭呂巽伯表弟命賦','蘇泂','宋','宋诗','song-poetry','','[]','蠟屐登山去，金貂換酒來。',48,'全唐诗/poet.song.184000.json','["蠟屐登山去，金貂換酒來。", "一生須幾兩，萬事付三杯。", "飲爾非狂耳，歸歟有旨哉。", "何時兩亭暮，吾與汝徘徊。"]'),
('4db8f0cb-69e6-41fc-a3e7-607d708db91d','三界  其一','蘇泂','宋','宋诗','song-poetry','','[]','地屬元三令，風回更幅蒲。',48,'全唐诗/poet.song.184000.json','["地屬元三令，風回更幅蒲。", "櫓聲欹枕裏，燈影到家初。", "稍覺身何有，行當夢亦無。", "平生不耕食，五斗欲誰辜。"]'),
('75e93878-6486-4d8b-b34c-f0e098136bcc','三界  其二','蘇泂','宋','宋诗','song-poetry','','[]','風日催曛暮，江溪半濁清。',48,'全唐诗/poet.song.184000.json','["風日催曛暮，江溪半濁清。", "春寒歸雁急，沙遠落鷗驚。", "有志詩書誤，無家去就輕。", "短篷扄不寐，高枕念平生。"]'),
('ebbf8ab4-9471-4729-82b0-33a22a1d9639','地壁道中','蘇泂','宋','宋诗','song-poetry','','[]','落日宜平野，回車憩薄陰。',48,'全唐诗/poet.song.184000.json','["落日宜平野，回車憩薄陰。", "羸牛歸徑險，寒雀聚枝深。", "足未傷和玉，文曾賣蜀金。", "百年渠未已，出處遂何心。"]'),
('3a036dba-b62d-4e0a-b735-b7cc0c349819','三游洞','蘇泂','宋','宋诗','song-poetry','','[]','懸崖三百丈，五里到松門。',48,'全唐诗/poet.song.184000.json','["懸崖三百丈，五里到松門。", "路盡始佳處，苔深無屐痕。", "細泉牛乳滴，亭午艾香溫。", "舟楫經行疾，無勞具酒尊。"]'),
('72663573-93b8-4101-a932-e4045ebba47a','西陵道中','蘇泂','宋','宋诗','song-poetry','','[]','凍纜牽鷗浦，炊煙飯驛亭。',48,'全唐诗/poet.song.184000.json','["凍纜牽鷗浦，炊煙飯驛亭。", "吳雲懷踐白，越樹怨閭青。", "年數那無老，巢居會有寧。", "長歌和漁者，愁絕未堪聽。"]'),
('bb0eb9c3-93a1-4c45-802a-6763f4a24c3f','吳淞','蘇泂','宋','宋诗','song-poetry','','[]','把蟹風前醉，吟詩水面歌。',48,'全唐诗/poet.song.184000.json','["把蟹風前醉，吟詩水面歌。", "餘年聽造物，所嗜獨烟波。", "蘭棹憑雙穉，菱花笑一皤。", "稽山今又昔，賀老苦無多。"]'),
('f9a93e0e-9791-478f-b366-cad5f77c52ea','途次口占三首  其一','蘇泂','宋','宋诗','song-poetry','','[]','草檄頭風愈，吟詩瘧鬼藏。',48,'全唐诗/poet.song.184000.json','["草檄頭風愈，吟詩瘧鬼藏。", "三年如昨日，多難更殊鄉。", "澗底秋花小，枝頭病葉黄。", "饑餐并困卧，平地有仙方。"]'),
('b7f5ee7e-d974-45ce-8553-dabc52882b88','途次口占三首  其二','蘇泂','宋','宋诗','song-poetry','','[]','鼓棹泛瀰茫，驅車道莽蒼。',48,'全唐诗/poet.song.184000.json','["鼓棹泛瀰茫，驅車道莽蒼。", "功名中底用，奔走爲誰忙。", "白浪高揚子，青山入建康。", "從來懷古意，秋至轉悲凉。"]'),
('54b439a9-60cd-4d0e-9f59-77b96af016c6','途次口占三首  其三','蘇泂','宋','宋诗','song-poetry','','[]','棗子萬星攢，良苗綠一端。',48,'全唐诗/poet.song.184000.json','["棗子萬星攢，良苗綠一端。", "撲籃多秀色，吹帽受風寒。", "擾擾水和尚，泠泠山藥官。", "近詩差進步，安得老梅看。"]'),
('5ff6c2c3-38e7-45f2-9344-8a85cc2e0604','八月十二日再入都','蘇泂','宋','宋诗','song-poetry','','[]','野色連山碧，時光似水流。',48,'全唐诗/poet.song.184000.json','["野色連山碧，時光似水流。", "鄒陽仍是客，李廣不封侯。", "業已詩中老，何須病始休。", "草根螢一點，寂照萬端憂。"]'),
('f9a0c079-89f0-4b41-9bf3-0be57be8b77a','晚渡','蘇泂','宋','宋诗','song-poetry','','[]','小雨濕詩人，人疑過渡頻。',48,'全唐诗/poet.song.184000.json','["小雨濕詩人，人疑過渡頻。", "望山高著眼，就樹巧遮身。", "有句尋鷗說，無家認鶴親。", "明朝上京去，釃酒酹溪神。"]'),
('6be06a0c-7e5c-4164-a133-5725a91ffea2','曹娥江','蘇泂','宋','宋诗','song-poetry','','[]','月下傾殘酒，風前讀斷碑。',48,'全唐诗/poet.song.184000.json','["月下傾殘酒，風前讀斷碑。", "采江那有意，陟岵不無悲。", "樹影經船疾，灘聲到枕遲。", "重來更何日，放棹欲何之。"]'),
('f2c247b9-47a0-4dd0-b195-400af41a3e75','浙江','蘇泂','宋','宋诗','song-poetry','','[]','演迤來何代，崩騰直至今。',48,'全唐诗/poet.song.184000.json','["演迤來何代，崩騰直至今。", "飛潜知險地，征逐欠閒心。", "西障殘山渺，東流大海深。", "會携秋月色，徐聽夜龍吟。"]'),
('8f321f17-6140-45a1-a1ca-2c54f041e873','若耶溪','蘇泂','宋','宋诗','song-poetry','','[]','歲月去悠悠，沙邊一線流。',48,'全唐诗/poet.song.184000.json','["歲月去悠悠，沙邊一線流。", "榮無嚴子釣，直有楚臣鈎。", "雨氣知魚樂，煙光驗鳥愁。", "餘年未可料，幾度此維舟。"]'),
('6feb041f-1293-4211-b7cc-4b71c573fd41','長江二首  其一','蘇泂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江無六月，大地絕纖埃。',48,'全唐诗/poet.song.184000.json','["長江無六月，大地絕纖埃。", "暑向風前退，秋從雨後來。", "問桐知葉落，修桂待花開。", "疇昔扁舟興，分明欲喚回。"]'),
('071aeda1-d2da-4e20-ab38-3dcd827f7fc7','長江二首  其二','蘇泂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','處暑無三日，新凉直萬金。',48,'全唐诗/poet.song.184000.json','["處暑無三日，新凉直萬金。", "白頭更世事，青草印禪心。", "放鶴婆娑舞，聽蛩斷續吟。", "極知仁者壽，未必海之深。"]'),
('8de3842c-fe96-4454-ba45-17a97a41feec','遊子','蘇泂','宋','宋诗','song-poetry','','[]','遊子那無故，青春亦有歸。',48,'全唐诗/poet.song.184000.json','["遊子那無故，青春亦有歸。", "小舟衝岸疾，白鳥破烟飛。", "物理迷終極，人生喜願違。", "東南雙病眼，隨日下漁磯。"]'),
('f88eb212-153d-43cc-a470-a8b9a6596e5a','曉行','蘇泂','宋','宋诗','song-poetry','','[]','稚子侵煙語，征夫破曉行。',48,'全唐诗/poet.song.184000.json','["稚子侵煙語，征夫破曉行。", "百爲真有數，萬物本同生。", "擾擾歲月晚，悠悠江海情。", "荒雞叫茅屋，一笑又天明。"]'),
('c7e1e39b-d167-4460-842b-30bba58619f3','過高資丞相墓','蘇泂','宋','宋诗','song-poetry','','[]','先祖當元祐，誠心相哲宗。',48,'全唐诗/poet.song.184000.json','["先祖當元祐，誠心相哲宗。", "閙藍初不入，遺表尚深忠。", "簪笏兒孫少，松楸盜賊空。", "經從每瞻拜，何日免飄蓬。"]'),
('0fb1b1ed-6941-462f-bbab-1df878c1c175','拜大父墓','蘇泂','宋','宋诗','song-poetry','','[]','六載今如此，青松到屋梁。',48,'全唐诗/poet.song.184000.json','["六載今如此，青松到屋梁。", "何言聲籍籍，直作去堂堂。", "事已難追悔，天高只痛傷。", "當時巴蜀使，書疏不能忘。"]'),
('74ec7a64-c63e-4fc4-83e7-881f957dda0c','望三山放翁居','蘇泂','宋','宋诗','song-poetry','','[]','晚進違前輩，湮才重此州。',48,'全唐诗/poet.song.184000.json','["晚進違前輩，湮才重此州。", "絕知他日少，預作百年憂。", "樵牧非身致，聰明不我謀。", "莫令司馬藁，祗候茂陵求。"]'),
('c350edb4-96fe-4fc8-91c8-8884b1ca4b70','泊通明','蘇泂','宋','宋诗','song-poetry','','[]','午夜通明泊，朝來自啟篷。',48,'全唐诗/poet.song.184000.json','["午夜通明泊，朝來自啟篷。", "驟看潮带雨，還作雪隨風。", "酒薄愁無料，詩難老未工。", "疎寮有奇士，恨不此行同。"]'),
('7ee4ce28-d4cf-4522-8033-3f0cd966ef04','又約趙大再遊小陽明其山全似峽中點煙一亭可爲吳越之冠','蘇泂','宋','宋诗','song-poetry','','[]','客路心常慰，歸棲氣苦低。',48,'全唐诗/poet.song.184000.json','["客路心常慰，歸棲氣苦低。", "經行天柱北，夢想雪峰西。", "翠壁千巖長，蒼煙半點迷。", "何當同拄杖，重此聽猿啼。"]'),
('cea65b7f-1b3b-446f-854f-2bc99bb6e47e','出婺城','蘇泂','宋','宋诗','song-poetry','','[]','萬頃平田雪，前村昨夜梅。',48,'全唐诗/poet.song.184000.json','["萬頃平田雪，前村昨夜梅。", "夢還荆國舊，吟欠兔園才。", "只作尋詩去，何曾爲酒來。", "茲行得奇事，夾道有瓊瑰。"]'),
('0a669792-dc7f-49f1-ae67-7d27f4329922','歸棹','蘇泂','宋','宋诗','song-poetry','','[]','形役何時已，凄凉莫更論。',48,'全唐诗/poet.song.184000.json','["形役何時已，凄凉莫更論。", "雁啼雲背月，人語水邊村。", "十月冬猶暖，三杯酒易昏。", "悠悠信歸棹，今夜宿誰門。"]'),
('b995e685-0679-4105-bfd7-2444efa8af92','雪霽歸湖山過千秋觀少留','蘇泂','宋','宋诗','song-poetry','','[]','縱轡不嫌遠，逢山猶一登。',48,'全唐诗/poet.song.184000.json','["縱轡不嫌遠，逢山猶一登。", "夕陽波渺渺，殘雪塔層層。", "折竹橫遮道，饑烏下啄冰。", "欲歸還小駐，倚杖對崚嶒。"]'),
('a07d20c7-b19b-4849-bc2c-644c7c69db85','在昔','蘇泂','宋','宋诗','song-poetry','','[]','在昔西游日，飄然入劍關。',48,'全唐诗/poet.song.184000.json','["在昔西游日，飄然入劍關。", "酒醒天外驛，詩爽峽中山。", "天地羈棲久，鄉園縞素還。", "不堪明鏡裏，重覓舊朱顔。"]'),
('eabc82eb-6e06-42bb-bc1e-d5393ee32b63','正月二十七日陪唐子耆登卧龍時稼軒已去令人懷之','蘇泂','宋','宋诗','song-poetry','','[]','晴雨煙雲態，高深會見聞。',48,'全唐诗/poet.song.184000.json','["晴雨煙雲態，高深會見聞。", "亂山依越定，一水向吳分。", "元白諸侯表，楊王俊士羣。", "春風到紅綠，花草總能文。"]'),
('39814fd7-207d-4dc7-8da1-eff5df4f325f','書張氏壁','蘇泂','宋','宋诗','song-poetry','','[]','潮水遲朝渡，湖村竟日留。',48,'全唐诗/poet.song.184000.json','["潮水遲朝渡，湖村竟日留。", "肯從沽酒飲，故作挾書游。", "得句因題壁，逢人問買州。", "雙鳬應不遠，知道客來不。"]'),
('4cb4d5fd-127e-4e30-8ac8-76b5b11da837','題元真觀屋壁二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','琳宮無俗務，書卷得相親。',48,'全唐诗/poet.song.184000.json','["琳宮無俗務，書卷得相親。", "樹影自知午，棋聲不見人。", "實爲蕭爽地，蹔得自由身。", "客至誰能接，應知懶是真。"]'),
('dd7e1c8a-844f-4f2c-a16e-1fcedffcab09','題元真觀屋壁二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','冬青幹已老，柏樹亦蕭蕭。',48,'全唐诗/poet.song.184000.json','["冬青幹已老，柏樹亦蕭蕭。", "紫殿歲年遠，黄冠早晚朝。", "井甘鄰共汲，食寡腹常枵。", "永夜看河漢，仙人似見招。"]'),
('b3d63737-da68-4f5c-9ef3-fc98de4172b5','玉麟堂上偶成','蘇泂','宋','宋诗','song-poetry','','[]','雨燕飛仍集，池荷密復疎。',48,'全唐诗/poet.song.184000.json','["雨燕飛仍集，池荷密復疎。", "無心應人事，隨意數遊鱼。", "碑字千年冷，薰風五月初。", "玉麟堂上客，曷日賦歸歟。"]'),
('78637606-1aad-4b10-bfa0-20a678267b5f','安隠寺詩','蘇泂','宋','宋诗','song-poetry','','[]','樟樹何年種，娑娑滿寺門。',48,'全唐诗/poet.song.184000.json','["樟樹何年種，娑娑滿寺門。", "金身虛像設，畫壁儘塵昏。", "龍虎青山遠，冰霜碧甃存。", "坊官敬人客，頃刻具肴尊。"]'),
('acd55b3c-ad88-443b-a34e-4b255d394eca','題周氏庵','蘇泂','宋','宋诗','song-poetry','','[]','緩步勝騎馬，迷塗問跨牛。',48,'全唐诗/poet.song.184000.json','["緩步勝騎馬，迷塗問跨牛。", "蓴絲方擾擾，湖水亦悠悠。", "解后因成款，淹留却當游。", "旁觀君共我，真是兩沙鷗。"]'),
('642ede86-1808-4b41-93da-745ee2ed8391','別湖橋','蘇泂','宋','宋诗','song-poetry','','[]','步轉湖橋晚，家園隔斷陂。',48,'全唐诗/poet.song.184000.json','["步轉湖橋晚，家園隔斷陂。", "回看猶萬里，別去不多時。", "犢子迎風立，童兒以杖隨。", "筍輿方坐睡，到此忽成詩。"]'),
('d73838b4-04ca-48e6-8a8f-31935924c1f0','三白','蘇泂','宋','宋诗','song-poetry','','[]','大雪平地尺，臘中相見三。',48,'全唐诗/poet.song.184000.json','["大雪平地尺，臘中相見三。", "無人堪共賞，與壁自高談。", "茗事工爲祟，詩盟跡不咸。", "夢成蝴蝶去，飛過百花巖。"]'),
('ae547a29-54eb-4f82-a1c4-e7d59bb77560','上清雪','蘇泂','宋','宋诗','song-poetry','','[]','撥雪尋行路，推書問枕屏。',48,'全唐诗/poet.song.184000.json','["撥雪尋行路，推書問枕屏。", "恍登瑶玉府，憶在錦官城。", "眠少燈相伴，愁多酒易醒。", "寒鷄喚清曉，匹馬又遐征。"]'),
('4a0e3759-0a45-4b39-98b9-795a96e9240e','餘姚江上夜看殘雪','蘇泂','宋','宋诗','song-poetry','','[]','星斗夜迢迢，江空一棹摇。',48,'全唐诗/poet.song.184000.json','["星斗夜迢迢，江空一棹摇。", "亂山詩態活，殘雪醉魂消。", "已作無懷氏，長思有道朝。", "周公夢不見，篷底聽鴟鴞。"]'),
('bc8a6f24-4dcd-4373-af35-f55362da4c96','奉和高秘書雪中雜興','蘇泂','宋','宋诗','song-poetry','','[]','平湖添細碧，繞郭看新晴。',48,'全唐诗/poet.song.184000.json','["平湖添細碧，繞郭看新晴。", "幸作當年瑞，那無一日情。", "睡魂依酒濁，詩味益茶清。", "寒事今如許，重捫反舌聲。"]'),
('0b728dc5-4d0f-4246-a781-a27dc7d572b7','次韻馬季思禁體雪二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','滌盡妖氛氣，粧成富貴冬。',48,'全唐诗/poet.song.184000.json','["滌盡妖氛氣，粧成富貴冬。", "梅花香處覺，人意火邊濃。", "未暖那飛絮，非寒底見松。", "絕憐階下竹，腰折爲誰恭。"]'),
('c7228fd5-bc3a-4e7d-9bbf-3ad6d2a6fb3d','次韻馬季思禁體雪二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','庭樹曉毿毿，行空馬脫驂。',48,'全唐诗/poet.song.184000.json','["庭樹曉毿毿，行空馬脫驂。", "瑞臻平地尺，白見一年三。", "照眼花猶散，齊腰話可參。", "岑樓尋勝賞，溪泛此何慚。"]'),
('9a3d88dd-45c6-4563-ad68-91f8cf149f2d','咏月  其一','蘇泂','宋','宋诗','song-poetry','','[]','入夜金盆上，終宵玉鏡懸。',48,'全唐诗/poet.song.184000.json','["入夜金盆上，終宵玉鏡懸。", "氣凉征戍骨，腸斷別離緣。", "皎潔寧傷性，虛明欲竟天。", "平生看不足，茲夕更悠然。"]'),
('ef3ff93b-90e4-4910-8b26-f488736980ff','咏月  其二','蘇泂','宋','宋诗','song-poetry','','[]','既雨中秋望，纖毫桂影分。',48,'全唐诗/poet.song.184000.json','["既雨中秋望，纖毫桂影分。", "魄高疑壓霧，香動欲衝雲。", "稍窘癡蟾窟，全驚睡鵲羣。", "孤清若箇畔，玉笛片時聞。"]'),
('cd333ec6-2a44-4dfe-9707-c9cb8f905135','秋風  其一','蘇泂','宋','宋诗','song-poetry','','[]','秋風清入骨，秋樹薄於雲。',48,'全唐诗/poet.song.184000.json','["秋風清入骨，秋樹薄於雲。", "老去悲時序，新來斷句文。", "燕鴻相背發，涇渭一生分。", "信有難言事，天高不爲聞。"]'),
('18237e62-37a7-4ed0-84f1-a59ecaf4c7a7','秋風  其二','蘇泂','宋','宋诗','song-poetry','','[]','秋風荷葉老，秋月桂枝生。',48,'全唐诗/poet.song.184000.json','["秋風荷葉老，秋月桂枝生。", "萬物四時意，八荒雙眼明。", "憂虞滋疾病，治亂閲陰晴。", "秔稻今年少，無勞社酒傾。"]'),
('5cc34bfc-e27d-468f-98ce-6b38eac7f90b','霜露吟','蘇泂','宋','宋诗','song-poetry','','[]','短褐新冬逼，中流一棹孤。',48,'全唐诗/poet.song.184000.json','["短褐新冬逼，中流一棹孤。", "旅程沙泊鴈，行色樹穿馿。", "霜露悲愁骨，功名畏老夫。", "平生知范蠡，嘗膽會吞吳。"]'),
('a00e0253-95e9-4ab8-a887-3274fe84af2d','中秋扶病對月','蘇泂','宋','宋诗','song-poetry','','[]','久病頭如石，中秋月似盆。',48,'全唐诗/poet.song.184000.json','["久病頭如石，中秋月似盆。", "起瞻惟一色，歸卧只空村。", "信有鄜州見，曾同秘省論。", "微吟到河漢，桂樹忽飛翻。"]'),
('c6eab1ad-86be-4096-9dd9-a393617cb947','感秋','蘇泂','宋','宋诗','song-poetry','','[]','索索來何處，梧桐昨夜黄。',48,'全唐诗/poet.song.184000.json','["索索來何處，梧桐昨夜黄。", "蛩聲機杼月，鴈影塞垣霜。", "俗尚儒餐貴，家貧父業荒。", "三秋病消瘦，吾興入柴桑。"]'),
('c7aac040-9af1-4684-b554-0546394278a5','秋感','蘇泂','宋','宋诗','song-poetry','','[]','朱槿不堪留，牽牛上竹幽。',48,'全唐诗/poet.song.184000.json','["朱槿不堪留，牽牛上竹幽。", "蛩聲清奪漏，鷹翮勁思秋。", "掩卷悲先哲，看山憶舊遊。", "閨情兼旅夢，百慮五更頭。"]'),
('9c6d9a5b-a244-49ca-93e6-a8b7ae4f2578','獨鳥','蘇泂','宋','宋诗','song-poetry','','[]','獨鳥愁歸翮，霜寒謝世紛。',48,'全唐诗/poet.song.184000.json','["獨鳥愁歸翮，霜寒謝世紛。", "夢遥鄉思局，砧急酒醒聞。", "一笑胡爲爾，中年更不羣。", "頗疑當日論，飽飯薄能文。"]'),
('53af1e97-642f-4fba-9381-c9a21a646ba9','乳爵','蘇泂','宋','宋诗','song-poetry','','[]','乳爵機心淺，逢人自不飛。',48,'全唐诗/poet.song.184000.json','["乳爵機心淺，逢人自不飛。", "闊疏羅網事，愛惜羽毛稀。", "一物知天理，他年任布衣。", "相忘容苟免，吾與汝無違。"]'),
('f7b59b9c-2bc3-4fb1-a3d6-6e5f31528bae','老蚌','蘇泂','宋','宋诗','song-poetry','','[]','老蚌吸秋月，饑鷹號朔風。',48,'全唐诗/poet.song.184000.json','["老蚌吸秋月，饑鷹號朔風。", "人生根蒂少，物理短長同。", "難學纍纍印，休書咄咄空。", "餘年見兒態，若箇白頭翁。"]'),
('e7274938-23f8-4001-a016-b234920462b1','題司馬提舉畫鷹','蘇泂','宋','宋诗','song-poetry','','[]','舊讀少陵句，今觀司馬鷹。',48,'全唐诗/poet.song.184000.json','["舊讀少陵句，今觀司馬鷹。", "風雲千變化，天地一飛騰。", "側目看枝鳥，回身掣臂繩。", "何由飲西顥，真逐羽毛升。"]'),
('7d958df5-133c-436d-b295-c9205df4123e','學漁','蘇泂','宋','宋诗','song-poetry','','[]','舟楫蘋花渺，江湖喜氣多。',48,'全唐诗/poet.song.184000.json','["舟楫蘋花渺，江湖喜氣多。", "一天飛白雨，半夜濕青蓑。", "帆轉星初落，潮歸鏡欲磨。", "平生動中靜，安枕信風波。"]'),
('9d2633c8-2e39-423a-9731-ffcf64eab83a','北苑','蘇泂','宋','宋诗','song-poetry','','[]','北苑心無壯，南窗眼費明。',48,'全唐诗/poet.song.184000.json','["北苑心無壯，南窗眼費明。", "病因杯酒見，花值客愁生。", "落落知誰合，紛紛詎不情。", "未成幽處宅，且逐衆人行。"]'),
('eab30616-7ff2-4cf1-a5f3-8f8f3b7eece7','老鬢詩','蘇泂','宋','宋诗','song-poetry','','[]','老鬢驚霜覺，春容带雪來。',48,'全唐诗/poet.song.184000.json','["老鬢驚霜覺，春容带雪來。", "散愁詩數首，覓醉酒三杯。", "行店人歸少，荒林鳥去回。", "高情無與共，自摘澗邊梅。"]'),
('0928b169-317f-414f-926d-6783252197b8','霜毛','蘇泂','宋','宋诗','song-poetry','','[]','深深四簷雨，眇眇一枝燈。',48,'全唐诗/poet.song.184000.json','["深深四簷雨，眇眇一枝燈。", "酒盡獨愁婦，家貧全似僧。", "中年多感慨，同好少交朋。", "自省空諸有，霜毛未可憎。"]'),
('141c13e5-baec-4605-bab9-2ce0c0049be1','即事','蘇泂','宋','宋诗','song-poetry','','[]','新笋看成竹，春風去不知。',48,'全唐诗/poet.song.184000.json','["新笋看成竹，春風去不知。", "麥天蠶上早，槐日燕飛遲。", "褐短偏憐婦，家貧更惜兒。", "十年霜鬢白，未必總因詩。"]'),
('bb8f7c1f-0444-421c-822e-2d5273f2ca9f','問水詩','蘇泂','宋','宋诗','song-poetry','','[]','頃別知何處，重來喜奈何。',48,'全唐诗/poet.song.184000.json','["頃別知何處，重來喜奈何。", "望洋誇海谷，倒篋注天河。", "變化龜文坼，淪漪鴨頂波。", "白鷗沒浩蕩，清興滿吟哦。"]'),
('5ea06f9b-3808-4f42-9204-6d217c8c4167','送三兄出宰常山','蘇泂','宋','宋诗','song-poetry','','[]','官次淹時久，才華應世須。',288,'全唐诗/poet.song.184000.json','["官次淹時久，才華應世須。", "及瓜逢六月，行李過三衢。", "迓吏江邊少，齎裝驛外都。", "潮經漁浦夜，檣泊富陽晡。", "柳障飛雲合，花溪落照孤。", "別情初島溆，行色半菰蒲。", "後日思家否，兼旬到縣無。", "衙新夸綵棟，俗厚省鳴枹。", "陸走通閩蜀，川浮赴越吳。", "往來紛鴈鶩，富貴幾金珠。", "故老知名父，諸公拜畫圖。", "琴聲追舊宓，謠詠溢今蘇。", "馴聽桑間雉，歡瞻屋上烏。", "源流從孔氏，操履是顔徒。", "卓魯方如許，龔黄盍念夫。", "吾儕甘齟齬，仕路不崎嶇。", "霜葉看青綬，秋蓬類白鬚。", "但令民若子，何恤吏如奴。", "宰相曾傳業，郎官此問途。", "入朝端繼軌，負郭款營租。", "女大宜招婿，兒單切教渠。", "箕裘綿代遠，門戶更誰扶。", "乃伯偏憐我，尊兄况友于。", "中年嗟契闊，少小事差殊。"]'),
('ae4ac42e-2de7-4245-ae2d-0a60f2ef4190','梅口遣興','蘇泂','宋','宋诗','song-poetry','','[]','屏迹甘衡陋，馳書捷置郵。',288,'全唐诗/poet.song.184000.json','["屏迹甘衡陋，馳書捷置郵。", "繫匏成潦倒，行李當嬉遊。", "偶往無前約，明知不自由。", "米鹽嗔婦問，書劍惜兒留。", "頗涉湖堤遠，旋驚野店稠。", "小梅溪側寺，疎柳驛邊樓。", "放燒催青入，瞻山揭翠流。", "鷄籠從勢卓，獅卧得形脩。", "花面施家說，碑顔蠡廟修。", "池冰魚附藻，縣早肉垂鈎。", "短景中俄昃，孤煙散復收。", "數鳬將子出，一鴈落聲幽。", "古怪藤妨瓦，灣碕石礙輈。", "度危還借步，揭淺更呼舟。", "栗大封懸屋，萁香炒貯甌。", "氣豪紛敺擊，博負幾喧啾。", "月與星偕隠，雲將雪共謀。", "拾岩乾窸窣，汲澗冷颼飀。", "少飯粞爲食，無衣紙作裘。", "楮艱錢愈瘦，吏墨政仍偷。", "橋幻僧伽佛，桁傳嶺海囚。", "舞儺羣畫鬼，唱牧和村謳。", "飣坐初嘗蠘，比鄰遞解牛。", "門符矜鷙詭，館泊佐倡優。"]'),
('001a2296-6d7b-4f30-aeff-da10c94f49da','上樓大參  其一','蘇泂','宋','宋诗','song-poetry','','[]','貞元朝士久成空，故國靈光但有公。',64,'全唐诗/poet.song.184000.json','["貞元朝士久成空，故國靈光但有公。", "四海已遲三日雨，八荒同在一春風。", "耆年盛德天應相，大冊高文老更工。", "且爲商家了梅事，未須海道覓舟東。"]'),
('81aae43f-850b-459e-8c6c-28f0c047bb63','上樓大參  其二','蘇泂','宋','宋诗','song-poetry','','[]','四朝相業舊儀刑，今代衣冠類曉星。',64,'全唐诗/poet.song.184000.json','["四朝相業舊儀刑，今代衣冠類曉星。", "青眼更誰憐後裔，白頭空復抱遺經。", "沖霄有路開籠鶴，槁案無時泣卷螢。", "吏部觀文均所愛，因聲廊廟一丁寧。"]'),
('f768651f-2ee3-4ab0-9912-d220e0293d9b','喜雨和轉庵韻','蘇泂','宋','宋诗','song-poetry','','[]','香霧騰雲滃鬰蒸，九重精禱格真清。',64,'全唐诗/poet.song.184000.json','["香霧騰雲滃鬰蒸，九重精禱格真清。", "連朝潤澤非凡雨，通國驩呼荷聖情。", "好句便疑從地湧，勞歌不復和車聲。", "鵓鳩屋角休無頼，未許尋常喚婦鳴。"]'),
('37ef4700-90da-42c9-b9e6-e72e45a03c7e','雨後乞御正殿得請次韻','蘇泂','宋','宋诗','song-poetry','','[]','已成霖雨慰黎蒸，聖主齋居尚穆清。',64,'全唐诗/poet.song.184000.json','["已成霖雨慰黎蒸，聖主齋居尚穆清。", "奏許正朝仍玉食，盡回喜色見民情。", "衣篝不惜添梅潤，籤帙從堆亂葉聲。", "要雨雨來天便許，不須更卜白鼉鳴。"]'),
('39965ec6-fdcf-4738-8b92-e754ac32b5df','酬王木叔判院喜雨韻','蘇泂','宋','宋诗','song-poetry','','[]','雨在琴書溽更蒸，雨餘衣袂潤猶清。',64,'全唐诗/poet.song.184000.json','["雨在琴書溽更蒸，雨餘衣袂潤猶清。", "良苗日起有佳色，聖澤天同無靳情。", "得句餉耘聊志喜，欲歌擊缶不容聲。", "居然引玉何從至，敢向黄鐘作釜鳴。"]'),
('90226651-5450-4ff6-9588-78d26637bf0b','四月二十四日喜雨次振之韻','蘇泂','宋','宋诗','song-poetry','','[]','朝來驟雨鬰煩蒸，晚見疎星掛漢青。',64,'全唐诗/poet.song.184000.json','["朝來驟雨鬰煩蒸，晚見疎星掛漢青。", "大點忽隨風信入，好聲先覺夢魂聽。", "春過種失農猶及，喜極詩成語未停。", "每恨買山無醖藉，不知肝膽露青萍。"]'),
('6e04f0d1-3802-4be2-9b07-b45fa6f8fbd3','劉振之訪別舉似喜雨詩次韻','蘇泂','宋','宋诗','song-poetry','','[]','尺澤霏微起寸陰，稍蘇焦槁見青青。',64,'全唐诗/poet.song.184000.json','["尺澤霏微起寸陰，稍蘇焦槁見青青。", "便疑菽粟中天降，絕喜階除半夜聽。", "訪我尚期新舊雨，話歸還憶短長亭。", "交游若問今何似，世味諳來似楚萍。"]'),
('c221c9d6-14f5-4a06-8355-c17a9b6b9f06','喜雨忽風作酬仲歸','蘇泂','宋','宋诗','song-poetry','','[]','觸石興雲走列峰，天官日日課分龍。',64,'全唐诗/poet.song.184000.json','["觸石興雲走列峰，天官日日課分龍。", "有懷競喜神靈雨，無術添驅變化筇。", "枕上佳聲欣濺瀑，田間樂事喻號鐘。", "連朝風伯何從惡，敢不凌兢爲肅容。"]'),
('abf7240c-18ca-4e33-bfd5-1938fdc9c826','次韻仲歸喜雨有肯顧之意','蘇泂','宋','宋诗','song-poetry','','[]','願試黄昏上古湯，社中今得沈東陽。',64,'全唐诗/poet.song.184000.json','["願試黄昏上古湯，社中今得沈東陽。", "素衣肯爲緇塵染，秀句殊增灌頂涼。", "不惜聯翩過舊隠，也欣滂沛洗炎光。", "預知定得驚人語，約略眉間喜氣黄。"]'),
('f2a01fc4-9d8b-4ceb-99ac-a53b79d0bf29','家國','蘇泂','宋','宋诗','song-poetry','','[]','長安五月火雲堆，客子光陰鬢髮催。',64,'全唐诗/poet.song.184000.json','["長安五月火雲堆，客子光陰鬢髮催。", "謀國已嗟無位及，憂家只怕有書來。", "榴花照眼何曾摘，萱草驚心不要開。", "焉得兒男備征戍，等閑挈取版圖回。"]'),
('ee779cff-a197-43fb-99a3-d191f7b441ff','悟前生','蘇泂','宋','宋诗','song-poetry','','[]','秋風拂拂草頭青，秋日離離萬寶成。',64,'全唐诗/poet.song.184000.json','["秋風拂拂草頭青，秋日離離萬寶成。", "懶把幽懷經俗事，每因前境悟他生。", "謝郎船上魚新買，賀監湖邊酒細傾。", "七十三分今過二，且然無忤白鷗盟。"]'),
('8dab797f-7aff-49cc-9b16-95a8938ec786','名節','蘇泂','宋','宋诗','song-poetry','','[]','了知名節重於山，誰信今人古誼存。',64,'全唐诗/poet.song.184000.json','["了知名節重於山，誰信今人古誼存。", "百草前頭梅萼秀，羣飛之內鳳凰尊。", "有身合下陽城拜，無些能招宋玉魂。", "公道世間猶我輩，未妨歸卧掩柴門。"]'),
('4ccd8eae-dd72-48b1-8d9c-efee92c7ea4b','感春','蘇泂','宋','宋诗','song-poetry','','[]','紛紛忙事幾曾閑，快上高樓得解顔。',64,'全唐诗/poet.song.184000.json','["紛紛忙事幾曾閑，快上高樓得解顔。", "夜月一奩花似鏡，春風千疊柳如山。", "多情未放芳塵遠，漸老難追少日還。", "燕子飛來那有意，又催團扇入懷間。"]'),
('7e8b7b39-a298-4b0d-a7e0-58d2c75f1152','春去','蘇泂','宋','宋诗','song-poetry','','[]','城郭春風賦式微，忽看鶑老燕雛飛。',64,'全唐诗/poet.song.184000.json','["城郭春風賦式微，忽看鶑老燕雛飛。", "秧田水滿聞姑惡，樹葉陰濃叫姊歸。", "百歲襟期真索寞，十年心事只依稀。", "人間我亦無能者，華髮蒼顔未必非。"]'),
('8db2983d-df29-47e4-9b9f-5b411a6adc52','聽雨詩','蘇泂','宋','宋诗','song-poetry','','[]','三分春事二分休，造化明明百草頭。',64,'全唐诗/poet.song.184000.json','["三分春事二分休，造化明明百草頭。", "一夜雨聲清似玉，半窗梅影淡於秋。", "家貧只與詩爲伍，客去從教睡作儔。", "敗衲依然湖海闊，老來無喜亦無憂。"]'),
('602fda2d-c1f6-4262-bf23-bcce8fbc6383','雨','蘇泂','宋','宋诗','song-poetry','','[]','春禽喚雨屋山呼，二月韶光一半無。',64,'全唐诗/poet.song.184000.json','["春禽喚雨屋山呼，二月韶光一半無。", "作祟豈逃泥滑滑，原情當坐穀孤孤。", "不應荳蔻花梢重，已怪荼䕷葉子麤。", "年去年來誰奈得，酒酣擊缶和噫嗚。"]'),
('d173a715-90fa-4df8-b054-c6b3c5c4330e','次韻曾文清公復熱句','蘇泂','宋','宋诗','song-poetry','','[]','百頃滄波望似空，鑿冰吾欲浸其中。',64,'全唐诗/poet.song.184000.json','["百頃滄波望似空，鑿冰吾欲浸其中。", "何言雷電不爲雨，須信梧桐自有風。", "子晉臺頭笙遠近，西真池面玉丁東。", "行牋章奏求清冷，乞取玄冥換祝融。"]'),
('6cf67c6d-46cf-466c-afa3-b943328facf0','熱','蘇泂','宋','宋诗','song-poetry','','[]','夏雲端的似奇峰，忽作頹牆四面紅。',64,'全唐诗/poet.song.184000.json','["夏雲端的似奇峰，忽作頹牆四面紅。", "坐想微風過荷葉，夢成疎雨滴梧桐。", "浮家何計來波上，舉扇無因出焙中。", "三十餘年吟冷語，今年吟到水晶宮。"]'),
('3e224d84-1f05-4d01-9b36-4cb37637a08b','次韻潁小弟秋日','蘇泂','宋','宋诗','song-poetry','','[]','遊鱗羈羽任浮沉，老大凄然感歲陰。',64,'全唐诗/poet.song.184000.json','["遊鱗羈羽任浮沉，老大凄然感歲陰。", "風底波紋生別浦，雨餘山影出疎林。", "殘年不足償多病，萬事寧須付有心。", "滿眼黄花一杯酒，愴懷元弗爲聽砧。"]'),
('21099cdd-4c72-43e3-8385-f05a68c95f82','雪','蘇泂','宋','宋诗','song-poetry','','[]','窮冬那得許奇觀，疑怪重衾夜更寒。',64,'全唐诗/poet.song.184000.json','["窮冬那得許奇觀，疑怪重衾夜更寒。", "正爛漫花隨處有，不堅牢玉暫時看。", "上章謁帝應留得，下令教兒莫掃乾。", "岐路楊朱定垂泣，東西南北總漫漫。"]'),
('2d7d2b00-60b8-4eb8-b88f-db1d2117821f','簡銛朴翁兼簡敬叟二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','雪花梅萼兩婆娑，梅雪相催柰老何。',64,'全唐诗/poet.song.184000.json','["雪花梅萼兩婆娑，梅雪相催柰老何。", "只合孤山訪和靖，不應華屋比東坡。", "詩情可喜絲生鬢，歸意猶須冰泮河。", "林下相尋未岑寂，木魚能拍鳥能歌。"]'),
('33ddba55-97e9-48b6-8fa1-c56478fa726b','簡銛朴翁兼簡敬叟二首  其二','蘇泂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','生機幻法不無神，信手拈來却是真。',64,'全唐诗/poet.song.184000.json','["生機幻法不無神，信手拈來却是真。", "雪月梅花同一色，陳黄蘇老只三人。", "論詩已具頂門眼，選勝直賒頭上春。", "普請西湖作公案，與師聊結未來因。"]'),
('55f48566-13bf-49d3-83b4-af4d1b538283','遣興','蘇泂','宋','宋诗','song-poetry','','[]','風林縹緲有如無，煙樹重重直愛渠。',64,'全唐诗/poet.song.184000.json','["風林縹緲有如無，煙樹重重直愛渠。", "今我時光能有幾，古人詩興已無餘。", "又隨篛舫衝潮去，未結茅齋並水居。", "旅館蕭條厨傳少，江妃來遺一雙魚。"]'),
('afb67cf0-6307-4a57-ac0e-f776f669f8b9','自述','蘇泂','宋','宋诗','song-poetry','','[]','交友凋零似曉星，生涯依舊短長亭。',64,'全唐诗/poet.song.184000.json','["交友凋零似曉星，生涯依舊短長亭。", "前身房琯仍名永，今代蘇耽不姓丁。", "兒女成行頭自白，湖山相對眼終青。", "還鄉曲調如何唱，枯樹無言最可聽。"]'),
('94ecb6ab-b619-4d3e-b50a-3070b98c1344','壽陸放翁三首  其一','蘇泂','宋','宋诗','song-poetry','','[]','年事依稀鬢復青，看書細字眼猶明。',64,'全唐诗/poet.song.184000.json','["年事依稀鬢復青，看書細字眼猶明。", "池邊自種桃初熟，籬下曾枯竹再生。", "已覺貂蟬除世念，未妨龜鶴伴詩情。", "日供薪水門人職，準擬金丹點鐵成。"]'),
('644e9e98-9755-4b17-819c-95e62a9de0a7','壽陸放翁三首  其二','蘇泂','宋','宋诗','song-poetry','','[]','邊松坐石日從容，故國靈光只我公。',64,'全唐诗/poet.song.184000.json','["邊松坐石日從容，故國靈光只我公。", "豈有文章高海內，獨將身世老山中。", "丹頭躍笋分明異，梅萼含椒即漸紅。", "千歲斯人要宗主，不妨留眼送歸鴻。"]'),
('dc8c5cd4-c41d-4f7c-bb47-f275e2e685a2','壽陸放翁三首  其三','蘇泂','宋','宋诗','song-poetry','','[]','花間乳鹿笑相迎，拄杖穿花導鹿行。',64,'全唐诗/poet.song.184000.json','["花間乳鹿笑相迎，拄杖穿花導鹿行。", "六子子孫俱宦達，三山山水亦聰明。", "論詩何止高南渡，草檄相看了北征。", "带得門人也僊骨，年年來此賀長生。"]'),
('8eab2bd2-ceae-4f77-a6c7-1ba2ea6124f7','三山放翁先生生朝以筇竹杖爲壽一首','蘇泂','宋','宋诗','song-poetry','','[]','信手公侯八十年，言歸山澤更臞僊。',64,'全唐诗/poet.song.184000.json','["信手公侯八十年，言歸山澤更臞僊。", "聲名固自蓋天下，耆老所當留日邊。", "滿腹詩書真我有，一門簪笏自家傳。", "持來筇杖非無意，竊比東坡壽樂全。"]'),
('ac1a0647-dcfc-4de7-83fb-b6a36df61214','聞孟良父侍郎解婺印改江東漕再和堆字韻','蘇泂','宋','宋诗','song-poetry','','[]','十行芝檢從天下，六月荷花照水開。',64,'全唐诗/poet.song.184000.json','["十行芝檢從天下，六月荷花照水開。", "未必便將東節去，不妨政用此時來。", "安排過闕留中奏，想像攀轅戀別杯。", "遣賀以時非造次，索公一笑簿書堆。"]'),
('56284772-0a24-457b-8b89-f14f8c4ceea6','舟次橫河呈孫季和通守','蘇泂','宋','宋诗','song-poetry','','[]','冉冉歸雲不自閑，紛紛暮靄已依山。',64,'全唐诗/poet.song.184000.json','["冉冉歸雲不自閑，紛紛暮靄已依山。", "時光盡入髭鬚裏，行色元非草樹間。", "舊臘新正能幾許，粗衣糲飯試諸難。", "吾生所恨長飄泊，又宿汀州白鷺灣。"]'),
('c01b8e50-525a-427f-9820-932894f5d74b','十月二十八日遷入趙氏借屋適有名酒及延致內黄侯約兄弟共醉潁季有詩次韻一首','蘇泂','宋','宋诗','song-poetry','','[]','黄花已判一年休，短褐無端又去秋。',64,'全唐诗/poet.song.184000.json','["黄花已判一年休，短褐無端又去秋。", "環堵肯云原憲病，卜居那免屈平愁。", "交情白髮知難有，故里青山未拙謀。", "醑我橫戈陪季孟，人間棠棣薄公侯。"]'),
('5bdfb3c9-6e3e-43f9-8b5d-24f5021975fc','次韻葛天民','蘇泂','宋','宋诗','song-poetry','','[]','心火調停久不燒，詩書聊以永今朝。',64,'全唐诗/poet.song.184000.json','["心火調停久不燒，詩書聊以永今朝。", "擬尋筇杖遊還懶，望見梅花意已消。", "原憲既貧應甕牖，顔回所樂是簞瓢。", "歲寒交友今餘幾，留取人間作後凋。"]'),
('e1145d29-69f1-4bdd-8297-8189a8331bbb','次韻虞叟兄','蘇泂','宋','宋诗','song-poetry','','[]','百嘉萌動春來意，兩頰參差少日紅。',64,'全唐诗/poet.song.184000.json','["百嘉萌動春來意，兩頰參差少日紅。", "有底心情桃葉渡，不堪時世柳花風。", "先朝諸老知誰健，短歷今年又已窮。", "忙事盡歸趺坐裏，侯封從付立談中。"]'),
('f220a242-3d49-4d80-88d4-cce40182a821','潁叟弟贈別韻','蘇泂','宋','宋诗','song-poetry','','[]','狙公多詐惑朝三，蟻穴何知亦戰酣。',64,'全唐诗/poet.song.184000.json','["狙公多詐惑朝三，蟻穴何知亦戰酣。", "世上規行無中矩，人間北看有城南。", "懷哉畎畝終從欲，老矣江湖合罷參。", "便道阿連同結屋，未妨作繭似春蠶。"]'),
('afe1dc52-50fb-4c70-824a-56d5084d2e41','次潁叟弟送行韻','蘇泂','宋','宋诗','song-poetry','','[]','相傳衣鉢已分明，早覺詩含鮑謝情。',64,'全唐诗/poet.song.184000.json','["相傳衣鉢已分明，早覺詩含鮑謝情。", "心腹於人惟有弟，襟懷無我獨非兄。", "偶隨江路帆孤往，便憶梅窗酒對傾。", "歲晚勉旃無廢學，他年夷惠看雙清。"]'),
('6baff842-64e4-49b5-8c69-85135a32eb3d','次韻虞叟九兄七月一日作','蘇泂','宋','宋诗','song-poetry','','[]','日月跳丸逝不留，吟蛩得意蛻蟬憂。',64,'全唐诗/poet.song.184000.json','["日月跳丸逝不留，吟蛩得意蛻蟬憂。", "終更末伏應無暑，望見中元便有秋。", "風爽氣先青草動，雨凉心共白蓮幽。", "誰能跨鶴乘西顥，三十三天取次遊。"]'),
('2b2100ed-bee0-4255-9ef7-2b614a128eff','次韻知縣三兄','蘇泂','宋','宋诗','song-poetry','','[]','楊柳依依萬縷絲，梅花無計與扶衰。',64,'全唐诗/poet.song.184000.json','["楊柳依依萬縷絲，梅花無計與扶衰。", "十分酒滿悶如昨，一半春休雨未知。", "安得詩書成保社，畧容巖壑有心期。", "扁舟短策尋常事，肥馬輕裘我不爲。"]'),
('6f267fb9-be2f-456a-92e3-e1a935a19f95','趙黄州寄示詩絕奇次韻','蘇泂','宋','宋诗','song-poetry','','[]','書回聞道讀春秋，筆削餘功指顧收。',64,'全唐诗/poet.song.184000.json','["書回聞道讀春秋，筆削餘功指顧收。", "魯國故知人有禮，周家那得聖無憂。", "非君著意扶公穀，似我何辭贊夏游。", "會引青藜校天祿，毋忘華髮此滄洲。"]'),
('8dcbf0a2-38e8-4f1f-9b60-59c94add2470','將別潁叟弟','蘇泂','宋','宋诗','song-poetry','','[]','兄弟無聊各數年，東堂猶喜聚炊煙。',64,'全唐诗/poet.song.184000.json','["兄弟無聊各數年，東堂猶喜聚炊煙。", "翛然汝更尋靈照，別後吾知憶惠連。", "擊汰便應從櫓外，看書誰與共燈前。", "明朝不待鼕鼕鼓，祇有關門及早眠。"]'),
('dcce9f5a-752d-4e4e-ada4-5f65b4423693','次韻潁叟弟送行','蘇泂','宋','宋诗','song-poetry','','[]','間道驅車逐帥旗，別情惟有弟兄知。',64,'全唐诗/poet.song.184000.json','["間道驅車逐帥旗，別情惟有弟兄知。", "百年同好少張仲，舉世誰人似子期。", "竹葉尚堪中酒聖，梅花真是斷腸枝。", "蒼崖縛屋歸來好，此計輸君我後時。"]'),
('070b615a-fadd-4900-b274-a7e4552361d8','走筆謝高秘書送示詩文','蘇泂','宋','宋诗','song-poetry','','[]','郊居近郭非寂寞，蟠竹結茅依野塘。',64,'全唐诗/poet.song.184000.json','["郊居近郭非寂寞，蟠竹結茅依野塘。", "白屋老人談黍稷，青雲學士送文章。", "藕花開後滿船月，楓葉落時緣路霜。", "年過三紀不稱意，隨分江湖作醉鄉。"]'),
('d7271b45-2a0f-49f4-b9b0-23d4da794b79','和十二弟韻','蘇泂','宋','宋诗','song-poetry','','[]','三伏回頭夢欲醒，五更風露月逾清。',64,'全唐诗/poet.song.184000.json','["三伏回頭夢欲醒，五更風露月逾清。", "病餘似鶴精神爽，老去如僧念慮輕。", "邊面只今多勇戰，人間從昔少閑行。", "何當封事天皇殿，乞借秋霖洗甲兵。"]'),
('c7aef946-3445-4926-9615-023776ee2f5b','奉送呂表叔赴江陰','蘇泂','宋','宋诗','song-poetry','','[]','春風乍入澄江郡，最愛君山一點青。',64,'全唐诗/poet.song.184000.json','["春風乍入澄江郡，最愛君山一點青。", "柳外化民安若子，鷗邊爲政出於經。", "每慚舊守勤招喚，况識今侯更典刑。", "此去交承如借問，侯芭貧病髮星星。"]'),
('9da455e3-6d3d-4117-a7e8-2510262050bf','和岩壑兄九日','蘇泂','宋','宋诗','song-poetry','','[]','華顛可笑插茱萸，兒女歡然競挽鬚。',64,'全唐诗/poet.song.184000.json','["華顛可笑插茱萸，兒女歡然競挽鬚。", "故國黄花元自好，荒臺青草孰爲娛。", "舉觴感慨悲歌有，落帽風流藴藉無。", "粘起半生鐵如意，今愚何似古之愚。"]'),
('afd15cf9-7108-42a3-a1aa-614b04712ad4','閑居復遇重九悠然興懷頗謂此節特宜於貧蓋富貴者不知若是之清美也因賦唐律呈同社','蘇泂','宋','宋诗','song-poetry','','[]','風凄日薄鬢毛新，歲歲年年樂此辰。',64,'全唐诗/poet.song.184000.json','["風凄日薄鬢毛新，歲歲年年樂此辰。", "多少昔賢留賦詠，大都九日稱清貧。", "甕頭無酒心仍醉，籬下看山意愈真。", "自採黄花供陶謝，邇來嘉興屬何人。"]'),
('98bc06f2-aaf0-45b5-9762-db9e27cb137f','和陸判院懷祖','蘇泂','宋','宋诗','song-poetry','','[]','柴門臨水對山開，日日思君君不來。',64,'全唐诗/poet.song.184000.json','["柴門臨水對山開，日日思君君不來。", "與世相忘書萬卷，於人無忤酒三杯。", "參乎畢竟曾師孔，賜也如何敢望回。", "况是升沉方自此，丹陽聞道好官催。"]'),
('e7c9a7dc-ca28-472d-8e61-5545509563cd','次韻知縣兄','蘇泂','宋','宋诗','song-poetry','','[]','秋聲物物類歌豳，旋轉天機屬大鈞。',64,'全唐诗/poet.song.184000.json','["秋聲物物類歌豳，旋轉天機屬大鈞。", "一雨薦凉全却暑，兩湖添綠不生塵。", "黄花又近重陽酒，白髮長思五柳人。", "急喚西風與湔洗，恨無好句逐時新。"]'),
('f4246eae-258b-4ef9-b750-ebbecc58044b','五和堆字韻呈孟漕','蘇泂','宋','宋诗','song-poetry','','[]','十年但有書題問，今日親逢幕府開。',64,'全唐诗/poet.song.184000.json','["十年但有書題問，今日親逢幕府開。", "薤本自迎公始到，桃花應笑我重來。", "何妨邂逅評詩句，不用殷勤治酒杯。", "辦取籃輿共吟賞，石頭秋晚亂雲堆。"]'),
('328da1ba-352c-437d-934b-d0f4882da1bd','送陸懷祖之官丹陽','蘇泂','宋','宋诗','song-poetry','','[]','放翁去作水中仙，有子生平在眼前。',64,'全唐诗/poet.song.184000.json','["放翁去作水中仙，有子生平在眼前。", "鍾愛甚於賢伯仲，傳家仍自好詩篇。", "肯爲筦庫官無小，會復公侯澤更綿。", "我亦與君非久別，秋來須上浙西船。"]'),
('f3c14de4-0948-4c42-9e3c-25a325cb163b','送富知丞之官丹陽','蘇泂','宋','宋诗','song-poetry','','[]','官袍歲久不能青，放了銅章却縣丞。',64,'全唐诗/poet.song.184000.json','["官袍歲久不能青，放了銅章却縣丞。", "時事自新醒眼看，古心逾拙白髭生。", "有田有屋寧三仕，隨雨隨風又一行。", "舉世其誰識公者，臨岐何獨悵離情。"]'),
('dbe055e6-9685-4471-a8e7-b3a05b21ec06','次九兄秋句','蘇泂','宋','宋诗','song-poetry','','[]','愁多端的似無愁，何况周行苦滯留。',64,'全唐诗/poet.song.184000.json','["愁多端的似無愁，何况周行苦滯留。", "蘆簄月連銀界曉，榆關寒護玉峰秋。", "挑燈屢作聞鷄舞，看劍長思躍馬遊。", "從古封侯欠英傑，幽燕終欲笑談休。"]'),
('cea50a22-c4a1-481c-a814-345bd673f18f','簡朱子大學士一首','蘇泂','宋','宋诗','song-poetry','','[]','石家曾作送君來，建業收書未得回。',64,'全唐诗/poet.song.184000.json','["石家曾作送君來，建業收書未得回。", "只道還家仍款曲，誰知分袂許悲哀。", "冥間孰與論心事，世上誰堪共酒杯。", "昨到帷堂前後奠，却瞻喬木肺肝摧。"]'),
('15e84bb8-db0c-443f-9cbd-f6c92201416a','悼剡姊','蘇泂','宋','宋诗','song-poetry','','[]','庭闈消息判沉沉，鴈序殊鄉缺嗣音。',64,'全唐诗/poet.song.184000.json','["庭闈消息判沉沉，鴈序殊鄉缺嗣音。", "擇對漫言雙易姓，何人堪托一分心。", "孤魂寂寞丘中土，庶子凋零地下金。", "沒固無聊生亦爾，忍令行路獨霑巾。"]'),
('afb62c61-0fbc-4587-9514-fb079d10af49','張平父逝後寄堯章','蘇泂','宋','宋诗','song-poetry','','[]','入門回首事如麻，豈意銘旌落主家。',64,'全唐诗/poet.song.184000.json','["入門回首事如麻，豈意銘旌落主家。", "有夢合尋苕水路，何心更種馬塍花。", "十年知遇分生死，八口饑寒足嘆嗟。", "我亦此公門下客，只今垂淚過京華。"]'),
('06548fc6-8acb-49ab-b167-20eafd65a5f3','哭唐姑丈縣尉','蘇泂','宋','宋诗','song-poetry','','[]','一官藍綬只虛名，兩婦朱絲合不成。',64,'全唐诗/poet.song.184000.json','["一官藍綬只虛名，兩婦朱絲合不成。", "問我諸姑先冢舍，別君三日便銘旌。", "高堂寂寞朝昏養，側戶乖遺子女情。", "欲寫此哀無處所，竹風荷雨淚縱橫。"]'),
('37caf45c-0a89-4068-9a30-11c61d7f766e','懷古','蘇泂','宋','宋诗','song-poetry','','[]','故宮何在綠離離，逆順興亡世所知。',64,'全唐诗/poet.song.184000.json','["故宮何在綠離離，逆順興亡世所知。", "草木尚懷勾踐德，山川仍識夏王悲。", "行人月下誰吹笛，游客街前自買碑。", "欲倚闌干問陳迹，蒼煙白露兩遲疑。"]'),
('d904d621-2ccc-4102-bfbb-31c1629eb88c','八月十五日遊禹祠告成觀','蘇泂','宋','宋诗','song-poetry','','[]','度密穿青且意行，窮居誰識萬人英。',64,'全唐诗/poet.song.184000.json','["度密穿青且意行，窮居誰識萬人英。", "山當鑿處終須好，水到平時自不鳴。", "夏德真應參太始，禹功那復告其成。", "登臨遺廟秋風裏，不盡今來古往情。"]'),
('4ac372e4-13d4-4bc6-9113-d44ab793fd95','雲門寺詩','蘇泂','宋','宋诗','song-poetry','','[]','重岡落日思依依，地老天荒閲盛衰。',64,'全唐诗/poet.song.184000.json','["重岡落日思依依，地老天荒閲盛衰。", "萬古煙蘿千古寺，唐朝詩句晉朝碑。", "鶴貪清氣隨僧住，松引寒聲助客悲。", "十載重來衫鬢改，笋輿回路獨移時。"]'),
('e30d7b07-6e2c-428e-8f7c-f63c10c6b172','清凉寺','蘇泂','宋','宋诗','song-poetry','','[]','倚石爲城竟是癡，春風秋雨柰何其。',64,'全唐诗/poet.song.184000.json','["倚石爲城竟是癡，春風秋雨柰何其。", "山容似鐵猶能改，世事如棋未可知。", "廟食孫郎餘草莽，龕燈彌勒賸流離。", "相逢一笑真難得，把筆賡詩記此時。"]'),
('7be150f1-5d8b-4e08-89a8-ada2a8723be6','秋日泛鏡中憩千秋觀','蘇泂','宋','宋诗','song-poetry','','[]','病起重來理釣絲，扁舟迨及素秋時。',64,'全唐诗/poet.song.184000.json','["病起重來理釣絲，扁舟迨及素秋時。", "舊交猶有青山在，幽趣唯應白鳥知。", "冉冉年光行老矣，茫茫世路欲何之。", "秦皇酒榼苔封遍，虛負霜螯左手持。"]'),
('c9bfe8c5-d23c-4075-a6a3-9e56e97fce47','蔣山寺詩','蘇泂','宋','宋诗','song-poetry','','[]','高人元是愛山林，倦翼猶思息樹陰。',64,'全唐诗/poet.song.184000.json','["高人元是愛山林，倦翼猶思息樹陰。", "况是先賢遺舊跡，未妨吾黨得幽尋。", "熙豐法在言何害，莘渭人非恨已深。", "老我誰能知許事，自敲亭竹和猿吟。"]'),
('12e2f816-611e-4682-a23a-515c54cd53e0','松桂堂','蘇泂','宋','宋诗','song-poetry','','[]','素韠歸來痛倚廬，四時花鳥護幽居。',64,'全唐诗/poet.song.184000.json','["素韠歸來痛倚廬，四時花鳥護幽居。", "躬行已達參乎孝，佩服難忘孔子書。", "綠蔭千年知不改，清香奕世豈無餘。", "客來已自徵前夢，未必中堂影像虛。"]'),
('69275c39-937e-47d9-b174-e14f5e6d067d','晚步湖橋','蘇泂','宋','宋诗','song-poetry','','[]','吳儂生長鏡湖邊，湖晚登橋意欲仙。',64,'全唐诗/poet.song.184000.json','["吳儂生長鏡湖邊，湖晚登橋意欲仙。", "初見蒼山下紅日，忽看白月上青煙。", "收藏畫本歸吟筆，應答漁歌送客船。", "回首更闌人去後，玉虹橫浸冷金眠。"]'),
('ad37cade-653b-4901-908e-ab9fbb466bc5','次韻古梅','蘇泂','宋','宋诗','song-poetry','','[]','獨立枝南萬事非，歲寒引去合知幾。',64,'全唐诗/poet.song.184000.json','["獨立枝南萬事非，歲寒引去合知幾。", "伯夷自信西山餓，公望何須東海歸。", "笛外數聲空入夢，江頭一樹忽斜暉。", "相看有愧垂垂老，莫遣無端片片飛。"]'),
('c9abfc51-d892-4780-9bf2-d804df04ecb2','梅花樹下讀高兄詩','蘇泂','宋','宋诗','song-poetry','','[]','尋思秘閣賢郎樣，一似梅花带竹枝。',64,'全唐诗/poet.song.184000.json','["尋思秘閣賢郎樣，一似梅花带竹枝。", "每到君邊作梅想，却來梅下讀君詩。", "崇奎堂暖春風候，射的山寒夜雪時。", "安得居遊君共我，梅花三友說心期。"]'),
('4e385673-6b6f-42f2-92d9-536640111571','次韻高似之秘書謝薛書記七月二十七日早桂','蘇泂','宋','宋诗','song-poetry','','[]','翠蕤低映鬰金裳，昨夜千門萬戶凉。',64,'全唐诗/poet.song.184000.json','["翠蕤低映鬰金裳，昨夜千門萬戶凉。", "蟾小未禁僊掌露，犀寒先透玉墀霜。", "喚回臨水登山意，惱亂薰天撲地香。", "歲歲爲花愁不徹，雅歌欲和底成章。"]'),
('b25fdcd8-2a75-49e4-bc84-d8644a372249','又歎庭前雜花草','蘇泂','宋','宋诗','song-poetry','','[]','十年屢作花開想，開盡凡花獨未開。',64,'全唐诗/poet.song.184000.json','["十年屢作花開想，開盡凡花獨未開。", "祝付化工應念此，保全根撥待時來。", "爲梅自合和羹鼎，是菊終須上酒杯。", "莫笑凄凉周茂叔，窗前生意草成堆。"]'),
('4e9c6bd6-2109-425d-8bdb-6503115cbe22','白鷗','蘇泂','宋','宋诗','song-poetry','','[]','白鷗相見忽相猜，居士星星似我哉。',64,'全唐诗/poet.song.184000.json','["白鷗相見忽相猜，居士星星似我哉。", "習懶更無詩一句，澆愁惟有酒三杯。", "看梅倣雪行過去，翫月如霜弄影來。", "學得平生安樂法，等閑不受鬢毛催。"]'),
('85c5315b-1186-4c1b-9bdb-eebc3e096f5a','飛鳴','蘇泂','宋','宋诗','song-poetry','','[]','飛鳴一鴈带秋回，寂歷黄花傍節開。',64,'全唐诗/poet.song.184000.json','["飛鳴一鴈带秋回，寂歷黄花傍節開。", "草木不逃天地役，禽魚常罹網羅災。", "中年衣食憂妻子，道遠舟車倦往來。", "未了此生誰料得，相逢且覆眼前杯。"]'),
('5de281a3-1184-4021-96c9-63cbd1815d0b','混迹','蘇泂','宋','宋诗','song-poetry','','[]','桃花新綠漲溪橋，楊柳傞傞弄舞腰。',64,'全唐诗/poet.song.184000.json','["桃花新綠漲溪橋，楊柳傞傞弄舞腰。", "二月不堪寒尚在，一春無那病相撩。", "書編讀半懶重讀，爐籀燒殘欣復燒。", "老向人間除妄想，但思混迹向漁樵。"]'),
('7c804ead-04f8-4257-87a3-0ee5235e09ac','太息','蘇泂','宋','宋诗','song-poetry','','[]','生物趨功日夜忙，中年轉覺事茫茫。',64,'全唐诗/poet.song.184000.json','["生物趨功日夜忙，中年轉覺事茫茫。", "時情何限刀邊蜜，歲晚偏多葉上霜。", "屺岵增悲誰覆載，桃梅結實幾青黄。", "讀書不辦關門計，又著麻鞋走四方。"]'),
('4de3f6ad-ff20-4ad5-9dae-c769500cb803','釣魚','蘇泂','宋','宋诗','song-poetry','','[]','白頭波上白頭翁，竹葉盃邊竹葉叢。',64,'全唐诗/poet.song.184000.json','["白頭波上白頭翁，竹葉盃邊竹葉叢。", "烹鴈罪因應鴈得，非魚樂語詎魚同。", "醉醒未覺乾坤異，起滅懸知水鏡空。", "嚴子向來無世念，謝郎今日有家風。"]'),
('9e1f639f-2ac8-4c4e-932c-21f2c2e4d349','團扇','蘇泂','宋','宋诗','song-poetry','','[]','團扇光陰有一年，楚騷心事忽凄然。',64,'全唐诗/poet.song.184000.json','["團扇光陰有一年，楚騷心事忽凄然。", "風高碧落無窮雁，日暮青山欲斷蟬。", "老去極思頑似石，古來元忌直如弦。", "吾廬咫尺金沙地，聊與僧伽話夙緣。"]'),
('86c6fa79-b515-4e91-8d71-9d87cf4c9474','巖壑兄去歲此時作春前四絕句姿媚可愛然猶有遺者因復作一首','蘇泂','宋','宋诗','song-poetry','','[]','縈風送臘回，生意遍陳荄。',24,'全唐诗/poet.song.184000.json','["縈風送臘回，生意遍陳荄。", "似織如絲處，春從裏許來。"]'),
('ef4f9e6f-3c1e-49a2-ad7c-41913a6640a3','夜二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','明月耿清夜，亂蛩啼草根。',24,'全唐诗/poet.song.184000.json','["明月耿清夜，亂蛩啼草根。", "幽人渾未寢，獨自倚柴門。"]'),
('233b58ae-40fc-41c8-8287-f559660a8746','夜二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','明月在天上，流光遍草萊。',24,'全唐诗/poet.song.184000.json','["明月在天上，流光遍草萊。", "平生一樽酒，思與故人開。"]'),
('1791b972-3d35-4a17-ae27-a571ac78dcd8','鏡湖','蘇泂','宋','宋诗','song-poetry','','[]','蒼蒼煙霽塔，了了月明山。',24,'全唐诗/poet.song.184000.json','["蒼蒼煙霽塔，了了月明山。", "坐久忽不見，濛濛杳杳間。"]'),
('e7d5c981-125f-4e50-9dfe-123fae185822','舟中','蘇泂','宋','宋诗','song-poetry','','[]','一葉舟中宿，風高浪亦高。',24,'全唐诗/poet.song.184000.json','["一葉舟中宿，風高浪亦高。", "回頭人世事，真覺細如毛。"]'),
('837b92f0-d9c0-4c75-913a-825d99ce70ef','杜字','蘇泂','宋','宋诗','song-poetry','','[]','望帝城中住，春宵血沁花。',24,'全唐诗/poet.song.184000.json','["望帝城中住，春宵血沁花。", "何鄉真萬里，還憶夢中家。"]'),
('1d509649-68c9-4c51-9a09-9d222babbda3','聞鶑','蘇泂','宋','宋诗','song-poetry','','[]','一箇冬青樹，鶑聲日日來。',24,'全唐诗/poet.song.184000.json','["一箇冬青樹，鶑聲日日來。", "屋西偏婭姹，應是綠雲堆。"]'),
('8ec805f7-9eb6-4628-8f28-22b653b731bf','梅花','蘇泂','宋','宋诗','song-poetry','','[]','清貞表獨立，半蕊便風流。',24,'全唐诗/poet.song.184000.json','["清貞表獨立，半蕊便風流。", "信有魁天下，羣芳未轉頭。"]'),
('baf8e6a6-fdc6-44e7-92c9-11459798d2dd','贈草','蘇泂','宋','宋诗','song-poetry','','[]','一陣春風起，依然故舊情。',24,'全唐诗/poet.song.184000.json','["一陣春風起，依然故舊情。", "牆根霜下草，吾與汝更生。"]'),
('a92e95ab-c1eb-409b-9869-586e209e854b','十六日伏睹明堂禮成聖駕恭謝太一宮小臣敬成口號  其一','蘇泂','宋','宋诗','song-poetry','','[]','三邊兵隙果誰開，盡道秋高戰馬來。',32,'全唐诗/poet.song.184000.json','["三邊兵隙果誰開，盡道秋高戰馬來。", "宗祀告成無一事，小臣欣覩带花回。"]'),
('1965d1b5-ac6d-46b2-a9a1-b9726de2a110','十六日伏睹明堂禮成聖駕恭謝太一宮小臣敬成口號  其二','蘇泂','宋','宋诗','song-poetry','','[]','黄門馳馬去如雲，末後椒房駕玉輪。',32,'全唐诗/poet.song.184000.json','["黄門馳馬去如雲，末後椒房駕玉輪。", "驚起秋風無處避，變成三月萬花春。"]'),
('ce5156ee-65cb-456c-b9ea-e17189d28d26','十六日伏睹明堂禮成聖駕恭謝太一宮小臣敬成口號  其三','蘇泂','宋','宋诗','song-poetry','','[]','月中鼓吹日中歸，重領中宮拜壽闈。',32,'全唐诗/poet.song.184000.json','["月中鼓吹日中歸，重領中宮拜壽闈。", "指點都人最歡喜，今郊恩赦每郊稀。"]'),
('abd1f493-2f9d-4cab-b535-15518acb1c7c','十六日伏睹明堂禮成聖駕恭謝太一宮小臣敬成口號  其四','蘇泂','宋','宋诗','song-poetry','','[]','祥煙漠漠上龍旂，將相侯王護六飛。',32,'全唐诗/poet.song.184000.json','["祥煙漠漠上龍旂，將相侯王護六飛。", "一望御街紅數里，幾人簇擁赭黄衣。"]'),
('39995204-c4d3-402d-bda9-b7e6c6fb7d3e','十六日伏睹明堂禮成聖駕恭謝太一宮小臣敬成口號  其五','蘇泂','宋','宋诗','song-poetry','','[]','燕罷芳園敕御龍，須臾仙仗簇還宮。',32,'全唐诗/poet.song.184000.json','["燕罷芳園敕御龍，須臾仙仗簇還宮。", "千官過盡塵如霧，薄暮香鈿滿路中。"]'),
('78dc3c16-ed14-4234-b8b5-d3d1d68b43d7','十六日伏睹明堂禮成聖駕恭謝太一宮小臣敬成口號  其六','蘇泂','宋','宋诗','song-poetry','','[]','花枝人面兩欣然，和氣晴光四接連。',32,'全唐诗/poet.song.184000.json','["花枝人面兩欣然，和氣晴光四接連。", "親向官街聽輿誦，太平天子萬斯年。"]'),
('4ed1d3f1-fb27-4e61-a6b4-3ecba82005b2','十六日伏睹明堂禮成聖駕恭謝太一宮小臣敬成口號  其七','蘇泂','宋','宋诗','song-poetry','','[]','朝家積累有深仁，天聽由來不遠人。',32,'全唐诗/poet.song.184000.json','["朝家積累有深仁，天聽由來不遠人。", "且願君王省征伐，明郊重見四夷賓。"]'),
('8509e78d-ab53-4770-8044-9a4b92875d86','端午日宮宴二首  其一','蘇泂','宋','宋诗','song-poetry','','[]','仙裝宮樣一羣羣，花外花間藹若雲。',32,'全唐诗/poet.song.184000.json','["仙裝宮樣一羣羣，花外花間藹若雲。", "羞澀葵榴無舉止，盡傾顔色向南薰。"]'),
('abf5e330-0a0b-434a-b769-4b01d4b127fd','端午日宮宴二首  其二','蘇泂','宋','宋诗','song-poetry','','[]','香萱夾和宜男草，高下山梔安石榴。',32,'全唐诗/poet.song.184000.json','["香萱夾和宜男草，高下山梔安石榴。", "一樣薰風分五色，蜀葵林畔按涼州。"]');
